INSERT INTO public.grammars (ko, meaning, example, trans, deck_id) VALUES
('은/는', '{"en":"topic particle — marks what the sentence is about","es":"partícula de tema — marca de qué se habla; implica contraste","fr":"particule de thème — indique le sujet du discours","pt-BR":"partícula de tópico — indica do que se está falando","th":"อนุภาคแสดงหัวเรื่อง","id":"partikel topik — menandai apa yang dibicarakan","vi":"tiểu từ chủ đề — đánh dấu chủ đề câu","ja":"主題助詞「は」— 話題を示す"}'::jsonb, '저는 학생이에요.', '{"en":"I am a student.","es":"Yo soy estudiante.","fr":"Je suis étudiant.","pt-BR":"Eu sou estudante.","th":"ฉันเป็นนักเรียน","id":"Saya seorang pelajar.","vi":"Tôi là học sinh.","ja":"私は学生です。"}'::jsonb, 'topik-1'),
('이/가', '{"en":"subject particle — presents new info or emphasis","es":"partícula de sujeto — info nueva o énfasis","fr":"particule de sujet — info nouvelle ou emphase","pt-BR":"partícula de sujeito — informação nova ou ênfase","th":"อนุภาคประธาน — เน้นหรือข้อมูลใหม่","id":"partikel subjek — info baru atau penekanan","vi":"tiểu từ chủ ngữ — thông tin mới hoặc nhấn mạnh","ja":"主語助詞「が」— 新情報や強調"}'::jsonb, '고양이가 귀여워요.', '{"en":"The cat is cute.","es":"El gato es lindo.","fr":"Le chat est mignon.","pt-BR":"O gato é fofo.","th":"แมวน่ารัก","id":"Kucingnya lucu.","vi":"Con mèo dễ thương.","ja":"猫がかわいいです。"}'::jsonb, 'topik-1'),
('을/를', '{"en":"object particle — marks the direct object","es":"partícula de objeto — marca el objeto directo","fr":"particule d''objet — marque le complément d''objet direct","pt-BR":"partícula de objeto — marca o objeto direto","th":"อนุภาคกรรมตรง","id":"partikel objek","vi":"tiểu từ tân ngữ","ja":"目的語助詞「を」"}'::jsonb, '책을 읽어요.', '{"en":"I read a book.","es":"Leo un libro.","fr":"Je lis un livre.","pt-BR":"Eu leio um livro.","th":"ฉันอ่านหนังสือ","id":"Saya membaca buku.","vi":"Tôi đọc sách.","ja":"本を読みます。"}'::jsonb, 'topik-1'),
('에', '{"en":"at / to / on — static location, destination, point in time","es":"en / a — lugar estático, destino o momento","fr":"à / dans — lieu statique, destination, moment","pt-BR":"em / para — lugar estático, destino, momento","th":"ที่ / ไป — สถานที่ / ปลายทาง / เวลา","id":"di / ke — tempat statis, tujuan, waktu","vi":"ở / đến / vào — vị trí tĩnh, đích đến, thời điểm","ja":"「に」— 場所・到達点・時点"}'::jsonb, '학교에 가요.', '{"en":"I go to school.","es":"Voy a la escuela.","fr":"Je vais à l’école.","pt-BR":"Vou para a escola.","th":"ฉันไปโรงเรียน","id":"Saya pergi ke sekolah.","vi":"Tôi đi đến trường.","ja":"学校に行きます。"}'::jsonb, 'topik-1'),
('에서', '{"en":"at / from — location where an action happens, or origin","es":"en / desde — lugar donde ocurre la acción u origen","fr":"à / depuis — lieu d’action ou origine","pt-BR":"em / de — lugar onde acontece a ação ou origem","th":"ที่ / จาก — สถานที่เกิดการกระทำ / จุดเริ่มต้น","id":"di / dari — tempat aksi atau asal","vi":"ở / từ — nơi diễn ra hành động hoặc nguồn gốc","ja":"「で」/「から」— 動作の場所・起点"}'::jsonb, '카페에서 커피를 마셔요.', '{"en":"I drink coffee at the cafe.","es":"Bebo café en la cafetería.","fr":"Je bois du café au café.","pt-BR":"Tomo café no café.","th":"ฉันดื่มกาแฟที่ร้านกาแฟ","id":"Saya minum kopi di kafe.","vi":"Tôi uống cà phê ở quán.","ja":"カフェでコーヒーを飲みます。"}'::jsonb, 'topik-1'),
('와/과 · 하고 · (이)랑', '{"en":"\"and / with\" connecting nouns (formal / neutral / casual)","es":"\"y / con\" entre sustantivos (formal · neutro · informal)","fr":"\"et / avec\" entre noms (formel · neutre · familier)","pt-BR":"\"e / com\" entre substantivos (formal · neutro · informal)","th":"\"และ / กับ\" เชื่อมคำนาม (ทางการ · กลาง · ไม่ทางการ)","id":"\"dan / dengan\" antar kata benda (formal · netral · santai)","vi":"\"và / với\" giữa các danh từ (trang trọng · trung tính · thân mật)","ja":"名詞をつなぐ「と」(文語 와/과 · 中間 하고 · 口語 (이)랑)"}'::jsonb, '친구하고 영화를 봤어요.', '{"en":"I watched a movie with a friend.","es":"Vi una película con un amigo.","fr":"J’ai vu un film avec un ami.","pt-BR":"Assisti a um filme com um amigo.","th":"ฉันดูหนังกับเพื่อน","id":"Saya menonton film bersama teman.","vi":"Tôi đã xem phim cùng bạn.","ja":"友達と映画を見ました。"}'::jsonb, 'topik-1'),
('도', '{"en":"\"also / too / either\" — replaces 은/는, 이/가, 을/를","es":"\"también / tampoco\" — reemplaza 은/는, 이/가, 을/를","fr":"\"aussi / non plus\" — remplace 은/는, 이/가, 을/를","pt-BR":"\"também / tampouco\" — substitui 은/는, 이/가, 을/를","th":"\"ก็ / ด้วย\" — แทน 은/는, 이/가, 을/를","id":"\"juga\" — menggantikan 은/는, 이/가, 을/를","vi":"\"cũng\" — thay 은/는, 이/가, 을/를","ja":"「も」— は/が/をを置き換える"}'::jsonb, '저도 한국어를 배워요.', '{"en":"I’m also learning Korean.","es":"Yo también aprendo coreano.","fr":"Moi aussi, j’apprends le coréen.","pt-BR":"Eu também estudo coreano.","th":"ฉันก็เรียนภาษาเกาหลีเหมือนกัน","id":"Saya juga belajar bahasa Korea.","vi":"Tôi cũng học tiếng Hàn.","ja":"私も韓国語を勉強します。"}'::jsonb, 'topik-1'),
('만', '{"en":"\"only / just\" — exclusivity","es":"\"solo / únicamente\"","fr":"\"seulement / uniquement\"","pt-BR":"\"só / apenas / somente\"","th":"\"เท่านั้น / แค่\"","id":"\"hanya / saja\"","vi":"\"chỉ\"","ja":"「だけ」— 限定"}'::jsonb, '물만 마셨어요.', '{"en":"I only drank water.","es":"Solo bebí agua.","fr":"Je n’ai bu que de l’eau.","pt-BR":"Eu só bebi água.","th":"ฉันดื่มแค่น้ำเปล่า","id":"Saya hanya minum air.","vi":"Tôi chỉ uống nước.","ja":"水だけ飲みました。"}'::jsonb, 'topik-1'),
('의', '{"en":"possessive \"of\" — possession or relation","es":"partícula posesiva \"de\" — posesión o relación","fr":"particule possessive \"de\"","pt-BR":"partícula possessiva \"de\"","th":"อนุภาคแสดงความเป็นเจ้าของ \"ของ\"","id":"partikel kepemilikan (\"milik\")","vi":"tiểu từ sở hữu \"của\"","ja":"「の」— 所有・関係"}'::jsonb, '친구의 책이에요.', '{"en":"It’s my friend’s book.","es":"Es el libro de mi amigo.","fr":"C’est le livre de mon ami.","pt-BR":"É o livro do meu amigo.","th":"หนังสือของเพื่อนฉัน","id":"Itu buku teman saya.","vi":"Đó là sách của bạn tôi.","ja":"友達の本です。"}'::jsonb, 'topik-1'),
('에게 / 한테 / 께', '{"en":"to (a person) — formal 에게 · spoken 한테 · honorific 께","es":"a (persona) — formal 에게 · hablado 한테 · honorífico 께","fr":"à (personne) — écrit 에게 · oral 한테 · honorifique 께","pt-BR":"para (pessoa) — formal 에게 · falado 한테 · honorífico 께","th":"ให้ / กับ (คน) — ทางการ 에게 · พูด 한테 · ยกย่อง 께","id":"kepada (orang) — formal 에게 · lisan 한테 · hormat 께","vi":"cho (người) — trang trọng 에게 · nói 한테 · kính ngữ 께","ja":"人への「に」— 文語 에게 · 口語 한테 · 尊敬 께"}'::jsonb, '친구에게 선물을 줬어요.', '{"en":"I gave a gift to my friend.","es":"Le di un regalo a mi amigo.","fr":"J’ai donné un cadeau à mon ami.","pt-BR":"Dei um presente para meu amigo.","th":"ฉันให้ของขวัญเพื่อน","id":"Saya memberi hadiah kepada teman.","vi":"Tôi đã tặng quà cho bạn.","ja":"友達にプレゼントをあげました。"}'::jsonb, 'topik-1'),
('(으)로', '{"en":"direction / means / tool — \"by, with, toward\"","es":"dirección / medio / herramienta — \"por, con, hacia\"","fr":"direction / moyen / outil — \"par, avec, vers\"","pt-BR":"direção / meio / ferramenta — \"por, com, para\"","th":"ทิศทาง / วิธี / เครื่องมือ — \"ไปทาง · ด้วย\"","id":"arah / cara / alat — \"ke, dengan\"","vi":"hướng / phương tiện / công cụ — \"bằng, đến\"","ja":"方向・手段・道具の「で」「へ」"}'::jsonb, '지하철로 왔어요.', '{"en":"I came by subway.","es":"Vine en metro.","fr":"Je suis venu en métro.","pt-BR":"Vim de metrô.","th":"ฉันมาด้วยรถไฟใต้ดิน","id":"Saya datang dengan kereta bawah tanah.","vi":"Tôi đến bằng tàu điện ngầm.","ja":"地下鉄で来ました。"}'::jsonb, 'topik-1'),
('부터 / 까지', '{"en":"\"from\" (start) / \"to\" (end) — temporal or spatial range","es":"\"desde\" (inicio) / \"hasta\" (fin) — rango temporal o espacial","fr":"\"de\" (début) / \"jusqu’à\" (fin) — plage de temps ou d’espace","pt-BR":"\"de\" (início) / \"até\" (fim) — intervalo de tempo ou espaço","th":"\"ตั้งแต่ ... ถึง ...\" — ช่วงเวลา / สถานที่","id":"\"dari ... sampai ...\" — rentang waktu / tempat","vi":"\"từ ... đến ...\" — khoảng thời gian / không gian","ja":"「〜から〜まで」— 範囲"}'::jsonb, '9시부터 5시까지 일해요.', '{"en":"I work from 9 to 5.","es":"Trabajo de 9 a 5.","fr":"Je travaille de 9h à 17h.","pt-BR":"Trabalho das 9 às 5.","th":"ฉันทำงานตั้งแต่ 9 โมงถึง 5 โมง","id":"Saya bekerja dari jam 9 sampai jam 5.","vi":"Tôi làm việc từ 9 giờ đến 5 giờ.","ja":"9時から5時まで働きます。"}'::jsonb, 'topik-1'),
('마다', '{"en":"\"each / every\" — distributive marker","es":"\"cada / todos los\" — distributivo","fr":"\"chaque / tous les\" — distributif","pt-BR":"\"cada / todos os\" — distributivo","th":"\"ทุก ๆ\" — บอกการกระจาย","id":"\"setiap / tiap\" — distributif","vi":"\"mỗi / mọi\" — phân phối","ja":"「〜ごとに / 毎〜」— 配分"}'::jsonb, '날마다 운동해요.', '{"en":"I exercise every day.","es":"Hago ejercicio todos los días.","fr":"Je fais du sport tous les jours.","pt-BR":"Eu me exercito todos os dias.","th":"ฉันออกกำลังกายทุกวัน","id":"Saya berolahraga setiap hari.","vi":"Mỗi ngày tôi tập thể dục.","ja":"毎日運動します。"}'::jsonb, 'topik-1'),
('(이)나', '{"en":"\"or\" between nouns; with numbers: \"about / as many as\"","es":"\"o\" entre sustantivos; con números: \"aproximadamente / hasta\"","fr":"\"ou\" entre noms; avec un nombre : \"environ / pas moins de\"","pt-BR":"\"ou\" entre substantivos; com números: \"uns / até\"","th":"\"หรือ\" ระหว่างคำนาม; กับตัวเลข: \"ประมาณ / ตั้ง\"","id":"\"atau\" antar kata benda; dengan angka: \"kira-kira / sampai\"","vi":"\"hoặc\" giữa danh từ; với số: \"khoảng / đến\"","ja":"名詞間の「か」/ 数字で「〜も」"}'::jsonb, '커피나 차를 마실래요?', '{"en":"Would you like coffee or tea?","es":"¿Quieres café o té?","fr":"Tu veux du café ou du thé ?","pt-BR":"Você quer café ou chá?","th":"จะดื่มกาแฟหรือชาดีคะ","id":"Mau minum kopi atau teh?","vi":"Bạn muốn uống cà phê hay trà?","ja":"コーヒーかお茶を飲みますか？"}'::jsonb, 'topik-1'),
('이다 / 아니다', '{"en":"\"to be\" / \"to not be\" — copula for nouns (이에요/예요/입니다)","es":"\"ser\" / \"no ser\" — cópula con sustantivos (이에요/예요/입니다)","fr":"«être» / «ne pas être» — copule pour noms","pt-BR":"\"ser\" / \"não ser\" — cópula com substantivos","th":"\"เป็น/คือ\" / \"ไม่ใช่\" — กับคำนาม","id":"\"adalah\" / \"bukan\" — kopula untuk kata benda","vi":"\"là\" / \"không phải là\" — hệ từ cho danh từ","ja":"名詞文の「である / ではない」(이에요/예요/입니다)"}'::jsonb, '저는 학생이에요.', '{"en":"I am a student.","es":"Yo soy estudiante.","fr":"Je suis étudiant.","pt-BR":"Eu sou estudante.","th":"ฉันเป็นนักเรียน","id":"Saya seorang pelajar.","vi":"Tôi là học sinh.","ja":"私は学生です。"}'::jsonb, 'topik-1'),
('있다 / 없다', '{"en":"\"there is / have\" / \"there isn’t / don’t have\"","es":"\"haber / tener\" / \"no haber / no tener\"","fr":"\"il y a / avoir\" / \"il n’y a pas / ne pas avoir\"","pt-BR":"\"haver / ter\" / \"não haver / não ter\"","th":"\"มี\" / \"ไม่มี\"","id":"\"ada\" / \"tidak ada\"","vi":"\"có\" / \"không có\"","ja":"「ある・いる / ない・いない」"}'::jsonb, '시간이 없어요.', '{"en":"I don’t have time.","es":"No tengo tiempo.","fr":"Je n’ai pas le temps.","pt-BR":"Não tenho tempo.","th":"ฉันไม่มีเวลา","id":"Saya tidak punya waktu.","vi":"Tôi không có thời gian.","ja":"時間がありません。"}'::jsonb, 'topik-1'),
('좋아하다 / 싫어하다', '{"en":"\"to like / dislike\" — active verb, object marked with 을/를","es":"\"gustar / no gustar\" — verbo activo, OD con 을/를","fr":"\"aimer / ne pas aimer\" — verbe actif, COD avec 을/를","pt-BR":"\"gostar / não gostar\" — verbo ativo, OD com 을/를","th":"\"ชอบ / ไม่ชอบ\" — กริยา (กรรมใส่ 을/를)","id":"\"suka / tidak suka\" — verba aktif (objek pakai 을/를)","vi":"\"thích / không thích\" — động từ chủ động (tân ngữ với 을/를)","ja":"「好む / 嫌う」— 動作動詞、目的語に을/를"}'::jsonb, '저는 음악을 좋아해요.', '{"en":"I like music.","es":"Me gusta la música.","fr":"J’aime la musique.","pt-BR":"Eu gosto de música.","th":"ฉันชอบดนตรี","id":"Saya suka musik.","vi":"Tôi thích âm nhạc.","ja":"私は音楽が好きです。"}'::jsonb, 'topik-1'),
('-아/어요', '{"en":"polite present ending (해요체) — the everyday spoken form","es":"terminación de presente educado (해요체) — la forma cotidiana","fr":"terminaison présent poli (해요체) — forme courante","pt-BR":"terminação de presente educado (해요체)","th":"รูปสุภาพปัจจุบัน (해요체)","id":"akhiran sopan kala kini (해요체)","vi":"đuôi lịch sự hiện tại (해요체)","ja":"丁寧体の現在「〜아/어요」(해요체)"}'::jsonb, '저는 매일 운동해요.', '{"en":"I exercise every day.","es":"Hago ejercicio todos los días.","fr":"Je fais du sport tous les jours.","pt-BR":"Eu me exercito todos os dias.","th":"ฉันออกกำลังกายทุกวัน","id":"Saya berolahraga setiap hari.","vi":"Tôi tập thể dục mỗi ngày.","ja":"私は毎日運動します。"}'::jsonb, 'topik-1'),
('-았/었어요', '{"en":"polite past tense ending","es":"terminación de pasado educado","fr":"terminaison passé poli","pt-BR":"terminação de pretérito educado","th":"รูปสุภาพอดีต","id":"akhiran sopan lampau","vi":"đuôi lịch sự quá khứ","ja":"丁寧体の過去「〜았/었어요」"}'::jsonb, '어제 영화를 봤어요.', '{"en":"I watched a movie yesterday.","es":"Ayer vi una película.","fr":"J’ai vu un film hier.","pt-BR":"Ontem assisti a um filme.","th":"เมื่อวานดูหนัง","id":"Kemarin saya menonton film.","vi":"Hôm qua tôi đã xem phim.","ja":"昨日映画を見ました。"}'::jsonb, 'topik-1'),
('-(으)ㄹ 거예요', '{"en":"future / intention / supposition","es":"futuro / intención / suposición","fr":"futur / intention / supposition","pt-BR":"futuro / intenção / suposição","th":"อนาคต / ความตั้งใจ / การคาดเดา","id":"masa depan / niat / dugaan","vi":"tương lai / dự định / suy đoán","ja":"未来・意志・推量「〜つもりです / 〜でしょう」"}'::jsonb, '내일 서울에 갈 거예요.', '{"en":"I will go to Seoul tomorrow.","es":"Mañana iré a Seúl.","fr":"Demain j’irai à Séoul.","pt-BR":"Amanhã vou para Seul.","th":"พรุ่งนี้ฉันจะไปโซล","id":"Besok saya akan pergi ke Seoul.","vi":"Ngày mai tôi sẽ đến Seoul.","ja":"明日ソウルに行きます。"}'::jsonb, 'topik-1'),
('-(으)세요', '{"en":"polite imperative (\"please ...\") or honorific present","es":"imperativo educado (\"por favor...\") o presente honorífico","fr":"impératif poli ou présent honorifique","pt-BR":"imperativo educado (\"por favor\") ou presente honorífico","th":"คำสั่งสุภาพ / รูปยกย่องปัจจุบัน","id":"imperatif sopan / kala kini hormat","vi":"mệnh lệnh lịch sự / hiện tại kính ngữ","ja":"「お〜ください / ご〜ください」— 丁寧依頼・尊敬現在"}'::jsonb, '여기 앉으세요.', '{"en":"Please sit here.","es":"Siéntese aquí, por favor.","fr":"Asseyez-vous ici, s’il vous plaît.","pt-BR":"Sente-se aqui, por favor.","th":"เชิญนั่งตรงนี้ค่ะ","id":"Silakan duduk di sini.","vi":"Mời bạn ngồi đây.","ja":"こちらにお座りください。"}'::jsonb, 'topik-1'),
('-ㅂ/습니다', '{"en":"formal-style ending (합쇼체) — news, presentations, first meetings","es":"terminación formal (합쇼체) — noticias, presentaciones, formal","fr":"terminaison formelle (합쇼체) — discours, première rencontre","pt-BR":"terminação formal (합쇼체) — notícias, apresentações","th":"รูปทางการ (합쇼체) — ข่าว / การนำเสนอ","id":"akhiran formal (합쇼체) — berita / presentasi","vi":"đuôi trang trọng (합쇼체) — bản tin, thuyết trình","ja":"改まった「〜です/ます」(합쇼체)"}'::jsonb, '저는 한국 사람입니다.', '{"en":"I am Korean.","es":"Soy coreano.","fr":"Je suis coréen.","pt-BR":"Sou coreano.","th":"ผม/ฉันเป็นคนเกาหลี","id":"Saya orang Korea.","vi":"Tôi là người Hàn Quốc.","ja":"私は韓国人です。"}'::jsonb, 'topik-1'),
('안 + V / -지 않다', '{"en":"negation by choice — \"not\" (안 is short, -지 않다 is long/formal)","es":"negación por elección — \"no\" (안 corto, -지 않다 largo/formal)","fr":"négation par choix — court 안 / long -지 않다","pt-BR":"negação por escolha — curto 안 / longo -지 않다","th":"การปฏิเสธโดยเลือก — สั้น 안 / ยาว -지 않다","id":"negasi karena pilihan — pendek 안 / panjang -지 않다","vi":"phủ định do chọn không — ngắn 안 / dài -지 않다","ja":"意志による否定「〜ない」(短 안 / 長 -지 않다)"}'::jsonb, '오늘은 학교에 안 가요.', '{"en":"I’m not going to school today.","es":"Hoy no voy a la escuela.","fr":"Aujourd’hui je ne vais pas à l’école.","pt-BR":"Hoje eu não vou à escola.","th":"วันนี้ฉันไม่ไปโรงเรียน","id":"Hari ini saya tidak ke sekolah.","vi":"Hôm nay tôi không đi học.","ja":"今日は学校に行きません。"}'::jsonb, 'topik-1'),
('못 + V / -지 못하다', '{"en":"\"cannot\" — inability due to circumstance, not choice","es":"\"no poder\" — incapacidad por circunstancias, no por voluntad","fr":"«ne pas pouvoir» — incapacité due aux circonstances","pt-BR":"\"não poder / não conseguir\" — incapacidade por circunstância","th":"\"ไม่สามารถ\" — เพราะข้อจำกัด ไม่ใช่ความตั้งใจ","id":"\"tidak bisa\" — karena keadaan, bukan pilihan","vi":"\"không thể\" — do hoàn cảnh, không phải lựa chọn","ja":"「できない」— 不可能・能力不足"}'::jsonb, '저는 수영을 못 해요.', '{"en":"I can’t swim.","es":"No sé nadar.","fr":"Je ne sais pas nager.","pt-BR":"Não sei nadar.","th":"ฉันว่ายน้ำไม่เป็น","id":"Saya tidak bisa berenang.","vi":"Tôi không biết bơi.","ja":"私は泳げません。"}'::jsonb, 'topik-1'),
('안 vs 못 (비교)', '{"en":"contrast: 안 = won’t (choice) vs 못 = can’t (inability)","es":"contraste: 안 = no quiero (elección) vs 못 = no puedo (incapacidad)","fr":"contraste : 안 = je ne veux pas / 못 = je ne peux pas","pt-BR":"contraste: 안 = não quero / 못 = não consigo","th":"ความต่าง: 안 (เลือกไม่ทำ) / 못 (ทำไม่ได้)","id":"beda: 안 (memilih tidak) / 못 (tidak mampu)","vi":"phân biệt: 안 (không muốn) / 못 (không thể)","ja":"対比: 안 (しない) / 못 (できない)"}'::jsonb, '오늘은 술을 안 마셔요. 약 먹어서 못 마셔요.', '{"en":"Today I’m not drinking (by choice) — I can’t drink because I took meds.","es":"Hoy no bebo (elijo no) — no puedo beber porque tomé medicación.","fr":"Aujourd’hui je ne bois pas (par choix) — je ne peux pas car j’ai pris des médicaments.","pt-BR":"Hoje eu não bebo (por escolha) — não posso beber porque tomei remédio.","th":"วันนี้ฉันไม่ดื่ม (เลือกเอง) — ดื่มไม่ได้เพราะกินยา","id":"Hari ini saya tidak minum (memilih tidak) — tidak bisa minum karena minum obat.","vi":"Hôm nay tôi không uống (chọn không) — không thể uống vì đã uống thuốc.","ja":"今日はお酒を飲みません(意志)。薬を飲んだので飲めません(不可)。"}'::jsonb, 'topik-1'),
('-고', '{"en":"\"and (then)\" — connects actions or states; tense on last clause only","es":"\"y / y luego\" — conecta acciones o estados; tiempo solo en la última","fr":"\"et (puis)\" — relie actions/états; temps sur la dernière clause","pt-BR":"\"e (depois)\" — conecta ações/estados; tempo só na última","th":"\"แล้วก็\" — เชื่อมการกระทำ/สถานะ; เวลาที่ประโยคสุดท้าย","id":"\"lalu / dan\" — menghubungkan aksi/keadaan; kala di klausa terakhir","vi":"\"và / rồi\" — nối hành động/trạng thái; thì ở vế cuối","ja":"「〜して」— 動作・状態の接続(時制は最後の節のみ)"}'::jsonb, '숙제를 하고 잤어요.', '{"en":"I did my homework and went to sleep.","es":"Hice la tarea y me dormí.","fr":"J’ai fait mes devoirs et je suis allé dormir.","pt-BR":"Fiz a lição e fui dormir.","th":"ทำการบ้านแล้วก็นอน","id":"Saya kerjakan PR lalu tidur.","vi":"Tôi làm bài tập rồi đi ngủ.","ja":"宿題をして寝ました。"}'::jsonb, 'topik-1'),
('-아/어서', '{"en":"\"because / so\" + natural sequence; no past on first clause, no imperative on second","es":"\"porque\" + secuencia natural; sin pasado en la 1ª cláusula ni imperativo en la 2ª","fr":"\"parce que\" + suite naturelle; pas de passé en 1ʳᵉ ni d’impératif en 2ᵈᵉ","pt-BR":"\"porque\" + sequência natural; sem passado na 1ª nem imperativo na 2ª","th":"\"เพราะว่า\" — เหตุผลธรรมชาติ ห้ามอดีตในข้อแรกและคำสั่งในข้อหลัง","id":"\"karena\" — alasan alami; tanpa lampau di klausa 1 atau perintah di klausa 2","vi":"\"vì / nên\" — lý do tự nhiên; không quá khứ ở vế 1, không mệnh lệnh ở vế 2","ja":"「〜て・〜ので」— 自然な因果(前節に過去・後節に命令×)"}'::jsonb, '배가 고파서 밥을 먹었어요.', '{"en":"I was hungry, so I ate.","es":"Tenía hambre, así que comí.","fr":"J’avais faim, alors j’ai mangé.","pt-BR":"Eu estava com fome, então comi.","th":"ฉันหิวเลยกินข้าว","id":"Saya lapar, jadi saya makan.","vi":"Tôi đói nên đã ăn cơm.","ja":"お腹が空いたのでご飯を食べました。"}'::jsonb, 'topik-1'),
('-지만', '{"en":"\"but / although\" — adversative connector, any tense","es":"\"pero / aunque\" — adversativo, cualquier tiempo","fr":"\"mais / bien que\" — connecteur adversatif, tous les temps","pt-BR":"\"mas / embora\" — adversativo, qualquer tempo","th":"\"แต่ / แม้ว่า\"","id":"\"tetapi / meskipun\"","vi":"\"nhưng / dù\"","ja":"「〜けど・〜が」"}'::jsonb, '한국어는 어렵지만 재미있어요.', '{"en":"Korean is hard, but interesting.","es":"El coreano es difícil pero interesante.","fr":"Le coréen est difficile mais intéressant.","pt-BR":"O coreano é difícil, mas é interessante.","th":"ภาษาเกาหลียากแต่ก็สนุก","id":"Bahasa Korea sulit, tapi menarik.","vi":"Tiếng Hàn khó nhưng thú vị.","ja":"韓国語は難しいけど面白いです。"}'::jsonb, 'topik-1'),
('-(으)면', '{"en":"\"if / when\" (conditional)","es":"\"si / cuando\" (condicional)","fr":"\"si / quand\" (conditionnel)","pt-BR":"\"se / quando\" (condicional)","th":"\"ถ้า / เมื่อ\"","id":"\"jika / kalau\"","vi":"\"nếu / khi\"","ja":"「もし〜たら / 〜ば」"}'::jsonb, '시간이 있으면 같이 가요.', '{"en":"If you have time, let’s go together.","es":"Si tienes tiempo, vamos juntos.","fr":"Si tu as le temps, allons-y ensemble.","pt-BR":"Se tiver tempo, vamos juntos.","th":"ถ้ามีเวลา ไปด้วยกันนะ","id":"Kalau ada waktu, ayo pergi bersama.","vi":"Nếu có thời gian, đi cùng nhau nhé.","ja":"時間があれば一緒に行きましょう。"}'::jsonb, 'topik-1'),
('-ㄴ/는데', '{"en":"\"the thing is...\" — background, soft contrast, set-up for what follows","es":"\"es que...\" — contexto de fondo o contraste suave","fr":"\"il faut savoir que...\" — contexte de fond ou contraste léger","pt-BR":"\"acontece que...\" — contexto de fundo ou contraste suave","th":"\"คือว่า...\" — เกริ่นเหตุผล / ขัดแย้งเบา ๆ","id":"\"jadi begini...\" — latar / kontras lembut","vi":"\"chuyện là...\" — bối cảnh / tương phản nhẹ","ja":"「〜んだけど」— 前置き・軽い対比"}'::jsonb, '배가 고픈데 같이 밥 먹을까요?', '{"en":"I’m hungry — want to eat together?","es":"Tengo hambre, ¿comemos juntos?","fr":"J’ai faim, on mange ensemble ?","pt-BR":"Estou com fome, vamos comer juntos?","th":"หิวข้าวจัง ไปกินด้วยกันไหม","id":"Saya lapar, mau makan bareng?","vi":"Tôi đói rồi, mình ăn cùng nhau nhé?","ja":"お腹が空いたんだけど、一緒に食べませんか？"}'::jsonb, 'topik-1'),
('-고 싶다', '{"en":"\"want to do\" — used in 1st person (3rd: -고 싶어하다)","es":"\"querer hacer\" — 1ª persona (3ª: -고 싶어하다)","fr":"\"vouloir faire\" — 1ʳᵉ personne (3ᵉ : -고 싶어하다)","pt-BR":"\"querer fazer\" — 1ª pessoa (3ª: -고 싶어하다)","th":"\"อยากทำ\" — บุรุษที่ 1 (บุรุษที่ 3: -고 싶어하다)","id":"\"ingin / mau melakukan\" — orang pertama (ketiga: -고 싶어하다)","vi":"\"muốn làm\" — ngôi 1 (ngôi 3: -고 싶어하다)","ja":"「〜したい」— 一人称(三人称は -고 싶어하다)"}'::jsonb, '드라마를 보고 싶어요.', '{"en":"I want to watch a drama.","es":"Quiero ver un drama.","fr":"Je veux regarder un drama.","pt-BR":"Quero ver um drama.","th":"ฉันอยากดูซีรีส์","id":"Saya ingin menonton drama.","vi":"Tôi muốn xem phim.","ja":"ドラマを見たいです。"}'::jsonb, 'topik-1'),
('-고 있다', '{"en":"progressive aspect — \"be ...ing\"","es":"aspecto progresivo — \"estar + gerundio\"","fr":"aspect progressif — \"être en train de\"","pt-BR":"aspecto progressivo — \"estar fazendo\"","th":"รูปกำลังกระทำ — \"กำลัง...\"","id":"aspek progresif — \"sedang...\"","vi":"thì tiếp diễn — \"đang...\"","ja":"「〜ている」— 進行"}'::jsonb, '지금 뭐 하고 있어요?', '{"en":"What are you doing now?","es":"¿Qué estás haciendo ahora?","fr":"Que fais-tu maintenant ?","pt-BR":"O que você está fazendo agora?","th":"ตอนนี้ทำอะไรอยู่","id":"Sedang apa sekarang?","vi":"Bây giờ bạn đang làm gì?","ja":"今、何をしていますか？"}'::jsonb, 'topik-1'),
('-(으)러 가다/오다', '{"en":"\"go / come to (do)\" — purpose with motion verbs only","es":"\"ir / venir a (hacer)\" — propósito con verbos de movimiento","fr":"\"aller / venir (faire)\" — but avec verbes de mouvement","pt-BR":"\"ir / vir (fazer)\" — propósito com verbos de movimento","th":"\"ไป/มา เพื่อ...\" — กับกริยาเคลื่อนที่เท่านั้น","id":"\"pergi / datang untuk...\" — verba gerak saja","vi":"\"đi / đến để...\" — chỉ với động từ chuyển động","ja":"「〜しに行く・来る」— 移動の目的"}'::jsonb, '책을 사러 서점에 갔어요.', '{"en":"I went to the bookstore to buy a book.","es":"Fui a la librería a comprar un libro.","fr":"Je suis allé à la librairie pour acheter un livre.","pt-BR":"Fui à livraria comprar um livro.","th":"ฉันไปร้านหนังสือเพื่อซื้อหนังสือ","id":"Saya pergi ke toko buku untuk membeli buku.","vi":"Tôi đến nhà sách để mua sách.","ja":"本を買いに本屋に行きました。"}'::jsonb, 'topik-1'),
('-(으)ㄴ 적이 있다/없다', '{"en":"past experience — \"have / have never (done)\"","es":"experiencia pasada — \"haber / no haber + participio\"","fr":"expérience passée — \"avoir déjà / ne jamais fait\"","pt-BR":"experiência passada — \"já / nunca fiz\"","th":"ประสบการณ์ในอดีต — \"เคย / ไม่เคย\"","id":"pengalaman lampau — \"pernah / belum pernah\"","vi":"kinh nghiệm — \"đã từng / chưa từng\"","ja":"経験「〜したことがある／ない」"}'::jsonb, '한국에 가 본 적이 있어요?', '{"en":"Have you ever been to Korea?","es":"¿Has estado alguna vez en Corea?","fr":"Es-tu déjà allé en Corée ?","pt-BR":"Você já esteve na Coreia?","th":"เคยไปเกาหลีไหม","id":"Pernah ke Korea?","vi":"Bạn đã từng đến Hàn Quốc chưa?","ja":"韓国に行ったことがありますか？"}'::jsonb, 'topik-1'),
('-겠어요', '{"en":"supposition or firm 1st-person intent / formula in fixed phrases","es":"suposición o intención firme en 1ª persona; frases fijas","fr":"supposition ou volonté ferme en 1ʳᵉ personne; expressions figées","pt-BR":"suposição ou intenção firme em 1ª pessoa; frases fixas","th":"การคาดเดา / ความตั้งใจหนักแน่น / สำนวน","id":"dugaan / niat tegas orang pertama; ungkapan tetap","vi":"phỏng đoán / ý chí mạnh ngôi 1 / cụm cố định","ja":"推量・強い意志(一人称)/定型表現「〜だろう/しよう」"}'::jsonb, '맛있겠어요!', '{"en":"That must be delicious!","es":"¡Debe estar rico!","fr":"Ça doit être délicieux !","pt-BR":"Deve estar uma delícia!","th":"น่าจะอร่อยมาก!","id":"Pasti enak!","vi":"Chắc là ngon lắm!","ja":"おいしそうですね！"}'::jsonb, 'topik-1'),
('-(으)ㄹ래요?', '{"en":"\"Do you want to ...?\" (offer) / \"I’d like to ...\" (1st p. preference)","es":"\"¿Quieres...?\" (oferta) / \"quiero/me gustaría...\" (1ª persona)","fr":"\"Tu veux...?\" (proposition) / \"j’aimerais...\" (1ʳᵉ pers.)","pt-BR":"\"Quer...?\" (oferta) / \"eu gostaria...\" (1ª pessoa)","th":"\"จะ ... ไหม?\" (ชวน) / \"ฉันจะ...\" (ความต้องการ)","id":"\"Mau ...?\" (tawaran) / \"saya mau...\" (preferensi)","vi":"\"Bạn có muốn...?\" (đề nghị) / \"tôi muốn...\" (sở thích)","ja":"「〜ますか？(誘い)」/「〜します(意向)」"}'::jsonb, '같이 영화 볼래요?', '{"en":"Want to watch a movie together?","es":"¿Quieres ver una película juntos?","fr":"Tu veux regarder un film ensemble ?","pt-BR":"Quer ver um filme juntos?","th":"ดูหนังด้วยกันไหม","id":"Mau nonton film bareng?","vi":"Bạn muốn xem phim cùng nhau không?","ja":"一緒に映画を見ませんか？"}'::jsonb, 'topik-1'),
('-네요', '{"en":"discovery / mild surprise — \"oh, ...!\", \"I see, ...!\"","es":"descubrimiento / sorpresa suave — \"¡vaya, ...!\", \"¡anda...!\"","fr":"découverte / légère surprise — «tiens, ...!», «ah, ...!»","pt-BR":"descoberta / surpresa leve — \"nossa, ...!\", \"olha só, ...!\"","th":"การค้นพบ / ประหลาดใจเบา ๆ — \"อ้าว...\" \"อืม...\"","id":"penemuan / kaget ringan — \"wah, ...!\", \"ternyata...\"","vi":"phát hiện / ngạc nhiên nhẹ — \"ồ, ...!\", \"à ra vậy...\"","ja":"気づき・軽い驚き「〜ですね」"}'::jsonb, '여기 정말 예쁘네요!', '{"en":"Wow, this place is really pretty!","es":"¡Vaya, qué bonito es este lugar!","fr":"Oh, cet endroit est vraiment joli !","pt-BR":"Nossa, este lugar é lindo!","th":"ที่นี่สวยจริง ๆ เลยนะ","id":"Wah, tempat ini cantik sekali!","vi":"Ồ, chỗ này đẹp thật!","ja":"ここ、本当にきれいですね！"}'::jsonb, 'topik-1'),
('-지요? / -죠?', '{"en":"\"right?\" — seek confirmation of something assumed","es":"\"¿verdad?\" — busca confirmación de algo asumido","fr":"«non ?» / «n’est-ce pas ?» — chercher confirmation","pt-BR":"\"né?\" / \"não é?\" — pedir confirmação","th":"\"ใช่ไหม?\" — ขอการยืนยัน","id":"\"kan?\" / \"ya kan?\" — minta konfirmasi","vi":"\"phải không?\" — xác nhận","ja":"「〜でしょう？・〜よね？」— 確認"}'::jsonb, '한국 음식 좋아하시죠?', '{"en":"You like Korean food, right?","es":"Le gusta la comida coreana, ¿verdad?","fr":"Vous aimez la cuisine coréenne, non ?","pt-BR":"Você gosta de comida coreana, né?","th":"คุณชอบอาหารเกาหลีใช่ไหมคะ","id":"Anda suka makanan Korea, kan?","vi":"Anh/chị thích món Hàn phải không?","ja":"韓国料理がお好きですよね？"}'::jsonb, 'topik-1'),
('-아/어도 되다', '{"en":"\"may / it’s ok to ...\" — permission","es":"\"se puede / está bien si...\" — permiso","fr":"«il est permis de» / «on peut» — permission","pt-BR":"\"pode / está tudo bem\" — permissão","th":"\"...ก็ได้\" — ขออนุญาต / อนุญาต","id":"\"boleh ...\" — izin","vi":"\"có thể / được ...\" — cho phép","ja":"「〜てもいい」— 許可"}'::jsonb, '여기 앉아도 돼요?', '{"en":"May I sit here?","es":"¿Puedo sentarme aquí?","fr":"Je peux m’asseoir ici ?","pt-BR":"Posso me sentar aqui?","th":"นั่งตรงนี้ได้ไหมคะ","id":"Boleh saya duduk di sini?","vi":"Tôi ngồi đây được không?","ja":"ここに座ってもいいですか？"}'::jsonb, 'topik-1'),
('-지 않아도 되다', '{"en":"\"don’t have to\" — not required (different from prohibition)","es":"\"no hace falta / no es necesario\" (no es prohibición)","fr":"«il n’est pas nécessaire de» — non requis","pt-BR":"\"não precisa\" — não é obrigatório (não é proibição)","th":"\"ไม่ต้อง ... ก็ได้\"","id":"\"tidak harus / tidak perlu\"","vi":"\"không cần phải\"","ja":"「〜なくてもいい」— 義務なし"}'::jsonb, '걱정하지 않아도 돼요.', '{"en":"You don’t have to worry.","es":"No tienes que preocuparte.","fr":"Tu n’as pas besoin de t’inquiéter.","pt-BR":"Você não precisa se preocupar.","th":"ไม่ต้องเป็นห่วงก็ได้","id":"Tidak perlu khawatir.","vi":"Bạn không cần lo lắng.","ja":"心配しなくてもいいですよ。"}'::jsonb, 'topik-1'),
('-아/어 드리다', '{"en":"do something for someone — honorific of -아/어 주다","es":"hacer algo para alguien — honorífico de -아/어 주다","fr":"faire qch pour qqn — honorifique de -아/어 주다","pt-BR":"fazer algo por alguém — honorífico de -아/어 주다","th":"ทำให้ใคร — รูปยกย่องของ -아/어 주다","id":"melakukan untuk orang lain — hormat dari -아/어 주다","vi":"làm hộ ai — kính ngữ của -아/어 주다","ja":"「お〜する/差し上げる」— 주다の謙譲"}'::jsonb, '제가 도와 드릴게요.', '{"en":"Let me help you.","es":"Yo le ayudaré.","fr":"Je vais vous aider.","pt-BR":"Eu vou te ajudar.","th":"ให้ฉันช่วยนะคะ","id":"Saya yang akan membantu.","vi":"Để tôi giúp anh/chị.","ja":"お手伝いいたします。"}'::jsonb, 'topik-1'),
('의문사', '{"en":"core question words: what / who / where / when / why / how","es":"interrogativos esenciales: qué / quién / dónde / cuándo / por qué / cómo","fr":"mots interrogatifs : quoi / qui / où / quand / pourquoi / comment","pt-BR":"interrogativos: o que / quem / onde / quando / por que / como","th":"คำถามหลัก: อะไร / ใคร / ที่ไหน / เมื่อไหร่ / ทำไม / อย่างไร","id":"kata tanya inti: apa / siapa / di mana / kapan / mengapa / bagaimana","vi":"từ để hỏi: gì / ai / ở đâu / khi nào / tại sao / thế nào","ja":"疑問詞: 何 / 誰 / どこ / いつ / なぜ / どう"}'::jsonb, '이름이 뭐예요?', '{"en":"What is your name?","es":"¿Cómo te llamas?","fr":"Comment t’appelles-tu ?","pt-BR":"Qual é o seu nome?","th":"ชื่ออะไรคะ","id":"Siapa nama Anda?","vi":"Tên bạn là gì?","ja":"お名前は何ですか？"}'::jsonb, 'topik-1'),
('숫자', '{"en":"two number systems: Sino-Korean (prices, dates) and native (counting, ages, hours)","es":"dos sistemas: sino-coreano (precios, fechas) y nativo (contar objetos, edad, horas)","fr":"deux systèmes : sino-coréen (prix, dates) et natif (objets, âge, heures)","pt-BR":"dois sistemas: sino-coreano (preços, datas) e nativo (contar, idade, horas)","th":"มีสองระบบ: ตัวเลขจีน (ราคา/วันที่) และตัวเลขเกาหลีแท้ (นับของ/อายุ/ชั่วโมง)","id":"dua sistem: Sino-Korea (harga, tanggal) dan asli (menghitung, usia, jam)","vi":"hai hệ: Hán-Hàn (giá, ngày) và thuần Hàn (đếm, tuổi, giờ)","ja":"二系統: 漢字語(値段・日付)と固有語(数える・年齢・時)"}'::jsonb, '이 가방 얼마예요? — 삼만 오천 원이에요.', '{"en":"How much is this bag? — It’s 35,000 won.","es":"¿Cuánto cuesta esta mochila? — Son 35.000 won.","fr":"Combien coûte ce sac ? — 35 000 wons.","pt-BR":"Quanto custa essa mochila? — 35.000 wons.","th":"กระเป๋านี้ราคาเท่าไหร่ — 35,000 วอน","id":"Berapa tas ini? — 35.000 won.","vi":"Cái túi này bao nhiêu? — 35.000 won.","ja":"このカバンはいくらですか？ — 三万五千ウォンです。"}'::jsonb, 'topik-1'),
('시간 표현', '{"en":"common time adverbs: today, yesterday, tomorrow, now, always, sometimes…","es":"adverbios de tiempo: hoy, ayer, mañana, ahora, siempre, a veces…","fr":"adverbes de temps : aujourd’hui, hier, demain, maintenant, toujours, parfois…","pt-BR":"advérbios de tempo: hoje, ontem, amanhã, agora, sempre, às vezes…","th":"คำบอกเวลา: วันนี้ เมื่อวาน พรุ่งนี้ ตอนนี้ เสมอ บางครั้ง…","id":"kata waktu: hari ini, kemarin, besok, sekarang, selalu, kadang…","vi":"từ chỉ thời gian: hôm nay, hôm qua, ngày mai, bây giờ, luôn, thỉnh thoảng…","ja":"時の副詞: 今日・昨日・明日・今・いつも・時々…"}'::jsonb, '오늘 만나요.', '{"en":"Let’s meet today.","es":"Nos vemos hoy.","fr":"On se voit aujourd’hui.","pt-BR":"A gente se vê hoje.","th":"เจอกันวันนี้นะ","id":"Sampai jumpa hari ini.","vi":"Hôm nay gặp nhau nhé.","ja":"今日会いましょう。"}'::jsonb, 'topik-1'),
('이 / 그 / 저', '{"en":"three-way demonstratives: 이 (near speaker), 그 (near listener), 저 (far from both)","es":"sistema de 3 distancias: 이 (cerca del hablante), 그 (cerca del oyente), 저 (lejos de ambos)","fr":"démonstratifs à 3 niveaux : 이 (près du locuteur), 그 (près du destinataire), 저 (loin des deux)","pt-BR":"demonstrativos de 3 níveis: 이 (perto do falante), 그 (do ouvinte), 저 (longe de ambos)","th":"ระบบสามขั้น: 이 (ใกล้ผู้พูด) / 그 (ใกล้ผู้ฟัง) / 저 (ไกลทั้งคู่)","id":"3 tingkat: 이 (dekat penutur), 그 (dekat lawan bicara), 저 (jauh dari keduanya)","vi":"ba mức: 이 (gần người nói), 그 (gần người nghe), 저 (xa cả hai)","ja":"コソア: 이(話し手) / 그(聞き手) / 저(双方から遠い)"}'::jsonb, '이 가방 얼마예요?', '{"en":"How much is this bag?","es":"¿Cuánto cuesta esta mochila?","fr":"Combien coûte ce sac ?","pt-BR":"Quanto custa essa mochila?","th":"กระเป๋านี้ราคาเท่าไหร่","id":"Berapa tas ini?","vi":"Cái túi này bao nhiêu?","ja":"このカバンはいくらですか？"}'::jsonb, 'topik-1'),
('위치어 (위 / 아래 / 앞 / 뒤 / 옆 …)', '{"en":"location nouns used with 에 (state) or 에서 (action): above, under, in front, behind, next to, inside, outside, between, near","es":"sustantivos de ubicación con 에 (estático) o 에서 (acción): encima, debajo, delante, detrás, al lado, dentro, fuera, entre, cerca","fr":"noms de lieu avec 에 / 에서 : dessus, dessous, devant, derrière, à côté, dans, dehors, entre, près","pt-BR":"substantivos de lugar com 에 / 에서: em cima, embaixo, na frente, atrás, ao lado, dentro, fora, entre, perto","th":"คำบอกตำแหน่ง + 에/에서: ข้างบน ข้างล่าง ข้างหน้า ข้างหลัง ข้าง ๆ ข้างใน ข้างนอก ระหว่าง ใกล้","id":"kata lokasi + 에/에서: atas, bawah, depan, belakang, samping, dalam, luar, antara, dekat","vi":"từ chỉ vị trí + 에/에서: trên, dưới, trước, sau, cạnh, trong, ngoài, giữa, gần","ja":"位置名詞+에/에서: 上・下・前・後・横・中・外・間・近く"}'::jsonb, '가방 안에 책이 있어요.', '{"en":"There’s a book inside the bag.","es":"Hay un libro dentro de la mochila.","fr":"Il y a un livre dans le sac.","pt-BR":"Tem um livro dentro da mochila.","th":"มีหนังสืออยู่ในกระเป๋า","id":"Ada buku di dalam tas.","vi":"Có một quyển sách trong cặp.","ja":"カバンの中に本があります。"}'::jsonb, 'topik-1'),
('수 분류사 (개 / 명 / 권 / 잔 / 마리 …)', '{"en":"numeral classifiers — each category of object has its own counter, used with native numbers","es":"clasificadores numéricos — cada categoría tiene un contador propio (con números nativos)","fr":"classificateurs numériques — chaque catégorie a son compteur (avec nombres natifs)","pt-BR":"classificadores numéricos — cada categoria tem seu contador (números nativos)","th":"ลักษณนาม — ของแต่ละหมวดมีลักษณนามต่างกัน (ใช้ตัวเลขเกาหลีแท้)","id":"penggolong numeral — tiap kategori objek punya penggolongnya (angka asli)","vi":"loại từ — mỗi nhóm vật có loại từ riêng (dùng số thuần Hàn)","ja":"助数詞: 개(個), 명(人), 권(冊), 잔(杯), 마리(匹)… 固有語数詞と併用"}'::jsonb, '사과 두 개 주세요.', '{"en":"Two apples, please.","es":"Deme dos manzanas, por favor.","fr":"Deux pommes, s’il vous plaît.","pt-BR":"Duas maçãs, por favor.","th":"ขอแอปเปิ้ลสองลูกค่ะ","id":"Tolong, dua apel.","vi":"Cho tôi hai quả táo.","ja":"りんごを二つください。"}'::jsonb, 'topik-1'),
('인사 표현', '{"en":"core greetings: hello, goodbye (to the one leaving), thank you","es":"saludos esenciales: hola, adiós (al que se va), gracias","fr":"salutations de base : bonjour, au revoir (à celui qui part), merci","pt-BR":"saudações essenciais: olá, adeus (a quem vai), obrigado/a","th":"คำทักทายหลัก: สวัสดี / ไปดี / ขอบคุณ","id":"salam dasar: halo / selamat jalan / terima kasih","vi":"lời chào cơ bản: xin chào / tạm biệt / cảm ơn","ja":"挨拶: こんにちは / さようなら(去る人へ) / ありがとうございます"}'::jsonb, '안녕히 가세요!', '{"en":"Goodbye! (to the one leaving)","es":"¡Adiós! (al que se va)","fr":"Au revoir ! (à celui qui s’en va)","pt-BR":"Tchau! (a quem está indo)","th":"ไปดีนะคะ (ลาผู้ที่จะไป)","id":"Selamat jalan! (kepada yang pergi)","vi":"Tạm biệt nhé! (với người đi)","ja":"さようなら！(去る人に)"}'::jsonb, 'topik-1'),
('얼마나 걸려요?', '{"en":"\"How long does it take?\" — duration question using 걸리다","es":"\"¿Cuánto tiempo se tarda?\" — pregunta de duración con 걸리다","fr":"«Combien de temps cela prend ?» — durée avec 걸리다","pt-BR":"\"Quanto tempo demora?\" — pergunta de duração com 걸리다","th":"\"ใช้เวลาเท่าไหร่?\" — ถามระยะเวลา (걸리다)","id":"\"Berapa lama?\" — pertanyaan durasi (걸리다)","vi":"\"Mất bao lâu?\" — câu hỏi thời gian (걸리다)","ja":"「どのくらいかかりますか？」(걸리다)"}'::jsonb, '집에서 학교까지 얼마나 걸려요?', '{"en":"How long does it take from home to school?","es":"¿Cuánto se tarda de casa a la escuela?","fr":"Combien de temps faut-il de chez toi à l’école ?","pt-BR":"Quanto tempo leva de casa até a escola?","th":"จากบ้านไปโรงเรียนใช้เวลาเท่าไหร่","id":"Dari rumah ke sekolah berapa lama?","vi":"Từ nhà đến trường mất bao lâu?","ja":"家から学校までどのくらいかかりますか？"}'::jsonb, 'topik-1'),
('N(이)랑 / 하고 + 같이 / 함께', '{"en":"\"together with (someone)\" — companion particle + 같이/함께","es":"\"junto con (alguien)\" — partícula de compañía + 같이/함께","fr":"\"avec / ensemble (qqn)\" — particule + 같이/함께","pt-BR":"\"junto com (alguém)\" — partícula de companhia + 같이/함께","th":"\"กับ ... ด้วยกัน\" — อนุภาคบอกผู้ร่วม + 같이/함께","id":"\"bersama (orang)\" — partikel pendamping + 같이/함께","vi":"\"cùng với (ai)\" — tiểu từ đi cùng + 같이/함께","ja":"「(人)と一緒に」— 同伴助詞 + 같이/함께"}'::jsonb, '친구랑 같이 밥을 먹었어요.', '{"en":"I ate together with a friend.","es":"Comí junto con un amigo.","fr":"J’ai mangé avec un ami.","pt-BR":"Comi junto com um amigo.","th":"ฉันกินข้าวกับเพื่อน","id":"Saya makan bersama teman.","vi":"Tôi ăn cơm cùng bạn.","ja":"友達と一緒にご飯を食べました。"}'::jsonb, 'topik-1'),
('가져가다 / 가져오다 / 데려가다 / 데려오다', '{"en":"movement + action compounds — take / bring (object), take / bring (person)","es":"compuestos de movimiento + acción — llevar / traer (objeto), llevar / traer (persona)","fr":"composés de mouvement + action — emporter / apporter, emmener / amener","pt-BR":"compostos de movimento + ação — levar / trazer (objeto), levar / trazer (pessoa)","th":"คำประสม \"ไป/มา + การกระทำ\" — เอาไป / เอามา / พาไป / พามา","id":"kata majemuk gerak + aksi — membawa pergi / membawa (benda / orang)","vi":"từ ghép chuyển động + hành động — đem đi / đem đến / dẫn đi / dẫn đến","ja":"移動 + 動作の複合語 — 持っていく / 持ってくる / 連れていく / 連れてくる"}'::jsonb, '음식을 좀 가져왔어요.', '{"en":"I brought some food.","es":"Traje algo de comida.","fr":"J’ai apporté un peu de nourriture.","pt-BR":"Trouxe um pouco de comida.","th":"ฉันเอาอาหารมาให้","id":"Saya membawakan sedikit makanan.","vi":"Tôi mang theo chút đồ ăn.","ja":"食べ物を少し持ってきました。"}'::jsonb, 'topik-1'),
('-지 말다', '{"en":"negative imperative — \"don’t (do)\"; 마세요 / 마 / 말자 / 마십시오","es":"imperativo negativo — \"no (hagas)\"; 마세요 / 마 / 말자 / 마십시오","fr":"impératif négatif — «ne ... pas»; 마세요 / 마 / 말자 / 마십시오","pt-BR":"imperativo negativo — \"não (faça)\"; 마세요 / 마 / 말자 / 마십시오","th":"คำสั่งห้าม — \"อย่า ...\"; 마세요 / 마 / 말자 / 마십시오","id":"larangan — \"jangan ...\"; 마세요 / 마 / 말자 / 마십시오","vi":"cấm đoán — \"đừng ...\"; 마세요 / 마 / 말자 / 마십시오","ja":"「〜してはいけない / 〜しないで」(마세요 / 마 / 말자 / 마십시오)"}'::jsonb, '걱정하지 마세요.', '{"en":"Please don’t worry.","es":"No se preocupe.","fr":"Ne vous inquiétez pas.","pt-BR":"Não se preocupe.","th":"อย่ากังวลเลย","id":"Jangan khawatir.","vi":"Đừng lo lắng.","ja":"心配しないでください。"}'::jsonb, 'topik-1'),
('N 말고', '{"en":"\"not N, but ...\" — rejects one option in favor of another","es":"\"no N, sino ...\" — rechaza una opción a favor de otra","fr":"«pas N, mais ...» — rejette une option pour une autre","pt-BR":"\"N não, e sim ...\" — rejeita uma opção em favor de outra","th":"\"ไม่เอา N เอา ... แทน\"","id":"\"bukan N, melainkan ...\"","vi":"\"không phải N, mà ...\"","ja":"「Nではなくて ...」— 別の選択"}'::jsonb, '커피 말고 차 주세요.', '{"en":"Not coffee, please give me tea.","es":"Café no, deme té.","fr":"Pas de café, du thé s’il vous plaît.","pt-BR":"Café não, me dá chá.","th":"ไม่เอากาแฟ ขอชาแทนค่ะ","id":"Bukan kopi, tolong tehnya.","vi":"Không phải cà phê, cho tôi trà.","ja":"コーヒーではなくお茶をください。"}'::jsonb, 'topik-1'),
('-(으)ㄹ 수 있다/없다', '{"en":"can / cannot — ability, possibility","es":"poder / no poder — habilidad o posibilidad","fr":"pouvoir / ne pas pouvoir — capacité ou possibilité","pt-BR":"poder / não poder — habilidade ou possibilidade","th":"\"ทำได้ / ทำไม่ได้\" — ความสามารถ / ความเป็นไปได้","id":"\"bisa / tidak bisa\" — kemampuan atau kemungkinan","vi":"\"có thể / không thể\" — khả năng hoặc khả thi","ja":"「〜できる / 〜できない」— 可能・能力"}'::jsonb, '저는 한국어를 조금 할 수 있어요.', '{"en":"I can speak a little Korean.","es":"Puedo hablar un poco de coreano.","fr":"Je peux parler un peu coréen.","pt-BR":"Eu sei falar um pouco de coreano.","th":"ฉันพูดภาษาเกาหลีได้นิดหน่อย","id":"Saya bisa berbahasa Korea sedikit.","vi":"Tôi có thể nói một chút tiếng Hàn.","ja":"私は韓国語が少しできます。"}'::jsonb, 'topik-2'),
('-(으)ㄹ 때', '{"en":"\"when / at the moment of\" — simultaneous or habitual","es":"\"cuando / en el momento de\" — simultáneo o habitual","fr":"\"quand / au moment où\" — simultané ou habituel","pt-BR":"\"quando / no momento em que\" — simultâneo ou habitual","th":"\"เวลา / เมื่อ\" — ขณะ หรือ เป็นนิสัย","id":"\"ketika / waktu\" — bersamaan atau kebiasaan","vi":"\"khi / lúc\" — đồng thời hoặc thói quen","ja":"「〜とき / 〜時」— 同時・習慣"}'::jsonb, '심심할 때 음악을 들어요.', '{"en":"When I’m bored, I listen to music.","es":"Cuando me aburro, escucho música.","fr":"Quand je m’ennuie, j’écoute de la musique.","pt-BR":"Quando fico entediado, ouço música.","th":"เวลาเบื่อ ฉันฟังเพลง","id":"Ketika bosan, saya mendengarkan musik.","vi":"Khi buồn chán, tôi nghe nhạc.","ja":"退屈なとき音楽を聞きます。"}'::jsonb, 'topik-2'),
('-기 전에', '{"en":"\"before (doing)\" — also N + 전에 with time nouns","es":"\"antes de (hacer)\" — también N + 전에 con sustantivos de tiempo","fr":"\"avant de (faire)\" — aussi N + 전에 avec un nom de temps","pt-BR":"\"antes de (fazer)\" — também N + 전에 com substantivos de tempo","th":"\"ก่อน ...(ทำ)\" — รวมถึง N + 전에","id":"\"sebelum (melakukan)\" — juga N + 전에 dengan kata waktu","vi":"\"trước khi (làm)\" — cũng N + 전에 với danh từ thời gian","ja":"「〜する前に」(名詞の前は N + 전에)"}'::jsonb, '자기 전에 이를 닦아요.', '{"en":"I brush my teeth before sleeping.","es":"Me cepillo los dientes antes de dormir.","fr":"Je me brosse les dents avant de dormir.","pt-BR":"Eu escovo os dentes antes de dormir.","th":"แปรงฟันก่อนนอน","id":"Saya menyikat gigi sebelum tidur.","vi":"Tôi đánh răng trước khi đi ngủ.","ja":"寝る前に歯を磨きます。"}'::jsonb, 'topik-2'),
('-(으)ㄴ 후에 / 다음에', '{"en":"\"after (doing)\" — 후에 and 다음에 are interchangeable","es":"\"después de (hacer)\" — 후에 y 다음에 son intercambiables","fr":"\"après (avoir fait)\" — 후에 / 다음에 sont équivalents","pt-BR":"\"depois de (fazer)\" — 후에 e 다음에 são intercambiáveis","th":"\"หลังจาก (ทำ)\" — 후에 / 다음에 ใช้แทนกันได้","id":"\"setelah (melakukan)\" — 후에 dan 다음에 setara","vi":"\"sau khi (làm)\" — 후에 và 다음에 tương đương","ja":"「〜した後で / 〜した次に」"}'::jsonb, '밥을 먹은 후에 산책했어요.', '{"en":"After eating, I went for a walk.","es":"Después de comer, salí a caminar.","fr":"Après avoir mangé, je suis allé me promener.","pt-BR":"Depois de comer, fui caminhar.","th":"หลังจากกินข้าวก็ไปเดินเล่น","id":"Setelah makan, saya jalan-jalan.","vi":"Sau khi ăn, tôi đi dạo.","ja":"ご飯を食べた後で散歩しました。"}'::jsonb, 'topik-2'),
('-는 동안', '{"en":"\"while / during\" — two actions overlap; subjects may differ (cf. -(으)면서, same subject)","es":"\"mientras / durante\" — dos acciones simultáneas; sujetos pueden diferir (cf. -(으)면서, mismo sujeto)","fr":"\"pendant que / durant\" — actions parallèles; sujets différents possibles","pt-BR":"\"enquanto / durante\" — duas ações em paralelo; sujeitos podem diferir","th":"\"ในระหว่างที่\" — กระทำพร้อมกัน, ผู้กระทำต่างกันได้","id":"\"selama / sementara\" — aksi paralel, subjek bisa berbeda","vi":"\"trong khi / trong lúc\" — hai hành động song song, chủ ngữ khác nhau cũng được","ja":"「〜している間」— 並行(主語が異なっても可)"}'::jsonb, '음악을 듣는 동안 공부했어요.', '{"en":"I studied while listening to music.","es":"Estudié mientras escuchaba música.","fr":"J’ai étudié pendant que j’écoutais de la musique.","pt-BR":"Estudei enquanto ouvia música.","th":"ฉันเรียนหนังสือไปฟังเพลงไป","id":"Saya belajar sambil mendengarkan musik.","vi":"Tôi học trong khi nghe nhạc.","ja":"音楽を聞いている間、勉強しました。"}'::jsonb, 'topik-2'),
('-고 나서 / -고 나면', '{"en":"\"after fully doing\" — emphasizes completion before the next action","es":"\"después de completar\" — enfatiza que A se completó del todo antes de B","fr":"\"après avoir fini de\" — insiste sur l’achèvement préalable","pt-BR":"\"depois de terminar de\" — enfatiza a conclusão antes da próxima ação","th":"\"หลังจาก ... เสร็จแล้ว\" — เน้นการทำเสร็จ","id":"\"setelah selesai\" — menekankan penyelesaian terlebih dahulu","vi":"\"sau khi xong\" — nhấn mạnh hoàn tất trước","ja":"「〜してから / 〜し終えたら」— 完了の強調"}'::jsonb, '밥을 먹고 나서 설거지를 해요.', '{"en":"After eating, I wash the dishes.","es":"Después de comer (del todo), friego los platos.","fr":"Après avoir mangé, je fais la vaisselle.","pt-BR":"Depois de comer, lavo a louça.","th":"หลังจากกินข้าวเสร็จ ก็ล้างจาน","id":"Setelah selesai makan, saya cuci piring.","vi":"Sau khi ăn xong, tôi rửa bát.","ja":"ご飯を食べてから皿洗いをします。"}'::jsonb, 'topik-2'),
('-는 것', '{"en":"verb nominalization — \"the act of / -ing\"; spoken contractions 게/걸/건","es":"nominalización — \"el hecho de / acción de\"; contracciones habladas 게/걸/건","fr":"nominalisation — «le fait de / -er»; contractions orales 게/걸/건","pt-BR":"nominalização — \"o ato de / fazer\"; contrações faladas 게/걸/건","th":"การทำให้กริยาเป็นคำนาม — \"การทำ ...\"; รูปย่อ 게/걸/건","id":"nominalisasi verba — \"tindakan ...\"; bentuk lisan 게/걸/건","vi":"danh hóa động từ — \"việc / hành động ...\"; rút gọn 게/걸/건","ja":"動詞の名詞化「〜こと / 〜の」— 口語短縮 게/걸/건"}'::jsonb, '음악을 듣는 것을 좋아해요.', '{"en":"I like listening to music.","es":"Me gusta escuchar música.","fr":"J’aime écouter de la musique.","pt-BR":"Eu gosto de ouvir música.","th":"ฉันชอบฟังเพลง","id":"Saya suka mendengarkan musik.","vi":"Tôi thích nghe nhạc.","ja":"音楽を聞くことが好きです。"}'::jsonb, 'topik-2'),
('-(으)ㄴ/는 것 같다', '{"en":"\"it seems / I think\" — soft conjecture about present/past","es":"\"parece que / creo que\" — conjetura suave sobre presente o pasado","fr":"«il semble que / je crois que» — conjecture douce, présent/passé","pt-BR":"\"parece que / acho que\" — conjectura suave, presente ou passado","th":"\"คิดว่า / ดูเหมือน ...\" — การคาดเดาเบา ๆ (ปัจจุบัน / อดีต)","id":"\"sepertinya / saya pikir\" — dugaan halus (kini / lampau)","vi":"\"có vẻ / tôi nghĩ\" — phỏng đoán nhẹ (hiện tại / quá khứ)","ja":"「〜と思う / 〜ようだ」— 弱い推量(現在・過去)"}'::jsonb, '오늘 날씨가 추운 것 같아요.', '{"en":"It seems cold today.","es":"Parece que hoy hace frío.","fr":"On dirait qu’il fait froid aujourd’hui.","pt-BR":"Parece que está frio hoje.","th":"วันนี้ดูเหมือนจะหนาว","id":"Hari ini sepertinya dingin.","vi":"Hôm nay có vẻ lạnh.","ja":"今日は寒いようです。"}'::jsonb, 'topik-2'),
('-(으)ㄴ/는 모양이다', '{"en":"\"apparently / by the looks of it\" — inference from observable evidence","es":"\"al parecer / por lo que se ve\" — deducción a partir de evidencia visible","fr":"«apparemment / on dirait» — déduction à partir de signes visibles","pt-BR":"\"pelo jeito / aparentemente\" — dedução por evidências visíveis","th":"\"ดูท่าทาง / ดูเหมือนว่า\" — สรุปจากสิ่งที่เห็น","id":"\"kelihatannya / rupanya\" — kesimpulan dari bukti yang terlihat","vi":"\"có vẻ / xem ra\" — suy luận từ chứng cứ quan sát được","ja":"「〜らしい / 〜ようだ」— 観察に基づく推測"}'::jsonb, '불이 꺼진 걸 보니 자는 모양이에요.', '{"en":"The lights are off — looks like they’re sleeping.","es":"La luz está apagada, al parecer está durmiendo.","fr":"La lumière est éteinte ; apparemment, ils dorment.","pt-BR":"A luz está apagada, parece que está dormindo.","th":"ไฟดับอยู่ ดูเหมือนจะนอนแล้ว","id":"Lampu mati, kelihatannya sudah tidur.","vi":"Đèn đã tắt, có vẻ đang ngủ.","ja":"電気が消えているところを見ると、寝ているようです。"}'::jsonb, 'topik-2'),
('-아/어야 하다 / 되다', '{"en":"\"have to / must\" — 하다 and 되다 are interchangeable","es":"\"tener que / deber\" — 하다 y 되다 son intercambiables","fr":"\"devoir / il faut\" — 하다 et 되다 sont équivalents","pt-BR":"\"ter que / dever\" — 하다 e 되다 são intercambiáveis","th":"\"ต้อง\" — 하다 / 되다 ใช้แทนกันได้","id":"\"harus\" — 하다 dan 되다 setara","vi":"\"phải\" — 하다 và 되다 tương đương","ja":"「〜なければならない / 〜なきゃ」(하다/되다)"}'::jsonb, '내일까지 숙제를 해야 해요.', '{"en":"I have to do the homework by tomorrow.","es":"Tengo que hacer la tarea para mañana.","fr":"Je dois faire les devoirs d’ici demain.","pt-BR":"Tenho que fazer a lição até amanhã.","th":"ต้องทำการบ้านให้เสร็จภายในพรุ่งนี้","id":"Saya harus mengerjakan PR sampai besok.","vi":"Tôi phải làm bài tập trước ngày mai.","ja":"明日までに宿題をしなければなりません。"}'::jsonb, 'topik-2'),
('-(으)면 되다', '{"en":"\"it suffices to / just need to\" — minimum requirement to satisfy","es":"\"basta con / solo hay que\" — requisito mínimo","fr":"«il suffit de / il faut seulement» — exigence minimale","pt-BR":"\"basta / só precisa\" — requisito mínimo","th":"\"แค่ ... ก็พอ\" — เงื่อนไขขั้นต่ำ","id":"\"cukup / tinggal\" — syarat minimal","vi":"\"chỉ cần\" — yêu cầu tối thiểu","ja":"「〜ばいい」— 最低限の条件"}'::jsonb, '여기에 이름을 쓰면 돼요.', '{"en":"Just write your name here.","es":"Solo tienes que escribir tu nombre aquí.","fr":"Il suffit d’écrire ton nom ici.","pt-BR":"Basta escrever seu nome aqui.","th":"แค่เขียนชื่อตรงนี้ก็พอ","id":"Cukup tulis nama di sini.","vi":"Chỉ cần viết tên ở đây.","ja":"ここに名前を書けばいいです。"}'::jsonb, 'topik-2'),
('-(으)면 안 되다', '{"en":"\"must not / cannot\" — prohibition","es":"\"no se puede / está prohibido\" — prohibición","fr":"«on ne doit pas / il est interdit de» — prohibition","pt-BR":"\"não pode / é proibido\" — proibição","th":"\"ห้าม ... / ทำไม่ได้\" — ข้อห้าม","id":"\"tidak boleh / dilarang\" — larangan","vi":"\"không được\" — cấm","ja":"「〜してはいけない」— 禁止"}'::jsonb, '여기서 담배를 피우면 안 돼요.', '{"en":"You can’t smoke here.","es":"No se puede fumar aquí.","fr":"On ne peut pas fumer ici.","pt-BR":"Não pode fumar aqui.","th":"ห้ามสูบบุหรี่ที่นี่","id":"Tidak boleh merokok di sini.","vi":"Không được hút thuốc ở đây.","ja":"ここで煙草を吸ってはいけません。"}'::jsonb, 'topik-2'),
('-(으)ㄹ 필요가 있다/없다', '{"en":"\"need / no need to\" — more neutral than -아/어야 하다","es":"\"hace falta / no hace falta\" — más neutro que -아/어야 하다","fr":"«il faut / pas besoin de» — plus neutre que -아/어야 하다","pt-BR":"\"é necessário / não é necessário\" — mais neutro que -아/어야 하다","th":"\"จำเป็น / ไม่จำเป็นต้อง\" — เป็นกลางกว่า -아/어야 하다","id":"\"perlu / tidak perlu\" — lebih netral dari -아/어야 하다","vi":"\"cần / không cần\" — trung tính hơn -아/어야 하다","ja":"「〜する必要がある / ない」— 中立的"}'::jsonb, '걱정할 필요가 없어요.', '{"en":"There’s no need to worry.","es":"No hay necesidad de preocuparse.","fr":"Pas besoin de s’inquiéter.","pt-BR":"Não há necessidade de se preocupar.","th":"ไม่จำเป็นต้องเป็นห่วง","id":"Tidak perlu khawatir.","vi":"Không cần phải lo lắng.","ja":"心配する必要はありません。"}'::jsonb, 'topik-2'),
('-(으)ㄹ게요', '{"en":"\"I will (just decided) / I promise\" — 1st-person commitment to listener","es":"\"yo lo haré / lo prometo\" — compromiso del hablante en el momento","fr":"\"je vais (le) faire\" — engagement du locuteur (décision immédiate)","pt-BR":"\"eu vou fazer / prometo\" — compromisso do falante no momento","th":"\"ผมจะ ... นะ / สัญญา\" — ตกลงในขณะนั้น (บุรุษที่ 1)","id":"\"saya akan ... / janji\" — keputusan saat itu juga (orang pertama)","vi":"\"tôi sẽ ... / tôi hứa\" — cam kết tức thì (ngôi 1)","ja":"「〜しますね / 〜しますから」— その場の意志・約束(一人称)"}'::jsonb, '제가 할게요.', '{"en":"I’ll do it.","es":"Yo lo haré.","fr":"Je m’en occupe.","pt-BR":"Eu faço.","th":"ผมจะทำเองครับ","id":"Saya yang akan melakukannya.","vi":"Để tôi làm.","ja":"私がしますね。"}'::jsonb, 'topik-2'),
('-(으)ㄹ까요?', '{"en":"\"shall we ...? / I wonder if ...\" — suggestion or self-question","es":"\"¿hacemos…? / ¿será que…?\" — sugerencia o duda interior","fr":"«on ...? / je me demande si ...» — proposition ou interrogation","pt-BR":"\"vamos ...? / será que ...?\" — sugestão ou indagação","th":"\"... กันไหม? / สงสัยว่า ...\" — ชวน หรือ คิดในใจ","id":"\"... yuk? / kira-kira ...?\" — ajakan atau renungan","vi":"\"... nhé? / liệu ...?\" — đề nghị hoặc tự hỏi","ja":"「〜ましょうか / 〜でしょうか」— 提案・推量"}'::jsonb, '같이 점심을 먹을까요?', '{"en":"Shall we have lunch together?","es":"¿Comemos juntos el almuerzo?","fr":"On déjeune ensemble ?","pt-BR":"Vamos almoçar juntos?","th":"ทานข้าวเที่ยงด้วยกันไหม","id":"Makan siang bareng yuk?","vi":"Mình ăn trưa cùng nhau nhé?","ja":"一緒に昼ご飯を食べましょうか？"}'::jsonb, 'topik-2'),
('-(으)려고', '{"en":"\"in order to / with the intention of\" — same subject, no imperative in 2nd clause","es":"\"con la intención de / para\" — mismo sujeto, sin imperativo en la 2ª cláusula","fr":"«avec l’intention de / pour» — même sujet, pas d’impératif en 2ᵈᵉ","pt-BR":"\"com a intenção de / para\" — mesmo sujeito, sem imperativo na 2ª","th":"\"ตั้งใจจะ / เพื่อ ...\" — ผู้กระทำเดียวกัน, ห้ามคำสั่งในข้อหลัง","id":"\"berniat untuk / supaya\" — subjek sama, tanpa imperatif di klausa 2","vi":"\"với ý định / để ...\" — cùng chủ ngữ, không mệnh lệnh ở vế 2","ja":"「〜しようと / 〜するために」— 同主語、後節に命令不可"}'::jsonb, '한국어를 배우려고 학원에 다녀요.', '{"en":"I go to a hagwon in order to learn Korean.","es":"Voy a la academia para aprender coreano.","fr":"Je vais à l’académie pour apprendre le coréen.","pt-BR":"Vou a um curso particular para aprender coreano.","th":"ฉันไปสถาบันสอนพิเศษเพื่อเรียนภาษาเกาหลี","id":"Saya pergi ke kursus untuk belajar bahasa Korea.","vi":"Tôi đến trung tâm để học tiếng Hàn.","ja":"韓国語を学ぼうと塾に通っています。"}'::jsonb, 'topik-2'),
('-아/어 보다', '{"en":"\"try to / give it a go / have the experience of\"","es":"\"intentar / probar a / haber probado a\"","fr":"«essayer de / faire pour voir»","pt-BR":"\"tentar / experimentar / já ter feito\"","th":"\"ลอง ...\" — ลองทำดู / มีประสบการณ์","id":"\"coba / pernah mencoba\"","vi":"\"thử / đã từng thử\"","ja":"「〜てみる」— 試行・経験"}'::jsonb, '이 음식을 먹어 봤어요?', '{"en":"Have you tried this food?","es":"¿Has probado esta comida?","fr":"As-tu déjà goûté ce plat ?","pt-BR":"Você já experimentou essa comida?","th":"เคยลองกินอาหารนี้ไหม","id":"Pernah mencoba makanan ini?","vi":"Bạn đã thử món này chưa?","ja":"この料理を食べてみましたか？"}'::jsonb, 'topik-2'),
('-아/어 주다', '{"en":"\"do something for someone\" — favor/service; -아/어 주세요 = \"please ...\"","es":"\"hacer algo para alguien\" — favor; -아/어 주세요 = \"por favor...\"","fr":"«faire qch pour qqn» — service; -아/어 주세요 = «s’il te plaît…»","pt-BR":"\"fazer algo por alguém\" — favor; -아/어 주세요 = \"por favor...\"","th":"\"ทำให้ใคร / ช่วย ...\" — -아/어 주세요 = ขอความช่วยเหลือ","id":"\"melakukan untuk seseorang\" — -아/어 주세요 = \"tolong ...\"","vi":"\"làm giúp ai\" — -아/어 주세요 = \"làm ơn ...\"","ja":"「〜てあげる / 〜てくれる」— 〜아/어 주세요 で依頼"}'::jsonb, '사진을 찍어 주세요.', '{"en":"Please take a picture (for me/us).","es":"Por favor, sácanos una foto.","fr":"Prends-nous une photo, s’il te plaît.","pt-BR":"Tira uma foto, por favor.","th":"ช่วยถ่ายรูปให้หน่อยได้ไหม","id":"Tolong fotokan kami.","vi":"Vui lòng chụp ảnh giúp.","ja":"写真を撮ってください。"}'::jsonb, 'topik-2'),
('-아/어 버리다', '{"en":"definitive completion with emotional flavor (relief or regret)","es":"completitud definitiva con matiz emocional (alivio o lamento)","fr":"achèvement définitif avec nuance émotionnelle (soulagement / regret)","pt-BR":"conclusão definitiva com emoção (alívio ou pesar)","th":"ทำเสร็จเด็ดขาด — โล่งใจ / เสียดาย","id":"penyelesaian tuntas dengan emosi (lega / menyesal)","vi":"hoàn thành dứt khoát kèm cảm xúc (nhẹ nhõm / tiếc nuối)","ja":"「〜てしまう」— 完了+感情(安堵/後悔)"}'::jsonb, '숙제를 다 해 버렸어요.', '{"en":"I finished all the homework (at last!).","es":"Ya terminé toda la tarea (¡por fin!).","fr":"J’ai terminé tous les devoirs (enfin !).","pt-BR":"Terminei toda a lição (até que enfim!).","th":"ทำการบ้านเสร็จหมดแล้ว!","id":"Akhirnya semua PR selesai!","vi":"Tôi đã làm xong hết bài tập rồi!","ja":"宿題を全部やってしまいました。"}'::jsonb, 'topik-2'),
('-아/어 놓다 / -아/어 두다', '{"en":"\"do and leave (prepared for later)\" — 놓다 and 두다 are near-synonyms","es":"\"hacer y dejar (preparado para luego)\" — 놓다 y 두다 son casi sinónimos","fr":"«faire et laisser (préparé pour plus tard)» — 놓다 / 두다 quasi-synonymes","pt-BR":"\"deixar feito / preparado\" — 놓다 e 두다 são quase sinônimos","th":"\"ทำเตรียมไว้\" — 놓다 / 두다 ใกล้ความหมาย","id":"\"melakukan dan menyiapkan untuk nanti\" — 놓다 dan 두다 nyaris sama","vi":"\"làm sẵn / để dành\" — 놓다 và 두다 gần đồng nghĩa","ja":"「〜ておく」(놓다/두다 ほぼ同義)"}'::jsonb, '미리 예약해 뒀어요.', '{"en":"I made the reservation in advance.","es":"Hice la reserva con antelación.","fr":"J’ai fait la réservation à l’avance.","pt-BR":"Já fiz a reserva com antecedência.","th":"จองเอาไว้ล่วงหน้าแล้ว","id":"Saya sudah memesan lebih dulu.","vi":"Tôi đã đặt trước rồi.","ja":"前もって予約しておきました。"}'::jsonb, 'topik-2'),
('-(으)니까', '{"en":"\"because / so\" — allows imperative or past on 1st clause (cf. -아/어서)","es":"\"porque / ya que\" — admite imperativo y pasado en la 1ª cláusula (a diferencia de -아/어서)","fr":"«parce que / puisque» — accepte impératif et passé en 1ʳᵉ clause","pt-BR":"\"porque / já que\" — aceita imperativo e passado na 1ª cláusula","th":"\"เพราะว่า / เนื่องจาก\" — ใช้กับคำสั่งและอดีตในข้อแรกได้","id":"\"karena / sebab\" — boleh dengan imperatif/lampau di klausa 1","vi":"\"vì / bởi vì\" — cho phép mệnh lệnh / quá khứ ở vế 1","ja":"「〜から / 〜ので」— 命令・過去OK"}'::jsonb, '비가 오니까 우산을 가져가세요.', '{"en":"It’s raining, so take an umbrella.","es":"Como llueve, lleva paraguas.","fr":"Il pleut, alors prends un parapluie.","pt-BR":"Como está chovendo, leve um guarda-chuva.","th":"ฝนตก เอาร่มไปด้วยนะ","id":"Karena hujan, bawa payung ya.","vi":"Vì trời mưa, hãy mang ô đi.","ja":"雨が降っているから傘を持って行ってください。"}'::jsonb, 'topik-2'),
('때문에 / 기 때문에', '{"en":"\"because of / due to\" — formal; N + 때문에 or V + 기 때문에","es":"\"a causa de / debido a\" — formal; N + 때문에 o V + 기 때문에","fr":"«à cause de / en raison de» — formel; N + 때문에 ou V + 기 때문에","pt-BR":"\"por causa de / devido a\" — formal; N + 때문에 ou V + 기 때문에","th":"\"เพราะ / เนื่องด้วย\" — ทางการ (N + 때문에 / V + 기 때문에)","id":"\"karena / akibat dari\" — formal (N + 때문에 / V + 기 때문에)","vi":"\"do / vì\" — trang trọng (N + 때문에 / V + 기 때문에)","ja":"「〜のため / 〜のせいで」(名詞 + 때문에 / 動詞 + 기 때문에)"}'::jsonb, '비 때문에 못 갔어요.', '{"en":"I couldn’t go because of the rain.","es":"No pude ir a causa de la lluvia.","fr":"Je n’ai pas pu y aller à cause de la pluie.","pt-BR":"Não pude ir por causa da chuva.","th":"ไปไม่ได้เพราะฝนตก","id":"Tidak bisa pergi karena hujan.","vi":"Tôi không thể đi vì trời mưa.","ja":"雨のせいで行けませんでした。"}'::jsonb, 'topik-2'),
('-거나', '{"en":"\"or\" — between verbs or adjectives (for nouns use (이)나)","es":"\"o\" — entre verbos o adjetivos (para sustantivos: (이)나)","fr":"«ou» — entre verbes ou adjectifs (pour les noms: (이)나)","pt-BR":"\"ou\" — entre verbos ou adjetivos (para substantivos: (이)나)","th":"\"หรือ\" — ระหว่างกริยา/คุณศัพท์ (สำหรับคำนามใช้ (이)나)","id":"\"atau\" — antar verba/adjektiva (untuk kata benda: (이)나)","vi":"\"hoặc / hay\" — giữa động từ/tính từ (với danh từ dùng (이)나)","ja":"動詞・形容詞間の「〜たり / または」(名詞は (이)나)"}'::jsonb, '주말에는 영화를 보거나 책을 읽어요.', '{"en":"On weekends I watch movies or read books.","es":"Los fines de semana veo películas o leo libros.","fr":"Le week-end, je regarde des films ou je lis.","pt-BR":"Nos fins de semana, vejo filmes ou leio.","th":"สุดสัปดาห์ฉันดูหนังหรืออ่านหนังสือ","id":"Akhir pekan saya nonton film atau baca buku.","vi":"Cuối tuần tôi xem phim hoặc đọc sách.","ja":"週末は映画を見たり本を読んだりします。"}'::jsonb, 'topik-2'),
('-처럼 / -같이', '{"en":"\"like / similar to\" — comparative particle; 같이 also means \"together\"","es":"\"como / igual que\" — partícula comparativa; 같이 también = \"juntos\"","fr":"«comme» — particule comparative; 같이 signifie aussi «ensemble»","pt-BR":"\"como / igual a\" — partícula comparativa; 같이 também = \"juntos\"","th":"\"เหมือน / เช่น\" — บอกความเหมือน; 같이 ยังแปลว่า \"ด้วยกัน\"","id":"\"seperti / sama seperti\" — partikel pembanding; 같이 juga = \"bersama\"","vi":"\"giống / như\" — tiểu từ so sánh; 같이 còn nghĩa là \"cùng\"","ja":"「〜のように / 〜みたいに」(같이 は「一緒に」の意味も)"}'::jsonb, '친구처럼 대해 줘요.', '{"en":"Treat me like a friend.","es":"Trátame como a un amigo.","fr":"Traite-moi comme un ami.","pt-BR":"Me trate como um amigo.","th":"ปฏิบัติต่อฉันเหมือนเป็นเพื่อน","id":"Perlakukan saya seperti teman.","vi":"Hãy đối xử với tôi như bạn bè.","ja":"友達のように接してください。"}'::jsonb, 'topik-2'),
('-보다', '{"en":"\"more than\" — comparative particle; often reinforced by 더 (\"more\")","es":"\"más que\" — partícula comparativa; suele reforzarse con 더 (\"más\")","fr":"«plus que» — particule comparative, souvent renforcée par 더","pt-BR":"\"mais que\" — partícula comparativa, geralmente com 더 (\"mais\")","th":"\"มากกว่า\" — เปรียบเทียบ; มักเสริมด้วย 더 (\"ยิ่ง / มาก\")","id":"\"lebih ... dari\" — pembanding; sering ditegaskan 더 (\"lebih\")","vi":"\"hơn\" — so sánh; thường thêm 더 (\"hơn nữa\")","ja":"「〜より」— 比較。 더 と組み合わさることが多い"}'::jsonb, '한국어는 일본어보다 어려워요.', '{"en":"Korean is harder than Japanese.","es":"El coreano es más difícil que el japonés.","fr":"Le coréen est plus difficile que le japonais.","pt-BR":"O coreano é mais difícil que o japonês.","th":"ภาษาเกาหลียากกว่าภาษาญี่ปุ่น","id":"Bahasa Korea lebih sulit daripada bahasa Jepang.","vi":"Tiếng Hàn khó hơn tiếng Nhật.","ja":"韓国語は日本語より難しいです。"}'::jsonb, 'topik-2'),
('-(으)ㄴ/는지', '{"en":"embeds a question — \"whether / when / what / where...\" in subordinate clauses","es":"pregunta indirecta — \"si / cuándo / qué / dónde...\" en oraciones subordinadas","fr":"question indirecte — «si / quand / quoi / où» dans une subordonnée","pt-BR":"pergunta indireta — \"se / quando / o que / onde\" em orações subordinadas","th":"คำถามอ้อม — \"ว่า/อย่างไร/ที่ไหน ...\" ในประโยคย่อย","id":"pertanyaan tak langsung — \"apakah / kapan / apa / di mana ...\" di anak kalimat","vi":"câu hỏi gián tiếp — \"liệu / khi nào / cái gì / ở đâu ...\" trong mệnh đề phụ","ja":"間接疑問「〜のか / 〜かどうか」"}'::jsonb, '어디에 사는지 알아요?', '{"en":"Do you know where they live?","es":"¿Sabes dónde vive?","fr":"Sais-tu où il/elle habite ?","pt-BR":"Você sabe onde mora?","th":"รู้ไหมว่าเขาอยู่ที่ไหน","id":"Tahu di mana dia tinggal?","vi":"Bạn có biết người ấy sống ở đâu không?","ja":"どこに住んでいるか知っていますか？"}'::jsonb, 'topik-2'),
('-(으)ㄴ/는데요', '{"en":"\"the thing is...\" (polite) — softens, invites listener’s reaction","es":"\"es que...\" (educado) — suaviza la afirmación; invita a reaccionar","fr":"«il faut savoir que…» (poli) — adoucit, invite à réagir","pt-BR":"\"acontece que...\" (educado) — suaviza e convida à reação","th":"\"คือว่า ...\" (สุภาพ) — เกริ่นให้ผู้ฟังตอบ","id":"\"jadi begini...\" (sopan) — pelunak, mengundang reaksi","vi":"\"chuyện là...\" (lịch sự) — làm dịu câu nói","ja":"「〜なんですけど」— 丁寧な前置き"}'::jsonb, '좀 비싼데요...', '{"en":"It’s a bit pricey, though...","es":"Es un poco caro, la verdad...","fr":"C’est un peu cher, en fait…","pt-BR":"É um pouco caro, na verdade...","th":"แพงไปหน่อยน่ะ ...","id":"Agak mahal sih...","vi":"Hơi đắt đấy...","ja":"ちょっと高いんですけど…"}'::jsonb, 'topik-2'),
('얼마나', '{"en":"\"how much / how + adjective\" — asks degree or amount","es":"\"cuánto / qué tan\" — pregunta por grado o cantidad","fr":"«combien / à quel point» — degré ou quantité","pt-BR":"\"quanto / quão\" — pergunta por grau ou quantidade","th":"\"แค่ไหน / นานเท่าไหร่\" — ถามระดับหรือปริมาณ","id":"\"seberapa / berapa banyak\" — menanyakan kadar atau jumlah","vi":"\"bao nhiêu / đến mức nào\" — hỏi mức độ hoặc số lượng","ja":"「どのくらい / どれだけ」"}'::jsonb, '여기서 학교까지 얼마나 걸려요?', '{"en":"How long does it take from here to school?","es":"¿Cuánto se tarda de aquí hasta la escuela?","fr":"Combien de temps faut-il d’ici à l’école ?","pt-BR":"Quanto leva daqui até a escola?","th":"จากที่นี่ไปโรงเรียนใช้เวลาเท่าไหร่","id":"Berapa lama dari sini ke sekolah?","vi":"Từ đây đến trường mất bao lâu?","ja":"ここから学校までどのくらいかかりますか？"}'::jsonb, 'topik-2'),
('에 대해(서)', '{"en":"\"about / regarding / on the topic of\" — also 에 대한 + N","es":"\"sobre / acerca de / respecto a\" — también 에 대한 + N","fr":"«à propos de / concernant» — aussi 에 대한 + N","pt-BR":"\"sobre / a respeito de\" — também 에 대한 + N","th":"\"เกี่ยวกับ\" — รูปขยายคำนาม 에 대한 + N","id":"\"tentang / mengenai\" — bentuk pengubah: 에 대한 + N","vi":"\"về / liên quan đến\" — bổ ngữ danh từ 에 대한 + N","ja":"「〜について」(連体形: 에 대한 + N)"}'::jsonb, '한국 문화에 대해서 이야기해요.', '{"en":"We’re talking about Korean culture.","es":"Hablamos sobre la cultura coreana.","fr":"On parle de la culture coréenne.","pt-BR":"Estamos falando sobre cultura coreana.","th":"พวกเราคุยกันเรื่องวัฒนธรรมเกาหลี","id":"Kami berbicara tentang budaya Korea.","vi":"Chúng tôi nói chuyện về văn hóa Hàn Quốc.","ja":"韓国の文化について話します。"}'::jsonb, 'topik-2'),
('-(으)ㄹ까 봐', '{"en":"\"for fear that / in case ...\" — precaution against unwanted outcome","es":"\"por miedo a que / por si acaso ...\" — precaución ante algo no deseado","fr":"«de peur que / au cas où» — précaution contre quelque chose d’indésirable","pt-BR":"\"com medo de que / por via das dúvidas\" — precaução contra algo ruim","th":"\"กลัวว่าจะ ...\" — เพื่อป้องกันสิ่งไม่ดี","id":"\"khawatir ... / kalau-kalau ...\" — pencegahan","vi":"\"sợ rằng / phòng khi ...\" — đề phòng","ja":"「〜かと思って / 〜と心配して」"}'::jsonb, '비가 올까 봐 우산을 가져왔어요.', '{"en":"I brought an umbrella in case it rained.","es":"Traje el paraguas por si llovía.","fr":"J’ai apporté un parapluie au cas où il pleuvrait.","pt-BR":"Trouxe um guarda-chuva, com medo de chover.","th":"เอาร่มมาเผื่อฝนตก","id":"Saya bawa payung, takut nanti hujan.","vi":"Tôi mang ô vì sợ trời mưa.","ja":"雨が降るかと思って傘を持ってきました。"}'::jsonb, 'topik-2'),
('-더라도', '{"en":"\"even if / even in the case that ...\" — stronger than -아/어도; hypothetical","es":"\"aunque / incluso si (hipotético)\" — más fuerte que -아/어도","fr":"«même si / même au cas où» — plus fort que -아/어도","pt-BR":"\"mesmo que / mesmo se\" — mais forte que -아/어도","th":"\"แม้ว่า / แม้จะ ...\" — เน้นกว่า -아/어도","id":"\"meskipun / bahkan jika\" — lebih kuat dari -아/어도","vi":"\"dù cho / cho dù\" — mạnh hơn -아/어도","ja":"「〜たとしても / 〜であっても」"}'::jsonb, '시간이 없더라도 밥은 먹어야 해요.', '{"en":"Even if you have no time, you have to eat.","es":"Aunque no tengas tiempo, tienes que comer.","fr":"Même si tu n’as pas le temps, tu dois manger.","pt-BR":"Mesmo que não tenha tempo, precisa comer.","th":"แม้ไม่มีเวลาก็ต้องกินข้าว","id":"Meskipun tidak ada waktu, harus tetap makan.","vi":"Dù không có thời gian thì cũng phải ăn.","ja":"時間がなくてもご飯は食べなければなりません。"}'::jsonb, 'topik-2'),
('-(으)ㄹ지도 모르다', '{"en":"\"might / maybe / it’s possible that ...\" — uncertain possibility","es":"\"puede que / quizás / a lo mejor ...\" — posibilidad incierta","fr":"«il se peut que / peut-être» — possibilité incertaine","pt-BR":"\"pode ser que / talvez ...\" — possibilidade incerta","th":"\"อาจจะ / อาจเป็นไปได้ว่า ...\" — ความเป็นไปได้ที่ไม่แน่ใจ","id":"\"mungkin / siapa tahu ...\" — kemungkinan tidak pasti","vi":"\"có thể / biết đâu ...\" — khả năng không chắc","ja":"「〜かもしれない」"}'::jsonb, '내일 비가 올지도 몰라요.', '{"en":"It might rain tomorrow.","es":"Puede que mañana llueva.","fr":"Il se peut qu’il pleuve demain.","pt-BR":"Pode ser que chova amanhã.","th":"พรุ่งนี้อาจจะฝนตก","id":"Mungkin besok akan hujan.","vi":"Ngày mai có thể trời mưa.","ja":"明日雨が降るかもしれません。"}'::jsonb, 'topik-2'),
('-잖아요', '{"en":"\"as you know / it’s that ...\" — recalls shared info, mild reproach","es":"\"es que / como sabes ...\" — alude a información compartida; leve reproche","fr":"«tu vois bien que / tu sais que ...» — info partagée, léger reproche","pt-BR":"\"é que / como você sabe ...\" — apela a info já compartilhada","th":"\"ก็ ... ไง\" — เตือนสิ่งที่ทั้งคู่รู้ดี (ติเตียนเล็กน้อย)","id":"\"kan / bukannya ...\" — mengingatkan info yang sudah diketahui","vi":"\"đấy thôi / mà ...\" — gợi nhớ điều cả hai đã biết","ja":"「〜じゃないですか / 〜でしょ」— 既知情報の確認・軽い咎め"}'::jsonb, '저 그 사람 싫어하잖아요.', '{"en":"I don’t like that person, you know.","es":"Es que ya sabes que esa persona no me gusta.","fr":"Tu sais bien que je n’aime pas cette personne.","pt-BR":"É que eu não gosto dessa pessoa, sabe.","th":"ก็รู้อยู่แล้วว่าฉันไม่ชอบคนนั้น","id":"Saya kan tidak suka orang itu.","vi":"Tôi không thích người đó mà, anh biết rồi đấy.","ja":"私あの人が嫌いじゃないですか。"}'::jsonb, 'topik-2'),
('-군요 / -구나', '{"en":"\"ah, I see ...\" — quiet realization (군요 polite / 구나 casual)","es":"\"ah, ya veo ...\" — descubrimiento tranquilo (군요 educado / 구나 informal)","fr":"«ah, je vois» — réalisation calme (군요 poli / 구나 familier)","pt-BR":"\"ah, entendi ...\" — percepção tranquila (군요 educado / 구나 informal)","th":"\"อ๋อ, อย่างนี้นี่เอง\" — เข้าใจอย่างสงบ (군요 สุภาพ / 구나 กันเอง)","id":"\"oh begitu...\" — penyadaran tenang (군요 sopan / 구나 santai)","vi":"\"à ra vậy ...\" — phát hiện êm dịu (군요 lịch sự / 구나 thân mật)","ja":"「〜ですね / 〜なんですね」— 落ち着いた気づき(군요 丁寧 / 구나 タメ)"}'::jsonb, '이 식당이 유명하군요.', '{"en":"Ah, this restaurant is famous!","es":"¡Ah, este restaurante es famoso!","fr":"Ah, ce restaurant est célèbre !","pt-BR":"Ah, esse restaurante é famoso!","th":"อ๋อ ร้านอาหารร้านนี้ดังนี่เอง","id":"Oh, ternyata restoran ini terkenal.","vi":"À, nhà hàng này nổi tiếng đấy.","ja":"この食堂は有名なんですね。"}'::jsonb, 'topik-2'),
('-더라고요', '{"en":"\"I noticed / it turned out ...\" — recounting a direct past observation","es":"\"resultó que / me di cuenta de que ...\" — observación directa pasada","fr":"«il s’est avéré que / j’ai constaté que» — observation directe passée","pt-BR":"\"acabou que / percebi que ...\" — observação direta no passado","th":"\"ปรากฏว่า / ฉันสังเกตเห็นว่า ...\" — เล่าจากที่ได้เห็นเอง","id":"\"ternyata / saya menyadari ...\" — pengamatan langsung lampau","vi":"\"hóa ra / tôi nhận ra rằng ...\" — quan sát trực tiếp trong quá khứ","ja":"「〜でしたよ / 〜していました」— 直接観察の報告"}'::jsonb, '그 식당 음식이 정말 맛있더라고요.', '{"en":"It turned out the food at that restaurant was really good.","es":"Resulta que la comida de ese restaurante estaba muy rica.","fr":"Il s’est avéré que la nourriture de ce restaurant était excellente.","pt-BR":"Acabou que a comida daquele restaurante era muito boa.","th":"ปรากฏว่าอาหารร้านนั้นอร่อยจริง ๆ","id":"Ternyata makanan restoran itu enak sekali.","vi":"Hóa ra món ăn nhà hàng đó ngon thật.","ja":"あのお店の料理、本当に美味しかったですよ。"}'::jsonb, 'topik-2'),
('-(으)ㄹ 만큼', '{"en":"\"as much as / to the extent that\" — proportion or sufficiency","es":"\"tanto como / lo suficiente como para\" — proporción o suficiencia","fr":"«autant que / au point que» — proportion ou suffisance","pt-BR":"\"tanto quanto / o suficiente para\" — proporção ou suficiência","th":"\"เท่าที่ / มากพอที่จะ\" — สัดส่วนหรือความเพียงพอ","id":"\"sebanyak / cukup untuk\" — proporsi atau kecukupan","vi":"\"đến mức / vừa đủ\" — tỷ lệ hoặc đủ","ja":"「〜ほど / 〜くらい」— 程度・十分さ"}'::jsonb, '먹을 만큼 드세요.', '{"en":"Take as much as you’ll eat.","es":"Sírvase lo que vaya a comer.","fr":"Sers-toi autant que tu vas en manger.","pt-BR":"Sirva-se quanto for comer.","th":"ตักไปเท่าที่จะกินไหว","id":"Ambil sebanyak yang akan dimakan.","vi":"Lấy đủ phần bạn ăn.","ja":"食べる分だけ取ってください。"}'::jsonb, 'topik-2'),
('-기 쉽다/어렵다', '{"en":"\"is easy / hard to ...\" — describes an action’s difficulty","es":"\"es fácil / difícil + infinitivo\" — describe la dificultad de una acción","fr":"«il est facile / difficile de» — décrit la difficulté d’une action","pt-BR":"\"é fácil / difícil de ...\" — descreve a dificuldade de uma ação","th":"\"ทำ ... ได้ง่าย / ยาก\"","id":"\"mudah / sulit untuk ...\"","vi":"\"dễ / khó để ...\"","ja":"「〜やすい / 〜にくい」"}'::jsonb, '이 단어는 잊어버리기 쉬워요.', '{"en":"This word is easy to forget.","es":"Esta palabra es fácil de olvidar.","fr":"Ce mot est facile à oublier.","pt-BR":"Essa palavra é fácil de esquecer.","th":"คำนี้ลืมง่าย","id":"Kata ini mudah dilupakan.","vi":"Từ này dễ quên.","ja":"この単語は忘れやすいです。"}'::jsonb, 'topik-2'),
('피동사 (이/히/리/기)', '{"en":"morphological passive — suffix 이/히/리/기 turns active into passive","es":"pasiva morfológica — sufijos 이/히/리/기 transforman activo a pasivo","fr":"passif morphologique — suffixes 이/히/리/기 (boire→être bu)","pt-BR":"voz passiva morfológica — sufixos 이/히/리/기","th":"รูปกริยาถูกกระทำ — เติม 이/히/리/기 ที่กริยาทำ","id":"pasif morfologis — sufiks 이/히/리/기 mengubah aktif ke pasif","vi":"thể bị động hình thái — hậu tố 이/히/리/기","ja":"形態的受動 (이/히/리/기) — 보이다/들리다/잡히다…"}'::jsonb, '저기서 바다가 보여요.', '{"en":"You can see the sea from there.","es":"Desde allí se ve el mar.","fr":"D’ici, on voit la mer.","pt-BR":"Dali dá para ver o mar.","th":"จากตรงนั้นมองเห็นทะเล","id":"Dari sana lautnya kelihatan.","vi":"Từ đó nhìn thấy biển.","ja":"あそこから海が見えます。"}'::jsonb, 'topik-2'),
('아무 N(이)나 / 아무 N도', '{"en":"\"any N (positive)\" / \"no N at all (with negation)\"","es":"\"cualquier N\" (positivo) / \"ningún N\" (con negación)","fr":"«n’importe quel N» (positif) / «aucun N» (avec négation)","pt-BR":"\"qualquer N\" (positivo) / \"nenhum N\" (com negação)","th":"\"N อะไรก็ได้\" (บวก) / \"ไม่มี N เลย\" (กับปฏิเสธ)","id":"\"N apa saja\" (positif) / \"tidak ada N pun\" (dengan negasi)","vi":"\"N nào cũng\" (khẳng định) / \"không N nào\" (phủ định)","ja":"肯定: 何/誰/どこでも / 否定: 何も/誰も/どこも"}'::jsonb, '아무 것이나 드세요.', '{"en":"Take anything, whatever you’d like.","es":"Tome cualquier cosa, lo que quiera.","fr":"Prends ce que tu veux.","pt-BR":"Pegue qualquer coisa, o que quiser.","th":"หยิบอะไรก็ได้","id":"Ambil saja apa pun, sesuka Anda.","vi":"Lấy gì cũng được, tùy bạn.","ja":"何でも召し上がってください。"}'::jsonb, 'topik-2'),
('(이)라도', '{"en":"\"at least / even if just ...\" — accept a less-than-ideal option","es":"\"aunque solo sea / al menos ...\" — aceptar una opción no ideal","fr":"«au moins / ne serait-ce que» — accepter une option non idéale","pt-BR":"\"pelo menos / mesmo que seja ...\" — aceitar opção não ideal","th":"\"อย่างน้อย ... ก็ ...\" — รับตัวเลือกที่ไม่สมบูรณ์","id":"\"setidaknya / kalaupun cuma ...\" — menerima opsi tak ideal","vi":"\"ít nhất / dù chỉ ...\" — chấp nhận lựa chọn không lý tưởng","ja":"「〜でも (せめて)」— 控えめな提案/受容"}'::jsonb, '물이라도 마실래요?', '{"en":"Would you like at least some water?","es":"¿Quieres al menos tomar agua?","fr":"Tu veux au moins boire un peu d’eau ?","pt-BR":"Quer pelo menos beber água?","th":"จะดื่มน้ำเปล่าก็ยังดีนะ","id":"Mau minum air saja kalau begitu?","vi":"Bạn có muốn ít nhất uống chút nước không?","ja":"お水でも飲みますか？"}'::jsonb, 'topik-2'),
('-다고요? / -(이)라고요?', '{"en":"repeats what was just heard, with surprise or for confirmation","es":"repite lo que se acaba de escuchar, con sorpresa o para confirmar","fr":"reprend ce qui vient d’être dit, par surprise ou pour confirmer","pt-BR":"repete o que acabou de ouvir, com surpresa ou para confirmar","th":"ทวนคำที่เพิ่งได้ยิน ด้วยความแปลกใจ / ขอยืนยัน","id":"mengulang yang baru didengar, dengan kaget atau minta konfirmasi","vi":"lặp lại điều vừa nghe, ngạc nhiên hoặc xác nhận","ja":"「〜って言いましたか？」— 確認・驚きで聞き返す"}'::jsonb, '내일 시험이 있다고요?', '{"en":"There’s an exam tomorrow, you say?","es":"¿Que mañana hay examen?","fr":"Tu dis qu’il y a un examen demain ?","pt-BR":"Você disse que tem prova amanhã?","th":"พรุ่งนี้มีสอบเหรอ","id":"Katanya besok ada ujian?","vi":"Bạn nói ngày mai có thi à?","ja":"明日試験があるんですって？"}'::jsonb, 'topik-2'),
('이/가 되다', '{"en":"\"to become (a noun)\" — change of state / role","es":"\"convertirse en / llegar a ser\" — cambio de estado o rol","fr":"«devenir» — changement d’état ou de rôle","pt-BR":"\"tornar-se / virar\" — mudança de estado ou papel","th":"\"กลายเป็น ...\" — เปลี่ยนสภาพหรือบทบาท","id":"\"menjadi ...\" — perubahan keadaan / peran","vi":"\"trở thành ...\" — đổi trạng thái / vai trò","ja":"「〜になる」"}'::jsonb, '저는 의사가 되고 싶어요.', '{"en":"I want to become a doctor.","es":"Quiero convertirme en médico.","fr":"Je veux devenir médecin.","pt-BR":"Eu quero ser médico.","th":"ฉันอยากเป็นหมอ","id":"Saya ingin menjadi dokter.","vi":"Tôi muốn trở thành bác sĩ.","ja":"私は医者になりたいです。"}'::jsonb, 'topik-2'),
('아직 / 벌써 / 이미', '{"en":"\"still / already (sooner than expected) / already (neutral fact)\"","es":"\"todavía / ya (más pronto de lo esperado) / ya (hecho neutral)\"","fr":"«encore / déjà (plus tôt que prévu) / déjà (fait constaté)»","pt-BR":"\"ainda / já (mais cedo que o esperado) / já (fato consumado)\"","th":"\"ยัง / เร็วจัง / เสร็จเรียบร้อยแล้ว\"","id":"\"masih / sudah (lebih cepat dari kira) / sudah (fakta)\"","vi":"\"vẫn / đã (sớm hơn dự kiến) / đã (sự thật rồi)\"","ja":"「まだ / もう(意外な早さ) / すでに(既成事実)」"}'::jsonb, '아직 숙제를 안 했어요.', '{"en":"I haven’t done the homework yet.","es":"Todavía no he hecho la tarea.","fr":"Je n’ai pas encore fait mes devoirs.","pt-BR":"Ainda não fiz a lição.","th":"ฉันยังไม่ได้ทำการบ้านเลย","id":"Saya belum mengerjakan PR.","vi":"Tôi vẫn chưa làm bài tập.","ja":"まだ宿題をしていません。"}'::jsonb, 'topik-2'),
('-아/어 죽겠다', '{"en":"\"I’m dying of ...\" — colloquial hyperbole for an extreme feeling","es":"\"me muero de ...\" — hipérbole coloquial para sensación extrema","fr":"«je meurs de ...» — hyperbole familière","pt-BR":"\"estou morrendo de ...\" — hipérbole coloquial","th":"\"... จะตายอยู่แล้ว\" — สำนวนกึ่งเล่น กึ่งจริง","id":"\"saya hampir mati karena ...\" — hiperbol sehari-hari","vi":"\"chết mất vì ...\" — nói cường điệu thân mật","ja":"「〜て死にそうだ」— 口語的誇張"}'::jsonb, '배고파 죽겠어요.', '{"en":"I’m starving (lit. dying of hunger).","es":"Me muero de hambre.","fr":"Je meurs de faim.","pt-BR":"Estou morrendo de fome.","th":"หิวจะตายแล้ว","id":"Saya lapar setengah mati.","vi":"Tôi đói chết mất.","ja":"お腹が空いて死にそうです。"}'::jsonb, 'topik-2'),
('-아/어 가지고', '{"en":"\"and so / because ...\" — colloquial connector, often contracted to -아/어 갖고; spoken-only alternative to -아/어서","es":"\"y entonces / porque ...\" — conector coloquial, se contrae a -아/어 갖고; alternativa hablada de -아/어서","fr":"«et donc / parce que ...» — connecteur familier, contracté en -아/어 갖고","pt-BR":"\"e então / porque ...\" — conector falado, contrai para -아/어 갖고","th":"\"... แล้วก็ ... / เพราะ ... (พูด)\"","id":"\"jadi / karena ... (lisan)\" — sering disingkat -아/어 갖고","vi":"\"do đó / vì ... (nói)\" — rút gọn -아/어 갖고","ja":"「〜して(口語) / 〜なので」— 縮約 -아/어 갖고"}'::jsonb, '비가 와 가지고 못 갔어요.', '{"en":"It rained, so I couldn’t go.","es":"Como llovió, no pude ir.","fr":"Comme il pleuvait, je n’ai pas pu y aller.","pt-BR":"Choveu, então não pude ir.","th":"ฝนตกเลยไปไม่ได้","id":"Gara-gara hujan, saya tidak bisa pergi.","vi":"Vì trời mưa nên tôi không đi được.","ja":"雨が降って行けませんでした。"}'::jsonb, 'topik-2'),
('-다(가) 말다', '{"en":"\"start ...ing and then leave it\" — partial action abandoned midway","es":"\"empezar a ... y dejarlo a medias\" — acción parcial abandonada","fr":"«commencer à ... puis laisser tomber» — action abandonnée","pt-BR":"\"começar a ... e largar pela metade\" — ação abandonada","th":"\"ทำ ... ค้างไว้ / เลิกกลางทาง\"","id":"\"melakukan ... lalu meninggalkannya di tengah jalan\"","vi":"\"đang ... thì bỏ dở\"","ja":"「〜しかけてやめる」— 中途で放棄"}'::jsonb, '책을 읽다가 말았어요.', '{"en":"I started reading the book but left it halfway.","es":"Empecé a leer el libro pero lo dejé a medias.","fr":"J’ai commencé à lire le livre mais je l’ai laissé tomber.","pt-BR":"Comecei a ler o livro, mas larguei pela metade.","th":"อ่านหนังสือค้างเอาไว้","id":"Saya mulai membaca buku tapi tidak selesai.","vi":"Tôi đọc sách được nửa chừng rồi bỏ.","ja":"本を読みかけてやめました。"}'::jsonb, 'topik-2'),
('-게 되다', '{"en":"\"come to / end up (doing)\" — change brought about by circumstance, not will","es":"\"llegar a / acabar (haciendo)\" — cambio por circunstancias, no por voluntad","fr":"«finir par / en venir à» — changement par les circonstances, non choisi","pt-BR":"\"acabar (fazendo) / vir a\" — mudança por circunstâncias, sem intenção","th":"\"กลายเป็นว่า / สุดท้ายก็ ...\" — เปลี่ยนเพราะสถานการณ์ ไม่ใช่เจตนา","id":"\"akhirnya / jadinya ...\" — perubahan karena keadaan, bukan kemauan","vi":"\"rốt cuộc / cuối cùng (làm) ...\" — đổi do hoàn cảnh, không do ý chí","ja":"「〜ことになる / 〜するようになる」— 状況による変化"}'::jsonb, '이 회사에서 일하게 되었어요.', '{"en":"I ended up working at this company.","es":"Acabé trabajando en esta empresa.","fr":"J’ai fini par travailler dans cette entreprise.","pt-BR":"Acabei trabalhando nesta empresa.","th":"สุดท้ายฉันก็ได้ทำงานที่บริษัทนี้","id":"Akhirnya saya jadi bekerja di perusahaan ini.","vi":"Cuối cùng tôi đã làm việc ở công ty này.","ja":"この会社で働くことになりました。"}'::jsonb, 'topik-3'),
('-아/어지다', '{"en":"\"become / get\" — gradual change of state with adjectives","es":"\"ponerse / volverse / hacerse\" — cambio gradual de estado con adjetivos","fr":"«devenir / se faire» — changement graduel d’état (adj.)","pt-BR":"\"ficar / tornar-se\" — mudança gradual de estado (adj.)","th":"\"กลายเป็น ... / ค่อย ๆ ...\" — เปลี่ยนสภาพทีละน้อย (กับคำคุณศัพท์)","id":"\"menjadi ...\" — perubahan keadaan bertahap (adjektiva)","vi":"\"trở nên ...\" — đổi trạng thái dần (tính từ)","ja":"「〜くなる / 〜になる」— 形容詞の段階的変化"}'::jsonb, '날씨가 따뜻해졌어요.', '{"en":"The weather has gotten warm.","es":"El tiempo se ha puesto cálido.","fr":"Le temps s’est radouci.","pt-BR":"O tempo ficou quente.","th":"อากาศอุ่นขึ้นแล้ว","id":"Cuacanya jadi hangat.","vi":"Trời đã trở nên ấm hơn.","ja":"天気が暖かくなりました。"}'::jsonb, 'topik-3'),
('-아/어 있다', '{"en":"resultant state — \"be + past participle\"; cf. -고 있다 (action in progress)","es":"estado resultante — \"estar + participio\"; cf. -고 있다 (acción en curso)","fr":"état résultant — «être + participe passé»; cf. -고 있다 (action en cours)","pt-BR":"estado resultante — \"estar + particípio\"; cf. -고 있다 (em progresso)","th":"สภาพคงค้างหลังจบการกระทำ — เทียบ -고 있다 (กำลังทำ)","id":"keadaan hasil — bedakan dengan -고 있다 (sedang berlangsung)","vi":"trạng thái kết quả — khác -고 있다 (đang tiến hành)","ja":"「〜ている」(結果状態) — 進行の -고 있다 と区別"}'::jsonb, '문이 열려 있어요.', '{"en":"The door is open.","es":"La puerta está abierta.","fr":"La porte est ouverte.","pt-BR":"A porta está aberta.","th":"ประตูเปิดอยู่","id":"Pintunya terbuka.","vi":"Cửa đang mở.","ja":"ドアが開いています。"}'::jsonb, 'topik-3'),
('-아/어 보이다', '{"en":"\"looks / appears + adj.\" — visual impression","es":"\"parecer / verse + adjetivo\" — impresión visual","fr":"«avoir l’air / sembler» — impression visuelle","pt-BR":"\"parecer / ter cara de\" — impressão visual","th":"\"ดู ...(เหมือน)\" — ความรู้สึกจากที่เห็น","id":"\"kelihatan / tampak ...\" — kesan visual","vi":"\"trông có vẻ ...\" — ấn tượng nhìn được","ja":"「〜く見える / 〜そうに見える」— 視覚的印象"}'::jsonb, '오늘 피곤해 보여요.', '{"en":"You look tired today.","es":"Hoy te ves cansado.","fr":"Tu as l’air fatigué aujourd’hui.","pt-BR":"Você parece cansado hoje.","th":"วันนี้ดูเหนื่อยนะ","id":"Hari ini kamu terlihat lelah.","vi":"Hôm nay trông bạn mệt mỏi.","ja":"今日は疲れて見えますね。"}'::jsonb, 'topik-3'),
('-기 때문에', '{"en":"\"because / due to\" — formal; allows imperative and past on 1st clause","es":"\"porque / debido a que\" — formal; admite imperativo y pasado en la 1ª cláusula","fr":"«parce que / du fait que» — formel; impératif et passé acceptés","pt-BR":"\"porque / pelo fato de que\" — formal; aceita imperativo e passado","th":"\"เพราะว่า\" — ทางการ; ใช้กับคำสั่ง/อดีตได้","id":"\"karena (formal)\" — boleh dengan imperatif dan lampau di klausa 1","vi":"\"vì / do (trang trọng)\" — cho phép mệnh lệnh/quá khứ ở vế 1","ja":"「〜ために / 〜ので(改まり)」— 命令・過去OK"}'::jsonb, '비가 오기 때문에 집에 있었어요.', '{"en":"I stayed home because it was raining.","es":"Porque estaba lloviendo, me quedé en casa.","fr":"Comme il pleuvait, je suis resté à la maison.","pt-BR":"Como estava chovendo, fiquei em casa.","th":"เพราะฝนตก เลยอยู่บ้าน","id":"Karena hujan, saya tinggal di rumah.","vi":"Vì trời mưa nên tôi ở nhà.","ja":"雨が降っていたため、家にいました。"}'::jsonb, 'topik-3'),
('-(으)면서', '{"en":"\"while / at the same time\" — same subject does two actions (cf. -는 동안)","es":"\"mientras (mismo sujeto)\" — dos acciones simultáneas del mismo sujeto","fr":"«tout en / pendant que» — même sujet pour les deux actions","pt-BR":"\"enquanto (mesmo sujeito)\" — duas ações simultâneas do mesmo sujeito","th":"\"ในขณะที่ ... ด้วย\" — ผู้กระทำเดียวกัน","id":"\"sambil (subjek sama)\" — dua aksi serentak satu subjek","vi":"\"vừa ... vừa ... (cùng chủ ngữ)\" — hai hành động đồng thời","ja":"「〜ながら」— 同主語の同時動作"}'::jsonb, '음악을 들으면서 공부해요.', '{"en":"I study while listening to music.","es":"Estudio mientras escucho música.","fr":"J’étudie tout en écoutant de la musique.","pt-BR":"Estudo enquanto escuto música.","th":"ฉันเรียนพร้อมกับฟังเพลง","id":"Saya belajar sambil mendengarkan musik.","vi":"Tôi vừa học vừa nghe nhạc.","ja":"音楽を聞きながら勉強します。"}'::jsonb, 'topik-3'),
('-(으)ㄹ 수밖에 없다', '{"en":"\"have no choice but to / inevitably\" — only one option remains","es":"\"no tener más remedio que / inevitablemente\" — sin otra opción","fr":"«n’avoir d’autre choix que de» — option unique","pt-BR":"\"não ter outra opção senão\" — não há alternativa","th":"\"ไม่มีทางเลือกอื่นนอกจาก ...\" — ทำได้แค่นี้","id":"\"tidak ada pilihan selain ...\" — terpaksa","vi":"\"không còn cách nào ngoài ...\"","ja":"「〜するしかない / 〜せざるを得ない」"}'::jsonb, '버스가 없어서 걸어갈 수밖에 없었어요.', '{"en":"There was no bus, so I had to walk.","es":"Como no había autobús, no tuve más remedio que ir caminando.","fr":"Il n’y avait pas de bus, j’ai dû y aller à pied.","pt-BR":"Como não tinha ônibus, não tive escolha senão ir a pé.","th":"ไม่มีรถบัส เลยต้องเดิน","id":"Karena tidak ada bus, terpaksa jalan kaki.","vi":"Không có xe buýt nên đành phải đi bộ.","ja":"バスがなかったので歩くしかありませんでした。"}'::jsonb, 'topik-3'),
('-기 위해(서) / -을/를 위해(서)', '{"en":"\"in order to / for the sake of\" — formal purpose; any verb (not only motion)","es":"\"para / con el fin de\" — propósito formal; cualquier verbo (no solo de movimiento)","fr":"«afin de / pour» — but formel; tout verbe (pas seulement de mouvement)","pt-BR":"\"para / a fim de\" — propósito formal; qualquer verbo","th":"\"เพื่อ ... (ทางการ)\" — กริยาใดก็ได้ ไม่จำกัด","id":"\"untuk / demi (formal)\" — verba apa pun, tak terbatas verba gerak","vi":"\"để / nhằm (trang trọng)\" — bất kỳ động từ nào","ja":"「〜ために」— 改まり、移動動詞に限定されない"}'::jsonb, '건강을 유지하기 위해서 운동을 해요.', '{"en":"I exercise in order to stay healthy.","es":"Hago ejercicio para mantener la salud.","fr":"Je fais du sport pour rester en bonne santé.","pt-BR":"Eu me exercito para manter a saúde.","th":"ฉันออกกำลังกายเพื่อรักษาสุขภาพ","id":"Saya berolahraga untuk menjaga kesehatan.","vi":"Tôi tập thể dục để giữ sức khỏe.","ja":"健康を維持するために運動します。"}'::jsonb, 'topik-3'),
('에 따라(서)', '{"en":"\"according to / depending on\" — variation based on something","es":"\"según / dependiendo de\" — varía conforme a algo","fr":"«selon / en fonction de» — variation selon qch","pt-BR":"\"conforme / dependendo de\" — varia segundo algo","th":"\"ตามที่ / ขึ้นอยู่กับ ...\" — เปลี่ยนตาม","id":"\"sesuai / tergantung ...\" — bervariasi","vi":"\"tùy theo / theo ...\" — biến đổi theo","ja":"「〜によって / 〜次第で」"}'::jsonb, '날씨에 따라 옷을 다르게 입어요.', '{"en":"I dress differently depending on the weather.","es":"Me visto diferente según el tiempo.","fr":"Je m’habille différemment selon le temps.","pt-BR":"Visto-me diferente conforme o clima.","th":"ฉันแต่งตัวต่างกันตามสภาพอากาศ","id":"Saya berpakaian beda tergantung cuaca.","vi":"Tôi mặc khác nhau tùy theo thời tiết.","ja":"天気によって服装が変わります。"}'::jsonb, 'topik-3'),
('에 비해(서)', '{"en":"\"compared to / relative to\" — neutral, more formal than 보다","es":"\"en comparación con / comparado con\" — más neutro que 보다","fr":"«par rapport à / comparé à» — neutre, plus formel que 보다","pt-BR":"\"em comparação com / comparado a\" — mais neutro que 보다","th":"\"เมื่อเทียบกับ ...\" — เป็นกลาง / ทางการกว่า 보다","id":"\"dibandingkan dengan ...\" — netral, lebih formal dari 보다","vi":"\"so với / so sánh với ...\" — trung tính, trang trọng hơn 보다","ja":"「〜に比べて」— 보다 より中立・改まり"}'::jsonb, '작년에 비해 올해 물가가 많이 올랐어요.', '{"en":"Compared to last year, prices have risen a lot this year.","es":"En comparación con el año pasado, los precios han subido mucho este año.","fr":"Par rapport à l’an dernier, les prix ont beaucoup monté cette année.","pt-BR":"Em comparação com o ano passado, os preços subiram muito este ano.","th":"เมื่อเทียบกับปีที่แล้ว ปีนี้ราคาขึ้นเยอะมาก","id":"Dibandingkan tahun lalu, harga naik banyak tahun ini.","vi":"So với năm ngoái, giá cả năm nay tăng rất nhiều.","ja":"昨年に比べて今年は物価がかなり上がりました。"}'::jsonb, 'topik-3'),
('-(으)ㄹ 것 같다', '{"en":"\"will probably / it seems X will\" — conjecture about future or hypothesis","es":"\"parece que va a / creo que ...\" — conjetura sobre futuro o hipótesis","fr":"«il semble que ... / je pense que ...» — futur ou hypothèse","pt-BR":"\"parece que vai / acho que ...\" — conjectura sobre o futuro","th":"\"คิดว่าน่าจะ ...\" — เดาเรื่องอนาคต","id":"\"sepertinya akan / saya rasa ...\" — dugaan akan datang","vi":"\"có lẽ sẽ ... / chắc là ...\" — phỏng đoán tương lai","ja":"「〜と思う / 〜そうだ(未来)」"}'::jsonb, '내일 비가 올 것 같아요.', '{"en":"I think it will rain tomorrow.","es":"Creo que mañana va a llover.","fr":"Je pense qu’il va pleuvoir demain.","pt-BR":"Acho que vai chover amanhã.","th":"พรุ่งนี้น่าจะฝนตก","id":"Sepertinya besok akan hujan.","vi":"Có vẻ ngày mai trời sẽ mưa.","ja":"明日は雨が降りそうです。"}'::jsonb, 'topik-3'),
('-(으)ㄴ/는 것처럼', '{"en":"\"as if / just like ...\" — comparison of manner or appearance","es":"\"como si / igual que ...\" — comparación de modo o apariencia","fr":"«comme si / tout comme ...» — manière ou apparence","pt-BR":"\"como se / igual a ...\" — comparação de modo ou aparência","th":"\"ราวกับ / เหมือนกับว่า ...\"","id":"\"seakan-akan / seperti ...\"","vi":"\"như thể / giống như ...\"","ja":"「〜のように / 〜かのように」"}'::jsonb, '아무 일도 없었던 것처럼 행동해요.', '{"en":"They act as if nothing had happened.","es":"Actúa como si no hubiera pasado nada.","fr":"Il agit comme si rien ne s’était passé.","pt-BR":"Age como se nada tivesse acontecido.","th":"ทำเหมือนไม่มีอะไรเกิดขึ้น","id":"Berlaku seakan tak terjadi apa-apa.","vi":"Hành xử như chưa có chuyện gì.","ja":"何事もなかったかのように振る舞います。"}'::jsonb, 'topik-3'),
('-(으)면 좋겠다', '{"en":"\"I wish / I hope\" — desire about a situation, often beyond one’s control","es":"\"ojalá / me gustaría que ...\" — deseo sobre una situación","fr":"«j’aimerais bien que / si seulement ...» — souhait","pt-BR":"\"tomara que / queria que ...\" — desejo sobre uma situação","th":"\"อยากให้ ... / หวังว่า ...\" — ความปรารถนา","id":"\"semoga / berharap ...\" — harapan","vi":"\"ước gì / mong rằng ...\" — mong muốn","ja":"「〜たらいいな / 〜ば いいのに」"}'::jsonb, '내일 날씨가 좋으면 좋겠어요.', '{"en":"I hope the weather will be nice tomorrow.","es":"Ojalá haga buen tiempo mañana.","fr":"J’espère qu’il fera beau demain.","pt-BR":"Tomara que faça bom tempo amanhã.","th":"หวังว่าพรุ่งนี้อากาศจะดี","id":"Semoga besok cuacanya bagus.","vi":"Mong là ngày mai trời đẹp.","ja":"明日天気が良ければいいですね。"}'::jsonb, 'topik-3'),
('-(으)ㄴ/는 줄 알다/몰랐다', '{"en":"\"thought that ... (but wasn’t)\" / \"didn’t know that ...\" — mistaken belief","es":"\"creía que ... (pero no era así)\" / \"no sabía que ...\" — creencia errónea","fr":"«je croyais que ...» / «je ne savais pas que ...» — croyance erronée","pt-BR":"\"achei que ... (mas não era)\" / \"não sabia que ...\" — crença equivocada","th":"\"คิดว่า ... (แต่ไม่ใช่)\" / \"ไม่รู้ว่า ...\"","id":"\"saya kira ... (ternyata bukan)\" / \"saya tidak tahu kalau ...\"","vi":"\"tôi tưởng là ...\" / \"tôi không biết là ...\"","ja":"「〜と思った / 〜と知らなかった」— 思い違い"}'::jsonb, '오늘 수업이 있는 줄 몰랐어요.', '{"en":"I didn’t know there was class today.","es":"No sabía que hoy había clase.","fr":"Je ne savais pas qu’il y avait cours aujourd’hui.","pt-BR":"Não sabia que tinha aula hoje.","th":"ไม่รู้ว่าวันนี้มีเรียน","id":"Saya tidak tahu kalau hari ini ada kelas.","vi":"Tôi không biết hôm nay có buổi học.","ja":"今日授業があるとは知りませんでした。"}'::jsonb, 'topik-3'),
('-기 마련이다', '{"en":"\"it’s natural that ... / inevitably ...\" — what tends to happen","es":"\"es natural que ... / suele ocurrir que ...\" — patrón esperable","fr":"«il est naturel que ... / il arrive forcément que ...»","pt-BR":"\"é natural que ... / naturalmente ...\"","th":"\"ก็ต้องเป็นอย่างนั้น / ธรรมดา ...\"","id":"\"sudah biasa / tentu saja ...\"","vi":"\"là chuyện thường / ắt phải ...\"","ja":"「〜するものだ」— 自然な道理"}'::jsonb, '사람은 누구나 실수하기 마련이에요.', '{"en":"It’s natural that anyone makes mistakes.","es":"Es inevitable que cualquier persona cometa errores.","fr":"Tout le monde fait forcément des erreurs.","pt-BR":"É natural que qualquer pessoa cometa erros.","th":"คนเราย่อมทำผิดพลาดเป็นเรื่องธรรมดา","id":"Wajar kalau siapa pun pernah salah.","vi":"Ai cũng có lúc mắc sai lầm là chuyện thường.","ja":"人は誰でも間違いをするものです。"}'::jsonb, 'topik-3'),
('-기로 하다', '{"en":"\"decide to / agree to\" — own decision or mutual agreement","es":"\"decidir hacer / quedar en\" — decisión propia o acuerdo","fr":"«décider de / convenir de» — décision ou accord","pt-BR":"\"decidir / combinar de\" — decisão ou acordo","th":"\"ตกลงว่าจะ / นัดกันว่าจะ ...\"","id":"\"memutuskan untuk / sepakat untuk ...\"","vi":"\"quyết định / hẹn nhau ...\"","ja":"「〜することにする / 〜することに決める」"}'::jsonb, '내일 만나기로 했어요.', '{"en":"We agreed to meet tomorrow.","es":"Quedamos en encontrarnos mañana.","fr":"On a convenu de se voir demain.","pt-BR":"Combinámos de nos encontrar amanhã.","th":"นัดกันว่าจะเจอกันพรุ่งนี้","id":"Kami sepakat ketemu besok.","vi":"Chúng tôi đã hẹn gặp nhau vào ngày mai.","ja":"明日会うことにしました。"}'::jsonb, 'topik-3'),
('-(으)ㄴ/는 편이다', '{"en":"\"tend to / be rather ...\" — relative tendency, \"on the side of\"","es":"\"tender a / ser más bien ...\" — tendencia relativa","fr":"«avoir tendance à / être plutôt ...»","pt-BR":"\"tender a / ser meio ...\" — tendência relativa","th":"\"ค่อนข้าง ... / มักจะ ...\" — แนวโน้ม","id":"\"cenderung / tergolong ...\" — kecenderungan relatif","vi":"\"có xu hướng / khá ...\" — khuynh hướng","ja":"「〜ほうだ」— 傾向"}'::jsonb, '저는 음식을 많이 먹는 편이에요.', '{"en":"I tend to eat a lot.","es":"Yo tiendo a comer bastante.","fr":"J’ai plutôt tendance à beaucoup manger.","pt-BR":"Eu costumo comer bastante.","th":"ฉันเป็นคนกินเยอะ","id":"Saya termasuk yang banyak makan.","vi":"Tôi thuộc kiểu ăn nhiều.","ja":"私は食べる量が多いほうです。"}'::jsonb, 'topik-3'),
('-(으)ㄹ 줄 알다/모르다', '{"en":"\"know / don’t know how to ...\" — learned skill (cf. -(으)ㄹ 수 있다, general possibility)","es":"\"saber / no saber cómo ...\" — habilidad aprendida (cf. -(으)ㄹ 수 있다 posibilidad)","fr":"«savoir / ne pas savoir faire» — compétence acquise","pt-BR":"\"saber / não saber como ...\" — habilidade aprendida","th":"\"รู้/ไม่รู้วิธี ...\" — ทักษะที่เรียนรู้","id":"\"tahu cara / tidak tahu cara ...\" — keterampilan","vi":"\"biết / không biết cách ...\" — kỹ năng học được","ja":"「〜の仕方を知っている / 知らない」— 習得能力"}'::jsonb, '저는 피아노를 칠 줄 알아요.', '{"en":"I know how to play the piano.","es":"Sé tocar el piano.","fr":"Je sais jouer du piano.","pt-BR":"Eu sei tocar piano.","th":"ฉันเล่นเปียโนเป็น","id":"Saya bisa main piano.","vi":"Tôi biết chơi piano.","ja":"私はピアノが弾けます。"}'::jsonb, 'topik-3'),
('-도록', '{"en":"\"so that / until / to the extent that\" — purpose, limit, or instruction","es":"\"para que / hasta que / de modo que\" — propósito, extensión o instrucción","fr":"«de sorte que / jusqu’à ce que / pour que»","pt-BR":"\"para que / até que / de modo que\"","th":"\"เพื่อให้ / จนกระทั่ง / ในแบบที่ ...\"","id":"\"agar / sampai / supaya ...\"","vi":"\"để / cho đến khi / sao cho ...\"","ja":"「〜するように / 〜まで」— 目的・限界・指示"}'::jsonb, '잘 들을 수 있도록 크게 말해 주세요.', '{"en":"Please speak loudly so I can hear well.","es":"Hable fuerte para que pueda oír bien.","fr":"Parle fort pour que je puisse bien entendre.","pt-BR":"Fale alto para eu poder ouvir bem.","th":"พูดดัง ๆ หน่อยเพื่อให้ฉันได้ยินชัด ๆ","id":"Bicara keras agar terdengar jelas.","vi":"Hãy nói to để tôi nghe rõ.","ja":"よく聞こえるように大きな声で話してください。"}'::jsonb, 'topik-3'),
('-자마자', '{"en":"\"as soon as / the moment that\" — immediate sequence","es":"\"en cuanto / nada más + infinitivo\" — secuencia inmediata","fr":"«dès que / aussitôt que» — séquence immédiate","pt-BR":"\"assim que / logo que\" — sequência imediata","th":"\"ทันทีที่ ...\" — ติดกันทันที","id":"\"begitu / segera setelah ...\"","vi":"\"ngay khi / vừa ... đã ...\"","ja":"「〜するやいなや / 〜したとたん」"}'::jsonb, '집에 오자마자 손을 씻어요.', '{"en":"As soon as I get home, I wash my hands.","es":"En cuanto llego a casa, me lavo las manos.","fr":"Dès que je rentre, je me lave les mains.","pt-BR":"Assim que chego em casa, lavo as mãos.","th":"พอกลับถึงบ้านก็ล้างมือทันที","id":"Begitu pulang, saya langsung cuci tangan.","vi":"Vừa về đến nhà tôi liền rửa tay.","ja":"家に帰るとすぐ手を洗います。"}'::jsonb, 'topik-3'),
('-(으)ㄴ 지', '{"en":"\"it has been (time) since (doing)\" — with duration + 됐어요/지났어요","es":"\"hace (tiempo) que / llevo + tiempo ...\" — con duración + 됐어요/지났어요","fr":"«cela fait (durée) que ...» — avec durée + 됐어요/지났어요","pt-BR":"\"faz (tempo) que / já se passou ...\" — com duração + 됐어요/지났어요","th":"\"นานเท่าไหร่แล้วที่ ...\" — กับช่วงเวลา + 됐어요/지났어요","id":"\"sudah (waktu) sejak ...\" — + 됐어요/지났어요","vi":"\"đã (thời gian) kể từ khi ...\" — + 됐어요/지났어요","ja":"「〜してから(時間)になる / が経つ」"}'::jsonb, '한국어를 공부한 지 2년이 됐어요.', '{"en":"It’s been two years since I started learning Korean.","es":"Llevo dos años estudiando coreano.","fr":"Cela fait deux ans que j’apprends le coréen.","pt-BR":"Faz dois anos que estudo coreano.","th":"เรียนภาษาเกาหลีมา 2 ปีแล้ว","id":"Sudah dua tahun saya belajar bahasa Korea.","vi":"Đã hai năm tôi học tiếng Hàn.","ja":"韓国語を勉強して2年になりました。"}'::jsonb, 'topik-3'),
('-아/어도', '{"en":"\"even if / although\" — simple concession","es":"\"aunque / incluso si\" — concesión simple","fr":"«même si» — concession simple","pt-BR":"\"mesmo que / ainda que\" — concessão simples","th":"\"แม้ว่าจะ ... ก็ ...\"","id":"\"meskipun / walaupun\"","vi":"\"dù / cho dù\"","ja":"「〜ても」— 単純な譲歩"}'::jsonb, '피곤해도 운동해요.', '{"en":"I exercise even when I’m tired.","es":"Aunque esté cansado, hago ejercicio.","fr":"Même fatigué, je fais du sport.","pt-BR":"Mesmo cansado, eu me exercito.","th":"แม้จะเหนื่อยก็ยังออกกำลังกาย","id":"Meskipun lelah, saya tetap berolahraga.","vi":"Dù mệt tôi vẫn tập thể dục.","ja":"疲れていても運動します。"}'::jsonb, 'topik-3'),
('-(으)ㄴ/는데도', '{"en":"\"despite the fact that / and yet\" — concession with unexpected outcome","es":"\"a pesar de que / y sin embargo\" — concesión con resultado sorpresivo","fr":"«bien que / pourtant» — concession avec résultat inattendu","pt-BR":"\"apesar de que / ainda assim\" — concessão com resultado inesperado","th":"\"แม้ว่า ... ก็ยัง ...\" — ผลที่ไม่คาดคิด","id":"\"meski ..., tetap ...\" — hasil tak terduga","vi":"\"mặc dù ... vẫn ...\" — kết quả bất ngờ","ja":"「〜のに」— 意外な結果を伴う譲歩"}'::jsonb, '많이 먹었는데도 배가 고파요.', '{"en":"I’m hungry even though I ate a lot.","es":"A pesar de haber comido mucho, tengo hambre.","fr":"Pourtant j’ai beaucoup mangé, j’ai encore faim.","pt-BR":"Apesar de ter comido muito, ainda estou com fome.","th":"กินไปเยอะแล้วก็ยังหิวอยู่","id":"Padahal sudah makan banyak, masih lapar.","vi":"Dù ăn nhiều rồi tôi vẫn đói.","ja":"たくさん食べたのにお腹が空いています。"}'::jsonb, 'topik-3'),
('밖에 + neg', '{"en":"\"only / nothing but ...\" — implies insufficiency; always with a negative verb","es":"\"solo / nada más que ...\" — implica insuficiencia; siempre con verbo en negativa","fr":"«ne ... que / rien que ...» — sentiment d’insuffisance, verbe au négatif","pt-BR":"\"só / nada além de ...\" — implica insuficiência; sempre com verbo negativo","th":"\"มีแค่ ... เท่านั้น\" — ความรู้สึกว่าน้อย / ไม่พอ (กริยาเป็นปฏิเสธ)","id":"\"hanya ... saja\" — kesan kurang; verba selalu negatif","vi":"\"chỉ có ... thôi\" — hàm ý không đủ; động từ phủ định","ja":"「〜しか〜ない」— 不足のニュアンス"}'::jsonb, '돈이 천 원밖에 없어요.', '{"en":"I only have 1,000 won.","es":"Solo tengo 1.000 won.","fr":"Je n’ai que mille wons.","pt-BR":"Eu só tenho 1.000 wons.","th":"มีเงินแค่ 1,000 วอน","id":"Saya hanya punya 1.000 won.","vi":"Tôi chỉ có 1.000 won thôi.","ja":"お金が1000ウォンしかありません。"}'::jsonb, 'topik-3'),
('피동 (이/히/리/기)', '{"en":"full passive system — suffix 이/히/리/기 by verb; agent marked with 에게/에 의해","es":"pasiva morfológica completa — sufijo 이/히/리/기 según verbo; agente con 에게/에 의해","fr":"passif morphologique complet — suffixes 이/히/리/기; agent par 에게/에 의해","pt-BR":"voz passiva completa — sufixos 이/히/리/기; agente com 에게/에 의해","th":"รูปกริยาถูกกระทำเต็ม — เติม 이/히/리/기; ผู้กระทำใส่ 에게/에 의해","id":"pasif morfologis lengkap — sufiks 이/히/리/기; pelaku dengan 에게/에 의해","vi":"thể bị động đầy đủ — hậu tố 이/히/리/기; tác nhân với 에게/에 의해","ja":"形態的受動の体系: 이/히/리/기 (動作主は 에게/에 의해)"}'::jsonb, '창문이 바람에 열렸어요.', '{"en":"The window was opened by the wind.","es":"La ventana se abrió con el viento.","fr":"La fenêtre s’est ouverte sous l’effet du vent.","pt-BR":"A janela foi aberta pelo vento.","th":"หน้าต่างถูกลมเปิด","id":"Jendela terbuka karena angin.","vi":"Cửa sổ bị gió mở ra.","ja":"窓が風で開きました。"}'::jsonb, 'topik-3'),
('사동 (이/히/리/기/우/추)', '{"en":"full causative system — make/let someone do; suffixes 이/히/리/기/우/추","es":"causativa morfológica completa — \"hacer que alguien haga\"; sufijos 이/히/리/기/우/추","fr":"causatif morphologique complet — «faire faire»; suffixes 이/히/리/기/우/추","pt-BR":"voz causativa completa — \"fazer alguém fazer\"; sufixos 이/히/리/기/우/추","th":"รูปกริยาทำให้ผู้อื่นทำ — เติม 이/히/리/기/우/추","id":"kausatif morfologis lengkap — sufiks 이/히/리/기/우/추","vi":"thể sai khiến đầy đủ — hậu tố 이/히/리/기/우/추","ja":"形態的使役の体系: 이/히/리/기/우/추 (먹이다/입히다/웃기다/재우다/낮추다)"}'::jsonb, '아이에게 밥을 먹였어요.', '{"en":"I fed the child.","es":"Le di de comer al niño.","fr":"J’ai donné à manger à l’enfant.","pt-BR":"Dei comida para a criança.","th":"ป้อนข้าวให้เด็ก","id":"Saya menyuapi anak itu.","vi":"Tôi đút cơm cho đứa bé.","ja":"子供にご飯を食べさせました。"}'::jsonb, 'topik-3'),
('-(으)려다가', '{"en":"\"was going to ... but ...\" — abandoned intention; changed mid-action","es":"\"iba a hacer ... pero ...\" — intención abandonada","fr":"«j’allais ... mais ...» — intention abandonnée","pt-BR":"\"ia fazer ... mas ...\" — intenção abandonada","th":"\"กำลังจะ ... แต่ ...\" — ละทิ้งความตั้งใจ","id":"\"berniat ... tetapi ...\" — niat dibatalkan","vi":"\"đang định ... thì ...\" — bỏ ý định","ja":"「〜しようとして / 〜しかけて」— 中止した意図"}'::jsonb, '전화하려다가 그냥 문자를 보냈어요.', '{"en":"I was going to call but I just sent a text instead.","es":"Iba a llamar pero al final mandé un mensaje.","fr":"J’allais appeler mais j’ai finalement envoyé un texto.","pt-BR":"Eu ia ligar, mas acabei mandando uma mensagem.","th":"จะโทร แต่สุดท้ายส่งข้อความแทน","id":"Mau nelpon tapi malah kirim pesan saja.","vi":"Tôi định gọi nhưng cuối cùng chỉ nhắn tin.","ja":"電話しようとしたけど、結局メッセージを送りました。"}'::jsonb, 'topik-3'),
('-다 보면', '{"en":"\"if you keep doing, eventually ...\" — encouragement / natural outcome","es":"\"si sigues haciendo, llegará a ...\" — proceso que lleva a un resultado","fr":"«à force de ..., on finit par ...» — résultat naturel","pt-BR":"\"se você continuar fazendo, eventualmente ...\" — resultado natural","th":"\"ถ้าทำต่อไปเรื่อย ๆ จะ ...\" — กระบวนการ → ผล","id":"\"kalau terus-terusan ..., akhirnya ...\"","vi":"\"nếu cứ làm mãi thì rồi ...\"","ja":"「〜していると / 〜しているうちに」— 継続→結果"}'::jsonb, '열심히 공부하다 보면 실력이 늘 거예요.', '{"en":"If you keep studying hard, your skills will improve.","es":"Si sigues estudiando con esfuerzo, tu nivel irá mejorando.","fr":"Si tu continues à étudier sérieusement, tu progresseras.","pt-BR":"Se continuar estudando com dedicação, vai melhorar.","th":"ถ้าเรียนหนักไปเรื่อย ๆ ฝีมือจะดีขึ้นเอง","id":"Kalau terus belajar serius, kemampuan akan meningkat.","vi":"Cứ chăm chỉ học, trình độ sẽ tiến bộ.","ja":"一生懸命勉強していれば、実力が伸びますよ。"}'::jsonb, 'topik-3'),
('-다 보니', '{"en":"\"while doing, I came to realize / ended up ...\" — gradual realization (past)","es":"\"mientras lo hacía, me di cuenta / resulté ...\" — descubrimiento gradual","fr":"«à force de ..., je me suis rendu compte / j’ai fini par ...» — découverte graduelle","pt-BR":"\"enquanto fazia, fui percebendo ...\" — descoberta gradual","th":"\"พอทำไปเรื่อย ๆ ก็ ... / รู้ว่า ...\" — รับรู้ทีละน้อย","id":"\"lama-kelamaan ... / ternyata ...\"","vi":"\"làm mãi thì nhận ra / cuối cùng ...\"","ja":"「〜しているうちに / 〜してみると」— 過去の気づき"}'::jsonb, '한국어를 공부하다 보니 한국 문화도 좋아지게 됐어요.', '{"en":"As I kept studying Korean, I came to like Korean culture too.","es":"Mientras estudiaba coreano, llegué a gustarme también la cultura coreana.","fr":"À force d’étudier le coréen, je me suis mis à aimer aussi la culture coréenne.","pt-BR":"À medida que estudava coreano, fui gostando também da cultura coreana.","th":"พอเรียนภาษาเกาหลีไปเรื่อย ๆ ก็เริ่มชอบวัฒนธรรมเกาหลีไปด้วย","id":"Lama-lama belajar bahasa Korea, saya jadi suka juga budayanya.","vi":"Học tiếng Hàn mãi, tôi cũng dần thích văn hóa Hàn.","ja":"韓国語を勉強しているうちに、韓国文化も好きになりました。"}'::jsonb, 'topik-3'),
('-아/어 대다', '{"en":"\"keep ...ing (excessively)\" — repeated action, often annoying to speaker","es":"\"hacer en exceso / no parar de ...\" — acción repetida, suele irritar al hablante","fr":"«n’arrête pas de ...» — action répétée, souvent agaçante","pt-BR":"\"não parar de / ficar ...\" — ação repetida, geralmente irritante","th":"\"... ไม่หยุด / ... อย่างหนัก\" — มักรำคาญ","id":"\"terus-menerus ... / kebanyakan ...\"","vi":"\"cứ ... mãi / liên tục ...\"","ja":"「〜してばかりいる / 〜しまくる」— 過度の反復(苛立ち)"}'::jsonb, '아이가 계속 울어 댔어요.', '{"en":"The child wouldn’t stop crying.","es":"El niño no paraba de llorar.","fr":"L’enfant n’arrêtait pas de pleurer.","pt-BR":"A criança não parava de chorar.","th":"เด็กร้องไห้ไม่หยุดเลย","id":"Anak itu menangis terus-menerus.","vi":"Đứa bé khóc mãi không thôi.","ja":"子供が泣き続けていました。"}'::jsonb, 'topik-3'),
('-고 말다', '{"en":"\"end up doing / finally happened ...\" — usually undesired outcome","es":"\"acabar haciendo / terminar por ...\" — resultado final, suele ser no deseado","fr":"«finir par ... (malgré soi)» — résultat final, souvent indésirable","pt-BR":"\"acabar fazendo / acabou que ...\" — desfecho geralmente indesejado","th":"\"สุดท้ายก็ ... (เสียใจ)\" — ผลที่ไม่ตั้งใจ","id":"\"akhirnya malah ...\" — hasil tak diinginkan","vi":"\"cuối cùng (vẫn) ...\" — kết cục không mong muốn","ja":"「〜してしまう」— 望まぬ結末"}'::jsonb, '참으려고 했는데 울고 말았어요.', '{"en":"I tried to hold back, but ended up crying.","es":"Intenté aguantar pero acabé llorando.","fr":"J’ai essayé de me retenir, mais j’ai fini par pleurer.","pt-BR":"Tentei segurar, mas acabei chorando.","th":"พยายามจะอดทน แต่สุดท้ายก็ร้องไห้","id":"Saya coba tahan, tapi akhirnya menangis juga.","vi":"Tôi cố nín nhưng cuối cùng vẫn khóc.","ja":"我慢しようとしたのに、結局泣いてしまいました。"}'::jsonb, 'topik-3'),
('-는다면 / -(이)라면', '{"en":"\"if (hypothetically) ...\" — pure hypothesis (cf. -(으)면 real condition)","es":"\"si (hipotético) ...\" — hipótesis pura (cf. -(으)면 condición real)","fr":"«si (hypothétique) ...» — hypothèse pure","pt-BR":"\"se (hipotético) ...\" — hipótese pura","th":"\"ถ้าสมมุติว่า ...\" — สมมุติฐาน (ต่างจาก -(으)면)","id":"\"andai / seandainya ...\" — hipotesis murni","vi":"\"giả sử / nếu giả như ...\" — giả thiết","ja":"「もし〜なら / 〜だとしたら」— 仮定"}'::jsonb, '내일 비가 온다면 어떻게 할 거예요?', '{"en":"If it rains tomorrow, what will you do?","es":"Si mañana llueve, ¿qué harás?","fr":"S’il pleut demain, que ferez-vous ?","pt-BR":"Se chover amanhã, o que vai fazer?","th":"ถ้าพรุ่งนี้ฝนตก จะทำอย่างไร","id":"Kalau besok hujan, kamu mau bagaimana?","vi":"Nếu ngày mai trời mưa thì bạn làm gì?","ja":"もし明日雨が降ったらどうしますか？"}'::jsonb, 'topik-3'),
('-아/어 가다', '{"en":"progressive continuative — \"to keep ...ing (toward the future)\"","es":"progresivo continuativo — \"ir + gerundio (avanzando con el tiempo)\"","fr":"progressif continu — «aller en ...ant»","pt-BR":"progressivo continuativo — \"ir ...ndo / continuar ...\"","th":"\"... ไปเรื่อย ๆ / ค่อย ๆ ... ไป\" — ดำเนินไปสู่อนาคต","id":"\"semakin / makin ... seiring waktu\"","vi":"\"cứ ... dần / tiếp tục ... đi tới\"","ja":"「〜していく」— 未来へ向かう継続"}'::jsonb, '일이 거의 다 끝나 가요.', '{"en":"The work is almost done.","es":"El trabajo está casi terminándose.","fr":"Le travail touche à sa fin.","pt-BR":"O trabalho está quase terminando.","th":"งานใกล้จะเสร็จแล้ว","id":"Pekerjaannya hampir selesai.","vi":"Công việc sắp xong rồi.","ja":"仕事がほとんど終わっていきます。"}'::jsonb, 'topik-3'),
('-아/어 오다', '{"en":"\"has been ...ing (from the past until now)\" — accumulative continuity","es":"\"venir + gerundio / llevar + gerundio\" — continuidad acumulativa desde el pasado","fr":"«être en train de ... depuis» — continuité accumulative","pt-BR":"\"vir ...ndo (do passado até agora)\"","th":"\"... มาตลอด / ... มาเรื่อย ๆ (จากอดีตถึงปัจจุบัน)\"","id":"\"sudah lama / selama ini ...-nya berlanjut\"","vi":"\"đã ... đến nay / vẫn ... bấy lâu nay\"","ja":"「〜してくる / 〜してきた」— 過去から現在への蓄積"}'::jsonb, '10년 동안 한국어를 공부해 왔어요.', '{"en":"I have been studying Korean for 10 years.","es":"Llevo 10 años estudiando coreano.","fr":"Cela fait 10 ans que j’étudie le coréen.","pt-BR":"Venho estudando coreano há 10 anos.","th":"ฉันเรียนภาษาเกาหลีมา 10 ปีแล้ว","id":"Saya sudah belajar bahasa Korea selama 10 tahun.","vi":"Tôi đã học tiếng Hàn được 10 năm rồi.","ja":"10年間韓国語を勉強してきました。"}'::jsonb, 'topik-3'),
('-아/어 내다', '{"en":"\"manage to / pull off ...\" — completion despite difficulty","es":"\"lograr (completar) ...\" — completar a pesar de la dificultad","fr":"«parvenir à / arriver à» — accomplissement malgré l’effort","pt-BR":"\"conseguir (completar) ...\" — conclusão apesar da dificuldade","th":"\"ทำ ... ได้สำเร็จ (แม้จะลำบาก)\"","id":"\"berhasil ... meski sulit\"","vi":"\"xoay sở / vượt khó để ...\"","ja":"「〜し切る / 〜し遂げる」— 困難を経ての達成"}'::jsonb, '어려운 문제를 풀어 냈어요.', '{"en":"I managed to solve the difficult problem.","es":"Logré resolver el problema difícil.","fr":"J’ai réussi à résoudre ce problème difficile.","pt-BR":"Consegui resolver o problema difícil.","th":"ฉันแก้โจทย์ที่ยากได้สำเร็จ","id":"Saya berhasil memecahkan soal yang sulit.","vi":"Tôi đã giải được bài toán khó.","ja":"難しい問題を解き切りました。"}'::jsonb, 'topik-3'),
('-지 그래(요)?', '{"en":"\"why don’t you ...?\" — soft suggestion","es":"\"¿por qué no ...? / podrías ...\" — sugerencia suave","fr":"«pourquoi ne pas ... ?» — suggestion douce","pt-BR":"\"por que você não ...?\" — sugestão suave","th":"\"ทำไมไม่ ... ล่ะ?\" — เสนอแนะอย่างนุ่มนวล","id":"\"kenapa tidak ... saja?\" — saran lembut","vi":"\"sao bạn không ... đi?\" — gợi ý nhẹ nhàng","ja":"「〜したらどう？」— 柔らかな提案"}'::jsonb, '좀 쉬지 그래요?', '{"en":"Why don’t you rest a bit?","es":"¿Por qué no descansas un poco?","fr":"Pourquoi ne pas te reposer un peu ?","pt-BR":"Por que você não descansa um pouco?","th":"ทำไมไม่พักสักหน่อยล่ะ","id":"Kenapa tidak istirahat sebentar?","vi":"Sao bạn không nghỉ một chút đi?","ja":"少し休んだらどうですか？"}'::jsonb, 'topik-3'),
('-아/어야지(요)', '{"en":"\"I should / you should ...\" — self-exhortation or mild reproach","es":"\"tengo que / deberías ...\" — autoexhortación o leve reproche","fr":"«il faut que / tu devrais ...» — auto-exhortation ou léger reproche","pt-BR":"\"tenho de / você deveria ...\" — autoexortação ou leve reproche","th":"\"ต้อง ... สิ / ก็ควรจะ ...\"","id":"\"harus dong / mestinya kamu ...\"","vi":"\"phải / lẽ ra phải ...\"","ja":"「〜なきゃ / 〜しないと」— 自戒・軽い咎め"}'::jsonb, '약속을 지켜야지요.', '{"en":"You should keep your promises.","es":"Hay que cumplir las promesas.","fr":"Il faut tenir ses promesses.","pt-BR":"A gente tem que cumprir as promessas.","th":"ก็ต้องรักษาสัญญาสิ","id":"Mestinya janji harus ditepati.","vi":"Phải giữ lời hứa chứ.","ja":"約束は守らなきゃですよ。"}'::jsonb, 'topik-3'),
('-거든(요)', '{"en":"\"it’s that / you see ...\" — gives an explanatory backstory","es":"\"es que / verás ...\" — introduce información explicativa","fr":"«c’est que / tu vois ...» — explication / fond","pt-BR":"\"é que / sabe ...\" — fornece explicação","th":"\"คือว่า / รู้ไหม ...\" — เกริ่นเหตุผล","id":"\"soalnya / kan ...\" — penjelasan latar","vi":"\"là vì / là thế này ...\" — đưa lý do","ja":"「〜んだよ / 〜んですよ」— 説明・前置き"}'::jsonb, '어제 너무 피곤했거든요.', '{"en":"It’s that I was really tired yesterday.","es":"Es que ayer estaba muy cansado.","fr":"C’est que j’étais vraiment fatigué hier.","pt-BR":"É que ontem eu estava muito cansado.","th":"คือเมื่อวานฉันเหนื่อยมาก","id":"Soalnya kemarin saya capek sekali.","vi":"Là vì hôm qua tôi mệt lắm.","ja":"昨日とても疲れていたんですよ。"}'::jsonb, 'topik-3'),
('N + 답다', '{"en":"\"typical of / worthy of N\" — turns a noun into an adjective: \"it is fittingly N\"","es":"\"propio de / digno de N\" — convierte N en adjetivo: \"es como debe ser un N\"","fr":"«digne de / typique de N» — N devient adjectif","pt-BR":"\"digno de / próprio de N\" — N como adjetivo","th":"\"สมเป็น N / เป็น N สมตัว\"","id":"\"layak / khas N\" — N jadi adjektiva","vi":"\"đúng kiểu / xứng đáng là N\"","ja":"「N らしい」— 名詞 + 답다"}'::jsonb, '너답다.', '{"en":"That’s so you.","es":"Eso es muy propio de ti.","fr":"C’est bien toi.","pt-BR":"Isso é a sua cara.","th":"สมเป็นเธอจริง ๆ","id":"Itu khas kamu sekali.","vi":"Đúng kiểu của bạn rồi.","ja":"いかにもあなたらしいです。"}'::jsonb, 'topik-3'),
('N + 스럽다', '{"en":"\"gives the impression of N / N-ish\" — appears to have the quality (cf. -답다 actually is)","es":"\"da la impresión de N / parece N\" — apariencia (cf. -답다 lo es realmente)","fr":"«qui semble / qui a l’air de N»","pt-BR":"\"que parece N / com cara de N\"","th":"\"ดู ... / มีลักษณะของ ...\"","id":"\"berkesan / kelihatannya ...\"","vi":"\"có vẻ / mang dáng dấp ...\"","ja":"「N らしく見える / N っぽい」(N + 스럽다)"}'::jsonb, '사랑스러워요.', '{"en":"You’re lovely.","es":"Eres adorable.","fr":"Tu es adorable.","pt-BR":"Você é uma graça.","th":"น่ารักจัง","id":"Kamu menggemaskan.","vi":"Bạn thật dễ thương.","ja":"愛らしいですね。"}'::jsonb, 'topik-3'),
('-다고 하다', '{"en":"indirect speech (statements) — \"said that ...\"; contracts to -대요 in casual speech","es":"discurso indirecto (afirmaciones) — \"dijo que ...\"; contracción coloquial -대요","fr":"discours indirect (affirmations) — «a dit que ...»; contraction orale -대요","pt-BR":"discurso indireto (afirmações) — \"disse que ...\"; contração falada -대요","th":"การพูดอ้อม (บอกเล่า) — \"บอกว่า ...\"; รูปย่อ -대요","id":"kalimat tak langsung (pernyataan) — \"katanya ...\"; bentuk lisan -대요","vi":"tường thuật gián tiếp — \"nói rằng ...\"; rút gọn -대요","ja":"間接話法(平叙)「〜と言う」— 口語短縮 -대요"}'::jsonb, '선생님이 내일 시험이 있다고 했어요.', '{"en":"The teacher said there’s an exam tomorrow.","es":"El profesor dijo que mañana hay examen.","fr":"Le professeur a dit qu’il y a un examen demain.","pt-BR":"O professor disse que amanhã tem prova.","th":"อาจารย์บอกว่าพรุ่งนี้มีสอบ","id":"Gurunya bilang besok ada ujian.","vi":"Cô giáo nói ngày mai có bài kiểm tra.","ja":"先生は明日試験があると言いました。"}'::jsonb, 'topik-4'),
('-(으)라고 하다', '{"en":"indirect command — \"told (someone) to ...\"; contracts to -(으)래요","es":"discurso indirecto de mandato — \"le dijo que (haga) ...\"; contracción -(으)래요","fr":"discours indirect (ordre) — «a dit de ...»; contraction -(으)래요","pt-BR":"discurso indireto (ordem) — \"mandou ...\"; contração -(으)래요","th":"การพูดอ้อม (สั่ง) — \"บอกให้ ...\"; รูปย่อ -(으)래요","id":"kalimat tak langsung (perintah) — \"menyuruh ...\"; bentuk lisan -(으)래요","vi":"mệnh lệnh gián tiếp — \"bảo ... hãy ...\"; rút gọn -(으)래요","ja":"間接話法(命令)「〜しろと言う」— 口語短縮 -(으)래요"}'::jsonb, '선생님이 조용히 하라고 했어요.', '{"en":"The teacher told us to be quiet.","es":"El profesor nos dijo que guardáramos silencio.","fr":"Le professeur nous a dit de nous taire.","pt-BR":"O professor mandou ficarmos em silêncio.","th":"อาจารย์บอกให้เงียบ","id":"Gurunya menyuruh kami diam.","vi":"Cô giáo bảo chúng tôi giữ im lặng.","ja":"先生は静かにしろと言いました。"}'::jsonb, 'topik-4'),
('-냐고 하다 / -(으)냐고 묻다', '{"en":"indirect question — \"asked whether / what ...\"; contracts to -냬요","es":"discurso indirecto de pregunta — \"preguntó si / qué ...\"; contracción -냬요","fr":"discours indirect (question) — «a demandé si ...»; contraction -냬요","pt-BR":"discurso indireto (pergunta) — \"perguntou se ...\"; contração -냬요","th":"การพูดอ้อม (ถาม) — \"ถามว่า ...\"; รูปย่อ -냬요","id":"kalimat tak langsung (tanya) — \"menanyakan apakah ...\"; bentuk lisan -냬요","vi":"câu hỏi gián tiếp — \"hỏi liệu ...\"; rút gọn -냬요","ja":"間接話法(疑問)「〜かと聞く」— 口語短縮 -냬요"}'::jsonb, '어디에 사느냐고 물었어요.', '{"en":"They asked where I live.","es":"Me preguntó dónde vivía.","fr":"Il/elle m’a demandé où j’habitais.","pt-BR":"Me perguntou onde eu morava.","th":"เขาถามว่าฉันอยู่ที่ไหน","id":"Dia menanyakan saya tinggal di mana.","vi":"Người ấy hỏi tôi sống ở đâu.","ja":"どこに住んでいるかと聞きました。"}'::jsonb, 'topik-4'),
('-자고 하다', '{"en":"indirect suggestion — \"proposed that (we) ...\"; contracts to -재요","es":"discurso indirecto de propuesta — \"propuso que (hagamos) ...\"; contracción -재요","fr":"discours indirect (proposition) — «a proposé de ...»; contraction -재요","pt-BR":"discurso indireto (sugestão) — \"propôs que ...\"; contração -재요","th":"การพูดอ้อม (ชวน) — \"ชวนว่า ...\"; รูปย่อ -재요","id":"kalimat tak langsung (ajakan) — \"mengajak ...\"; bentuk lisan -재요","vi":"lời rủ gián tiếp — \"rủ rằng ...\"; rút gọn -재요","ja":"間接話法(勧誘)「〜しようと言う」— 口語短縮 -재요"}'::jsonb, '친구가 같이 밥 먹자고 했어요.', '{"en":"My friend proposed that we eat together.","es":"Mi amigo propuso que comiéramos juntos.","fr":"Mon ami(e) a proposé qu’on mange ensemble.","pt-BR":"Meu amigo propôs comermos juntos.","th":"เพื่อนชวนกินข้าวด้วยกัน","id":"Teman saya mengajak makan bersama.","vi":"Bạn tôi rủ ăn cơm cùng nhau.","ja":"友達が一緒にご飯を食べようと言いました。"}'::jsonb, 'topik-4'),
('-다면서요?', '{"en":"\"I heard that ..., right?\" — verifies info heard from another source","es":"\"me dijeron que ..., ¿es cierto?\" — verifica info de terceros","fr":"«il paraît que ..., n’est-ce pas ?» — vérifie une info entendue","pt-BR":"\"ouvi dizer que ..., é verdade?\" — verifica info de terceiros","th":"\"ได้ยินมาว่า ... จริงไหม?\" — ยืนยันข่าวจากคนอื่น","id":"\"katanya ..., benar?\" — verifikasi info dari orang lain","vi":"\"nghe nói ... phải không?\" — kiểm chứng tin nghe được","ja":"「〜らしいですね？/ 〜だそうですね？」— 第三者情報の確認"}'::jsonb, '한국에 간다면서요?', '{"en":"I heard you’re going to Korea, is that right?","es":"Me dijeron que te vas a Corea, ¿es verdad?","fr":"Il paraît que tu pars en Corée, c’est vrai ?","pt-BR":"Ouvi dizer que você vai para a Coreia, é isso?","th":"ได้ยินว่าจะไปเกาหลีจริงเหรอ","id":"Katanya kamu mau ke Korea, benar?","vi":"Nghe nói bạn sắp đi Hàn Quốc phải không?","ja":"韓国に行くんですって？"}'::jsonb, 'topik-4'),
('-(으)ㄹ 뿐만 아니라', '{"en":"\"not only ... but also\" — adds an emphatic extra element","es":"\"no solo ... sino también\" — añade un elemento extra con énfasis","fr":"«non seulement ... mais aussi»","pt-BR":"\"não só ... como também\"","th":"\"ไม่เพียงแต่ ... ยัง ... อีกด้วย\"","id":"\"tidak hanya ... tetapi juga\"","vi":"\"không chỉ ... mà còn ...\"","ja":"「〜だけでなく / 〜のみならず」"}'::jsonb, '그 식당은 맛있을 뿐만 아니라 가격도 저렴해요.', '{"en":"That restaurant is not only delicious but also affordable.","es":"Ese restaurante no solo es rico, sino que también es barato.","fr":"Ce restaurant est non seulement bon mais aussi abordable.","pt-BR":"Aquele restaurante não só é gostoso, como também é barato.","th":"ร้านนั้นนอกจากอร่อยแล้ว ราคายังถูกอีกด้วย","id":"Restoran itu tidak hanya enak, harganya juga murah.","vi":"Nhà hàng đó không chỉ ngon mà giá còn rẻ.","ja":"あの店は美味しいだけでなく、値段も安いです。"}'::jsonb, 'topik-4'),
('-는 반면에', '{"en":"\"whereas / on the other hand ...\" — contrast between two related facts","es":"\"mientras que / en cambio ...\" — contraste entre dos hechos relacionados","fr":"«tandis que / en revanche»","pt-BR":"\"enquanto que / por outro lado\"","th":"\"ในขณะที่ / กลับกัน ...\"","id":"\"sementara itu / sebaliknya ...\"","vi":"\"trong khi đó / ngược lại ...\"","ja":"「〜反面 / 〜の一方で」"}'::jsonb, '언니는 활발한 반면에 저는 조용해요.', '{"en":"My older sister is outgoing, whereas I’m quiet.","es":"Mi hermana mayor es activa, mientras que yo soy tranquilo.","fr":"Ma sœur aînée est dynamique, tandis que moi je suis calme.","pt-BR":"Minha irmã mais velha é animada, enquanto eu sou quieto.","th":"พี่สาวเป็นคนร่าเริง ในขณะที่ฉันเป็นคนเงียบ ๆ","id":"Kakak perempuan saya periang, sementara saya pendiam.","vi":"Chị tôi hoạt bát, ngược lại tôi trầm tính.","ja":"姉は活発な反面、私は静かです。"}'::jsonb, 'topik-4'),
('-에도 불구하고', '{"en":"\"in spite of / despite ...\" — formal concession; common in writing","es":"\"a pesar de / pese a ...\" — concesión formal; frecuente en escritura","fr":"«malgré / en dépit de»","pt-BR":"\"apesar de / a despeito de\"","th":"\"แม้จะ ... ก็ตาม / ทั้งที่ ...\"","id":"\"meskipun demikian / kendati\"","vi":"\"bất chấp / mặc dù vậy\"","ja":"「〜にもかかわらず」— 改まり"}'::jsonb, '비에도 불구하고 많은 사람들이 모였어요.', '{"en":"Despite the rain, many people gathered.","es":"A pesar de la lluvia, se reunió mucha gente.","fr":"Malgré la pluie, beaucoup de gens se sont réunis.","pt-BR":"Apesar da chuva, muita gente se reuniu.","th":"แม้ฝนจะตก ก็มีคนมารวมตัวกันมากมาย","id":"Meskipun hujan, banyak orang berkumpul.","vi":"Bất chấp trời mưa, rất đông người tụ tập.","ja":"雨にもかかわらず、たくさんの人が集まりました。"}'::jsonb, 'topik-4'),
('-(으)ㄹ수록', '{"en":"\"the more ..., the more ...\" — proportional; often with 더","es":"\"cuanto más ..., más ...\" — proporcional; suele con 더","fr":"«plus ..., plus ...» — corrélation, souvent avec 더","pt-BR":"\"quanto mais ..., mais ...\" — proporcional; muitas vezes com 더","th":"\"ยิ่ง ... ยิ่ง ...\" — มักใช้กับ 더","id":"\"semakin ..., semakin ...\" — sering dengan 더","vi":"\"càng ..., càng ...\" — thường đi với 더","ja":"「〜ば〜ほど」"}'::jsonb, '한국어는 공부할수록 재미있어요.', '{"en":"The more I study Korean, the more fun it gets.","es":"Cuanto más estudio coreano, más divertido me resulta.","fr":"Plus j’étudie le coréen, plus c’est intéressant.","pt-BR":"Quanto mais estudo coreano, mais divertido fica.","th":"ภาษาเกาหลียิ่งเรียนยิ่งสนุก","id":"Bahasa Korea semakin dipelajari semakin seru.","vi":"Tiếng Hàn càng học càng thú vị.","ja":"韓国語は勉強すればするほど面白いです。"}'::jsonb, 'topik-4'),
('-는 한', '{"en":"\"as long as / to the extent that ...\" — sets a valid scope","es":"\"siempre que / mientras / en la medida en que ...\" — establece un alcance","fr":"«tant que / dans la mesure où»","pt-BR":"\"enquanto / na medida em que\"","th":"\"ตราบเท่าที่ / เท่าที่ ...\"","id":"\"selama / sejauh ...\"","vi":"\"chừng nào còn ... / trong chừng mực ...\"","ja":"「〜限り / 〜する限り」"}'::jsonb, '가능한 한 빨리 와 주세요.', '{"en":"Please come as soon as you can.","es":"Por favor, venga lo antes posible.","fr":"Venez aussi vite que possible.","pt-BR":"Por favor, venha o mais rápido possível.","th":"กรุณามาให้เร็วที่สุดเท่าที่จะทำได้","id":"Tolong datang secepat mungkin.","vi":"Vui lòng đến càng sớm càng tốt.","ja":"可能な限り早く来てください。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 데다가', '{"en":"\"on top of / besides ...\" — adds a same-polarity fact (good+good or bad+bad)","es":"\"además / encima de eso ...\" — suma hechos del mismo signo","fr":"«en plus de / qui plus est»","pt-BR":"\"além disso / por cima de\"","th":"\"นอกจาก ... แล้ว ยัง ...\"","id":"\"selain ..., juga ...\"","vi":"\"hơn nữa / thêm vào đó\"","ja":"「〜うえに / 〜に加えて」— 同じ極性の追加"}'::jsonb, '비가 오는 데다가 바람도 강해요.', '{"en":"On top of raining, the wind is strong too.","es":"Además de que llueve, también hace mucho viento.","fr":"En plus de pleuvoir, le vent est fort.","pt-BR":"Além de chover, o vento também está forte.","th":"นอกจากฝนตกแล้ว ลมยังแรงอีก","id":"Selain hujan, anginnya juga kencang.","vi":"Trời mưa, hơn nữa gió còn mạnh.","ja":"雨が降っているうえに風も強いです。"}'::jsonb, 'topik-4'),
('-(으)ㄹ 뿐더러', '{"en":"\"not only ... but also (formal)\" — written/literary version of -(으)ㄹ 뿐만 아니라","es":"\"no solo ... sino además (formal)\" — versión escrita de -(으)ㄹ 뿐만 아니라","fr":"«non seulement ... mais en plus» (registre soutenu)","pt-BR":"\"não só ... como também (formal)\"","th":"\"ไม่เพียงแต่ ... ยัง ... (ทางการ)\"","id":"\"tidak hanya ... bahkan juga (formal)\"","vi":"\"không chỉ ... mà còn ... (trang trọng)\"","ja":"「〜のみならず / 〜だけでなく(改まり)」"}'::jsonb, '그 제품은 품질이 좋을 뿐더러 가격도 합리적이에요.', '{"en":"That product not only has good quality but also a reasonable price.","es":"Ese producto no solo tiene buena calidad, sino que además el precio es razonable.","fr":"Ce produit a non seulement une bonne qualité mais aussi un prix raisonnable.","pt-BR":"Esse produto não só tem boa qualidade como também preço razoável.","th":"สินค้านั้นนอกจากคุณภาพดีแล้ว ราคายังสมเหตุสมผล","id":"Produk itu kualitasnya bagus, harga pun masuk akal.","vi":"Sản phẩm đó không chỉ chất lượng tốt mà giá còn hợp lý.","ja":"その製品は品質が良いのみならず価格も合理的です。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 한편', '{"en":"\"on the one hand / meanwhile ...\" — two simultaneous aspects of one situation","es":"\"por un lado / mientras tanto ...\" — dos aspectos simultáneos","fr":"«d’une part / parallèlement»","pt-BR":"\"por um lado / ao mesmo tempo\"","th":"\"ในด้านหนึ่ง / ในขณะเดียวกัน ...\"","id":"\"di satu sisi / sementara itu ...\"","vi":"\"một mặt / đồng thời ...\"","ja":"「〜一方で / 〜と同時に」"}'::jsonb, '도시는 발전하는 한편 환경 문제도 심각해졌어요.', '{"en":"On the one hand the city develops; on the other, environmental problems have worsened.","es":"Por un lado la ciudad se ha desarrollado; al mismo tiempo, los problemas ambientales se agravaron.","fr":"D’une part la ville se développe ; d’autre part, les problèmes environnementaux s’aggravent.","pt-BR":"Por um lado a cidade se desenvolve; ao mesmo tempo, os problemas ambientais pioraram.","th":"เมืองพัฒนาขึ้น ขณะเดียวกันปัญหาสิ่งแวดล้อมก็แย่ลง","id":"Di satu sisi kota berkembang, di sisi lain masalah lingkungan memburuk.","vi":"Một mặt thành phố phát triển, mặt khác vấn đề môi trường trở nên nghiêm trọng.","ja":"都市は発展する一方で、環境問題も深刻になりました。"}'::jsonb, 'topik-4'),
('-은/는 물론이고', '{"en":"\"of course ..., and also ...\" — taken-for-granted plus addition","es":"\"por supuesto ..., y además ...\" — lo obvio más una adición","fr":"«bien entendu ..., et en plus ...»","pt-BR":"\"obviamente ..., e também ...\"","th":"\"... ไม่ต้องพูดถึง ... ก็ยัง ...\"","id":"\"... apalagi / sudah jelas ..., bahkan ...\"","vi":"\"khỏi cần nói ..., thậm chí còn ...\"","ja":"「〜はもちろん / 〜はもとより」"}'::jsonb, '한국어는 물론이고 영어도 잘해요.', '{"en":"They speak Korean of course, and English well too.","es":"Por supuesto sabe coreano, y también habla bien inglés.","fr":"Le coréen évidemment, et aussi très bien l’anglais.","pt-BR":"Coreano claro, e fala bem inglês também.","th":"ภาษาเกาหลีไม่ต้องพูดถึง ภาษาอังกฤษก็เก่งด้วย","id":"Bahasa Korea sudah pasti, bahasa Inggris pun lancar.","vi":"Tiếng Hàn khỏi nói, tiếng Anh cũng giỏi.","ja":"韓国語はもちろん、英語も上手です。"}'::jsonb, 'topik-4'),
('-는 바람에', '{"en":"\"because of (unexpected / negative) ...\" — sudden cause out of speaker’s control","es":"\"a causa de (inesperado, negativo) ...\" — fuera del control del hablante","fr":"«à cause de (imprévu / négatif)»","pt-BR":"\"por causa de (inesperado / negativo)\"","th":"\"พอดี ... เลย ... (ผลร้าย ฉับพลัน)\"","id":"\"gara-gara (kejadian tiba-tiba, biasanya buruk)\"","vi":"\"do ... (bất ngờ, thường xấu)\"","ja":"「〜したせいで / 〜したばかりに」— 突発・悪影響"}'::jsonb, '갑자기 비가 오는 바람에 옷이 다 젖었어요.', '{"en":"Because it suddenly rained, my clothes got soaked.","es":"A causa de que de pronto se puso a llover, la ropa se me empapó.","fr":"À cause de la pluie soudaine, mes vêtements étaient trempés.","pt-BR":"Por causa da chuva repentina, minha roupa ficou ensopada.","th":"พอจู่ ๆ ฝนตก เสื้อผ้าก็เปียกหมด","id":"Gara-gara hujan mendadak, baju saya basah kuyup.","vi":"Do bất ngờ trời mưa, quần áo tôi ướt sạch.","ja":"急に雨が降ったせいで服が全部濡れました。"}'::jsonb, 'topik-4'),
('-는 통에', '{"en":"\"in the chaos / din of ...\" — prolonged disorder causing a negative result","es":"\"en el alboroto de / a causa del lío de ...\" — situación caótica prolongada","fr":"«à cause du tumulte de / dans le chaos de»","pt-BR":"\"em meio à confusão de / por causa do tumulto de\"","th":"\"ในความวุ่นวายของ ... / เพราะ ... ทำให้วุ่น\"","id":"\"karena keributan / kekacauan ...\"","vi":"\"do sự lộn xộn của / vì cảnh hỗn loạn ...\"","ja":"「〜する騒ぎで / 〜のあおりで」— 長引く混乱"}'::jsonb, '아이가 우는 통에 잠을 못 잤어요.', '{"en":"With the child crying, I couldn’t sleep.","es":"Con el llanto del niño, no pude dormir.","fr":"Avec l’enfant qui pleurait, je n’ai pas pu dormir.","pt-BR":"Com o choro da criança, não consegui dormir.","th":"เด็กร้องไห้วุ่นวายไปหมด เลยนอนไม่หลับ","id":"Gara-gara anak menangis terus, saya tidak bisa tidur.","vi":"Vì đứa bé khóc loạn lên, tôi không ngủ được.","ja":"子供が泣き騒いだせいで眠れませんでした。"}'::jsonb, 'topik-4'),
('-(으)ㄹ 텐데', '{"en":"\"I suppose / must be ..., (but) ...\" — firm conjecture with background","es":"\"supongo que / debe de ser que ..., (pero) ...\" — conjetura firme con trasfondo","fr":"«je suppose que ... / il doit ..., (mais) ...»","pt-BR":"\"deve estar / acho que ..., (mas) ...\"","th":"\"คิดว่าน่าจะ ... (แต่) ...\"","id":"\"saya kira ... / pasti ..., (tapi) ...\"","vi":"\"chắc là ... (nhưng) ...\"","ja":"「〜だろうに / 〜はずなのに」"}'::jsonb, '피곤하실 텐데 좀 쉬세요.', '{"en":"You must be tired — please rest a bit.","es":"Debe de estar cansado, descanse un poco.","fr":"Vous devez être fatigué, reposez-vous un peu.","pt-BR":"Você deve estar cansado, descanse um pouco.","th":"คุณคงเหนื่อยมาก พักหน่อยนะคะ","id":"Pasti capek, istirahatlah sebentar.","vi":"Chắc anh/chị mệt rồi, nghỉ chút đi.","ja":"お疲れでしょうから少し休んでください。"}'::jsonb, 'topik-4'),
('-(으)ㄹ 리가 없다', '{"en":"\"it can’t be that / it’s impossible that ...\" — logical impossibility","es":"\"no puede ser que / es imposible que ...\" — imposibilidad lógica","fr":"«il n’est pas possible que / il ne se peut pas que»","pt-BR":"\"não pode ser que / é impossível que\"","th":"\"เป็นไปไม่ได้ที่ ... / ไม่มีทาง ...\"","id":"\"tidak mungkin / mustahil ...\"","vi":"\"không thể nào ... / không lẽ ...\"","ja":"「〜はずがない」"}'::jsonb, '그 사람이 거짓말을 할 리가 없어요.', '{"en":"It can’t be that they would lie.","es":"No puede ser que esa persona mienta.","fr":"Il n’est pas possible que cette personne mente.","pt-BR":"Não tem como essa pessoa estar mentindo.","th":"ไม่มีทางที่คนนั้นจะโกหก","id":"Tidak mungkin orang itu berbohong.","vi":"Không thể nào người ấy nói dối được.","ja":"あの人が嘘をつくはずがありません。"}'::jsonb, 'topik-4'),
('-(으)ㄹ걸 그랬다', '{"en":"\"should have / wish I had ...\" — regret for not doing in the past","es":"\"debería haber ... / ojalá hubiera ...\" — arrepentimiento pasado","fr":"«j’aurais dû ... / si seulement j’avais ...»","pt-BR":"\"deveria ter ... / quem me dera ter ...\"","th":"\"น่าจะ ... ตอนนั้น\" — เสียดายที่ไม่ทำ","id":"\"seharusnya ... / coba saja saya ...\"","vi":"\"đáng lẽ phải ... / giá mà tôi đã ...\"","ja":"「〜すればよかった」— 後悔"}'::jsonb, '우산을 가져올걸 그랬어요.', '{"en":"I should have brought an umbrella.","es":"Debería haber traído el paraguas.","fr":"J’aurais dû apporter un parapluie.","pt-BR":"Eu deveria ter trazido o guarda-chuva.","th":"น่าจะเอาร่มมาตั้งแต่แรก","id":"Seharusnya saya bawa payung.","vi":"Đáng lẽ tôi nên mang ô.","ja":"傘を持ってくればよかったです。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 것을 보니', '{"en":"\"judging from / seeing that ...\" — inference from observed evidence","es":"\"viendo que / juzgando por ...\" — deducción a partir de evidencia visible","fr":"«à voir / vu que ...» — déduction à partir d’une observation","pt-BR":"\"vendo que / a julgar por ...\" — dedução a partir de observação","th":"\"ดูจาก ... / ดูท่าทาง ...\"","id":"\"melihat ... / dilihat dari ...\"","vi":"\"thấy ... thì có lẽ / nhìn ... mà đoán ...\"","ja":"「〜のを見ると / 〜ことからすると」"}'::jsonb, '연락이 없는 걸 보니 못 오는 것 같아요.', '{"en":"Judging by the lack of contact, it seems they can’t come.","es":"Viendo que no hay noticias, parece que no puede venir.","fr":"Vu qu’il n’y a pas de nouvelles, il semble qu’il/elle ne peut pas venir.","pt-BR":"Pelo silêncio, parece que não vem.","th":"ดูจากที่ไม่มีติดต่อมา คงมาไม่ได้แล้ว","id":"Melihat tidak ada kabar, sepertinya tidak bisa datang.","vi":"Thấy không có liên lạc, có lẽ không đến được.","ja":"連絡がないところを見ると、来られないみたいです。"}'::jsonb, 'topik-4'),
('-다가', '{"en":"\"was doing X and then Y\" — interruption / shift; same subject","es":"\"estaba haciendo X y luego ...\" — interrupción / cambio de acción; mismo sujeto","fr":"«étais en train de ... puis ...» — interruption; même sujet","pt-BR":"\"estava fazendo ... e (de repente) ...\" — interrupção; mesmo sujeito","th":"\"กำลังทำ ... แล้วก็ ...\" — สลับการกระทำ, ผู้กระทำเดียวกัน","id":"\"sedang ... lalu ...\" — interupsi, subjek sama","vi":"\"đang ... thì ...\" — gián đoạn, cùng chủ ngữ","ja":"「〜していて / 〜している途中で」— 中断・転換"}'::jsonb, '공부하다가 잠이 들었어요.', '{"en":"I was studying and fell asleep.","es":"Estaba estudiando y me quedé dormido.","fr":"J’étudiais et je me suis endormi.","pt-BR":"Estava estudando e acabei pegando no sono.","th":"นั่งเรียนอยู่แล้วก็เผลอหลับ","id":"Sedang belajar, lalu ketiduran.","vi":"Đang học thì tôi ngủ thiếp đi.","ja":"勉強していて寝てしまいました。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 척하다', '{"en":"\"pretend / act as if ...\" — feigning a state or action","es":"\"fingir / hacer como si ...\" — aparentar un estado o acción","fr":"«faire semblant de / faire comme si»","pt-BR":"\"fingir / fazer de conta que\"","th":"\"แกล้งทำเป็น ...\"","id":"\"berpura-pura / pura-pura ...\"","vi":"\"giả vờ / làm như ...\"","ja":"「〜ふりをする」"}'::jsonb, '모르는 척했어요.', '{"en":"They pretended not to know.","es":"Fingió no saber.","fr":"Il/elle a fait semblant de ne pas savoir.","pt-BR":"Fingiu não saber.","th":"แกล้งทำเป็นไม่รู้","id":"Berpura-pura tidak tahu.","vi":"Người ấy giả vờ không biết.","ja":"知らないふりをしました。"}'::jsonb, 'topik-4'),
('-게 하다', '{"en":"\"make / let someone do ...\" — periphrastic causative; flexible with any verb","es":"\"hacer / dejar que alguien haga ...\" — causativo perifrástico, cualquier verbo","fr":"«faire / laisser ... faire» — causatif périphrastique","pt-BR":"\"fazer / deixar alguém fazer ...\" — causativo perifrástico","th":"\"ทำให้ / ปล่อยให้ ... ทำ ...\"","id":"\"membuat / membiarkan ... melakukan ...\"","vi":"\"khiến cho / để cho ... làm ...\"","ja":"「〜させる / 〜ようにする」— 迂言的使役"}'::jsonb, '선생님이 학생들을 공부하게 했어요.', '{"en":"The teacher made the students study.","es":"El profesor hizo que los estudiantes estudiaran.","fr":"Le professeur a fait étudier les élèves.","pt-BR":"O professor fez os alunos estudarem.","th":"อาจารย์ทำให้นักเรียนเรียนหนังสือ","id":"Guru menyuruh murid-murid belajar.","vi":"Cô giáo bắt học sinh học.","ja":"先生は学生たちに勉強させました。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 대로', '{"en":"\"as / just like / right after / as much as ...\" — manner, immediacy, or full extent","es":"\"tal como / en cuanto / todo lo que ...\" — modo, inmediatez o alcance","fr":"«comme / dès que / autant que»","pt-BR":"\"do jeito que / assim que / tudo que ...\"","th":"\"ตามที่ / ทันทีที่ / เท่าที่ ...\"","id":"\"sebagaimana / segera setelah / sebanyak ...\"","vi":"\"theo như / ngay khi / hết mức ...\"","ja":"「〜のとおりに / 〜しだい / 〜だけ」"}'::jsonb, '제가 하는 대로 따라 하세요.', '{"en":"Do as I do — follow me.","es":"Haga tal como yo hago.","fr":"Faites comme je fais.","pt-BR":"Faça como eu faço.","th":"ทำตามที่ฉันทำเลย","id":"Lakukan sebagaimana saya melakukannya.","vi":"Hãy làm theo như tôi làm.","ja":"私がするとおりにしてください。"}'::jsonb, 'topik-4'),
('-(으)ㄹ 만하다', '{"en":"\"worth doing / tolerable / bearable ...\" — value or sufficiency","es":"\"vale la pena / es tolerable / merece ...\" — valor o tolerabilidad","fr":"«ça vaut la peine de / c’est supportable»","pt-BR":"\"vale a pena / dá para aguentar / merece ...\"","th":"\"คุ้มที่จะ / พอจะ ... ได้ / น่า ...\"","id":"\"layak / pantas / cukup untuk ...\"","vi":"\"đáng để ... / có thể chấp nhận ...\"","ja":"「〜する価値がある / 〜できる程度」"}'::jsonb, '이 영화는 볼 만해요.', '{"en":"This movie is worth watching.","es":"Esta película vale la pena verla.","fr":"Ce film vaut la peine d’être vu.","pt-BR":"Esse filme vale a pena assistir.","th":"หนังเรื่องนี้น่าดู","id":"Film ini layak ditonton.","vi":"Phim này đáng xem.","ja":"この映画は見る価値があります。"}'::jsonb, 'topik-4'),
('-(으)ㄹ 정도로', '{"en":"\"to the point of / so ... that ...\" — extreme degree leading to a result","es":"\"hasta el punto de / tan ... que ...\" — grado extremo con consecuencia","fr":"«au point de / à tel point que»","pt-BR":"\"a ponto de / tanto ... que\"","th":"\"ถึงขนาดที่ ... / มากจน ...\"","id":"\"sampai-sampai / sehingga ...\"","vi":"\"đến mức ... / đến nỗi ...\"","ja":"「〜ほど / 〜ぐらい(程度)」"}'::jsonb, '걷기 힘들 정도로 발이 아파요.', '{"en":"My feet hurt so much I can hardly walk.","es":"Me duelen tanto los pies que apenas puedo caminar.","fr":"J’ai si mal aux pieds que j’ai du mal à marcher.","pt-BR":"Meus pés doem a ponto de eu mal conseguir andar.","th":"เท้าเจ็บจนแทบเดินไม่ไหว","id":"Kaki saya sakit sampai sulit berjalan.","vi":"Chân tôi đau đến mức khó đi nổi.","ja":"歩くのがつらいほど足が痛いです。"}'::jsonb, 'topik-4'),
('-(으)ㄹ 듯하다 / -(으)ㄹ 듯이', '{"en":"\"seems about to / as if ...\" — imminent appearance or simile of manner","es":"\"parece que va a / como si fuera a ...\" — apariencia inminente o símil","fr":"«on dirait que ... va / comme s’il allait»","pt-BR":"\"parece que vai / como se fosse ...\"","th":"\"ดูเหมือนจะ ... / ราวกับว่าจะ ...\"","id":"\"sepertinya hampir ... / seakan akan ...\"","vi":"\"có vẻ sắp ... / như thể ...\"","ja":"「〜しそうだ / 〜しそうに」— 切迫の様子・直喩"}'::jsonb, '비가 올 듯해요.', '{"en":"It looks like it’s about to rain.","es":"Parece que va a llover.","fr":"On dirait qu’il va pleuvoir.","pt-BR":"Parece que vai chover.","th":"ดูเหมือนฝนจะตก","id":"Sepertinya akan hujan.","vi":"Có vẻ trời sắp mưa.","ja":"雨が降りそうです。"}'::jsonb, 'topik-4'),
('-기에 앞서', '{"en":"\"before / prior to ...\" — formal; implies preparation or precedence","es":"\"antes de (formal) ...\" — implica preparación o precedencia","fr":"«avant de / préalablement à» — registre formel","pt-BR":"\"antes de (formal) ...\" — implica preparação ou precedência","th":"\"ก่อนที่จะ ... (ทางการ)\" — สื่อถึงการเตรียมพร้อม","id":"\"sebelum (formal)\" — menyiratkan persiapan","vi":"\"trước khi ... (trang trọng)\" — hàm ý chuẩn bị","ja":"「〜に先立ち / 〜に先立って」"}'::jsonb, '시작하기에 앞서 몇 가지 안내 말씀을 드리겠습니다.', '{"en":"Before we begin, I’ll share a few announcements.","es":"Antes de comenzar, les haré algunas indicaciones.","fr":"Avant de commencer, quelques annonces.","pt-BR":"Antes de começarmos, algumas orientações.","th":"ก่อนเริ่ม ขออนุญาตชี้แจงสักเล็กน้อยครับ","id":"Sebelum mulai, izinkan saya menyampaikan beberapa info.","vi":"Trước khi bắt đầu, xin thông báo vài điều.","ja":"始めるに先立ち、いくつかご案内申し上げます。"}'::jsonb, 'topik-4'),
('-(으)로서 / -(으)로써', '{"en":"\"as (in the role/capacity of)\" 로서 vs \"by means of / with\" 로써 — classic TOPIK pair","es":"\"como (en calidad de)\" 로서 vs \"mediante / con\" 로써 — distinción típica del TOPIK","fr":"«en tant que (rôle)» 로서 vs «au moyen de» 로써 — distinction classique du TOPIK","pt-BR":"\"como (na qualidade de)\" 로서 vs \"por meio de / com\" 로써 — par clássico do TOPIK","th":"\"ในฐานะ ...\" 로서 vs \"ด้วย / โดยวิธี ...\" 로써 — แยกคู่นี้ (ออกสอบ TOPIK)","id":"\"sebagai (peran)\" 로서 vs \"dengan / lewat (alat)\" 로써 — pasangan klasik TOPIK","vi":"\"với tư cách là\" 로서 vs \"bằng / qua (phương tiện)\" 로써 — cặp dễ nhầm trong TOPIK","ja":"「〜として(資格)」로서 vs 「〜によって(手段)」로써 — TOPIK頻出の区別"}'::jsonb, '선생님으로서 학생들에게 책임이 있어요.', '{"en":"As a teacher, I have responsibility toward my students.","es":"Como profesor, tengo responsabilidad hacia mis estudiantes.","fr":"En tant qu’enseignant, j’ai des responsabilités envers mes élèves.","pt-BR":"Como professor, tenho responsabilidade com meus alunos.","th":"ในฐานะอาจารย์ ฉันมีหน้าที่รับผิดชอบนักเรียน","id":"Sebagai guru, saya bertanggung jawab atas siswa.","vi":"Với tư cách là giáo viên, tôi có trách nhiệm với học sinh.","ja":"教師として学生たちに責任があります。"}'::jsonb, 'topik-4'),
('-았/었더라면', '{"en":"\"if I/you had ...\" — past counterfactual; speculates what would have happened","es":"\"si hubiera ...\" — contrafactual pasado; especula sobre lo que habría pasado","fr":"«si j’avais ... (au passé)» — irréel du passé","pt-BR":"\"se eu tivesse ...\" — contrafactual no passado","th":"\"ถ้า ... ในอดีต / หากตอนนั้น ...\" — สมมุติย้อนหลัง","id":"\"andai dulu saya ... / kalau saja ...\" — kontrafaktual lampau","vi":"\"giá mà (trước đây) đã ...\" — phản thực quá khứ","ja":"「〜していたら / 〜ていれば」— 過去の反実仮想"}'::jsonb, '그때 더 열심히 공부했더라면 시험에 합격했을 거예요.', '{"en":"If I had studied harder then, I would have passed the exam.","es":"Si hubiera estudiado más en ese momento, habría aprobado el examen.","fr":"Si j’avais étudié plus à l’époque, j’aurais réussi l’examen.","pt-BR":"Se eu tivesse estudado mais naquela época, teria passado na prova.","th":"ถ้าตอนนั้นตั้งใจเรียนมากกว่านี้ คงจะสอบผ่าน","id":"Andai dulu saya belajar lebih keras, pasti lulus.","vi":"Giá mà hồi đó tôi học chăm hơn, thì đã đỗ.","ja":"あのときもっと一生懸命勉強していたら、試験に受かっていたでしょう。"}'::jsonb, 'topik-4'),
('-ㄴ/는다는 것이', '{"en":"\"I meant to ... but ended up ...\" — unintended outcome by mistake","es":"\"quería hacer A pero (sin querer) hice B\" — resultado no intencional","fr":"«je voulais ... mais j’ai fini par ... (par erreur)»","pt-BR":"\"queria ... mas acabei ... (sem querer)\"","th":"\"จะ ... แต่กลับ ... โดยไม่ตั้งใจ\"","id":"\"niat A, malah B (tanpa sengaja)\"","vi":"\"định ..., không ngờ lại ...\"","ja":"「〜しようとして / 〜するつもりが」— うっかりの結果"}'::jsonb, '인사한다는 것이 그만 큰 소리로 외쳐 버렸어요.', '{"en":"I meant to say hi, but I ended up shouting.","es":"Quería saludar, pero acabé gritando sin querer.","fr":"Je voulais saluer, mais j’ai fini par crier.","pt-BR":"Eu queria cumprimentar, mas acabei gritando.","th":"จะทักทาย กลับเผลอตะโกนเสียงดัง","id":"Niatnya menyapa, malah berteriak keras.","vi":"Định chào hỏi, không ngờ lại la to lên.","ja":"挨拶しようとしたのに、大声を出してしまいました。"}'::jsonb, 'topik-4'),
('-고서야', '{"en":"\"only after / not until ...\" — necessary precondition; realized late","es":"\"solo después de / no hasta que ...\" — condición previa necesaria","fr":"«qu’après / pas avant que»","pt-BR":"\"só depois de / só quando ...\"","th":"\"พอ ... แล้วถึงจะ ...\" — เพิ่งจะรู้/เป็นไปได้","id":"\"baru setelah ... / barulah ...\"","vi":"\"chỉ sau khi ... mới ...\"","ja":"「〜してこそ / 〜してはじめて」"}'::jsonb, '실패하고서야 얼마나 어려운지 알았어요.', '{"en":"Only after failing did I realize how hard it was.","es":"Solo tras fracasar entendí lo difícil que era.","fr":"Ce n’est qu’après avoir échoué que j’ai compris à quel point c’était difficile.","pt-BR":"Só depois de fracassar é que percebi como era difícil.","th":"พอล้มเหลวแล้วถึงรู้ว่ามันยากแค่ไหน","id":"Baru setelah gagal, saya tahu betapa sulitnya.","vi":"Chỉ sau khi thất bại tôi mới biết khó đến đâu.","ja":"失敗してはじめてどれほど難しいか分かりました。"}'::jsonb, 'topik-4'),
('-아/어 빠지다', '{"en":"\"utterly / completely (negative)\" — intensifies a negative adjective","es":"\"de lo más ... (negativo)\" — intensifica un adjetivo negativo","fr":"«complètement / on ne peut plus» — intensification négative","pt-BR":"\"super / completamente ... (negativo)\" — intensifica adjetivo","th":"\"... จัด / ... อย่างที่สุด (เน้นทางลบ)\"","id":"\"sangat / paling ... (sifat buruk)\"","vi":"\"... cùng cực / ... hết mức (tiêu cực)\"","ja":"「〜きっている / 〜くさい(極端な悪い性質)」"}'::jsonb, '게을러 빠진 사람이에요.', '{"en":"They’re an utterly lazy person.","es":"Es una persona perezosísima.","fr":"C’est quelqu’un de complètement paresseux.","pt-BR":"É uma pessoa preguiçosa demais.","th":"เป็นคนขี้เกียจจัด","id":"Orangnya pemalas banget.","vi":"Anh ta lười cùng cực.","ja":"ものすごく怠けきった人です。"}'::jsonb, 'topik-4'),
('-아/어 치우다', '{"en":"\"get it over with / dispatch quickly ...\" — finish briskly, often a chore","es":"\"despachar / quitárselo de encima ...\" — acabar de una vez","fr":"«expédier / en finir avec ...»","pt-BR":"\"despachar / dar conta de uma vez ...\"","th":"\"จัดการให้เสร็จเด็ดขาด\"","id":"\"selesaikan sekaligus / beresin\"","vi":"\"giải quyết cho xong / dứt điểm ...\"","ja":"「〜してしまう」— てきぱき片付け"}'::jsonb, '숙제를 빨리 해 치웠어요.', '{"en":"I quickly got the homework over with.","es":"Hice la tarea rápidamente, de una vez.","fr":"J’ai expédié les devoirs.","pt-BR":"Despachei a lição rapidinho.","th":"จัดการการบ้านเสร็จในพริบตา","id":"Saya selesaikan PR sekaligus.","vi":"Tôi làm cho xong bài tập.","ja":"宿題をさっと済ませてしまいました。"}'::jsonb, 'topik-4'),
('-아/어 봤자 / 봐야', '{"en":"\"even if you try ..., it’s pointless\" — futile effort","es":"\"por más que / aunque lo intentes ..., no sirve\" — esfuerzo inútil","fr":"«même si tu ..., ça ne sert à rien»","pt-BR":"\"por mais que ..., não adianta\" — esforço inútil","th":"\"ต่อให้ ... ก็เปล่าประโยชน์\"","id":"\"meskipun ..., percuma saja\"","vi":"\"có ... cũng vô ích\"","ja":"「〜したところで(無駄)」"}'::jsonb, '지금 가 봤자 늦었어요.', '{"en":"Even if you go now, it’s too late.","es":"Aunque vayas ahora, ya es tarde.","fr":"Même si tu y vas maintenant, c’est trop tard.","pt-BR":"Mesmo que vá agora, já é tarde.","th":"ต่อให้ไปตอนนี้ก็สายเสียแล้ว","id":"Walaupun pergi sekarang, sudah terlambat.","vi":"Có đi bây giờ thì cũng muộn rồi.","ja":"今行ったところで遅いです。"}'::jsonb, 'topik-4'),
('-고 보다 / -고 보니(까)', '{"en":"\"after doing, I realized ...\" — retrospective discovery","es":"\"al hacerlo, me di cuenta de que ...\" — descubrimiento retrospectivo","fr":"«après l’avoir fait, je me suis rendu compte que ...»","pt-BR":"\"depois de fazer, percebi que ...\" — descoberta retrospectiva","th":"\"พอทำแล้วถึงรู้ว่า ...\"","id":"\"setelah dilakukan, baru sadar ...\"","vi":"\"làm rồi mới biết ...\"","ja":"「〜してみると / 〜してみたら(気づき)」"}'::jsonb, '사고 보니 너무 비쌌어요.', '{"en":"After buying it, I realized it was too expensive.","es":"Después de comprarlo me di cuenta de que era muy caro.","fr":"Après l’avoir acheté, je me suis aperçu que c’était trop cher.","pt-BR":"Depois de comprar, percebi que estava muito caro.","th":"พอซื้อมาแล้วถึงรู้ว่าแพงเกินไป","id":"Setelah dibeli, baru sadar terlalu mahal.","vi":"Mua xong tôi mới thấy quá đắt.","ja":"買ってみたら高すぎました。"}'::jsonb, 'topik-4'),
('-고 말겠다', '{"en":"\"I will ... no matter what\" — strong future determination (future use of -고 말다)","es":"\"lo haré sí o sí\" — determinación firme en futuro (G167 base en T3)","fr":"«je le ferai coûte que coûte» — détermination future","pt-BR":"\"vou ... custe o que custar\" — determinação no futuro","th":"\"จะ ... ให้ได้แน่นอน\" — เด็ดเดี่ยว","id":"\"akan ... pasti / mau bagaimanapun\"","vi":"\"nhất định sẽ ... cho bằng được\"","ja":"「絶対に〜してみせる」— -고 말다 の未来用法"}'::jsonb, '이번 시험에는 꼭 합격하고 말 거예요.', '{"en":"This time I’ll pass the exam no matter what.","es":"Esta vez aprobaré el examen sí o sí.","fr":"Cette fois, je réussirai l’examen coûte que coûte.","pt-BR":"Desta vez vou passar na prova de qualquer jeito.","th":"รอบนี้จะสอบให้ผ่านให้ได้","id":"Kali ini saya pasti lulus ujian, apa pun caranya.","vi":"Lần này nhất định tôi sẽ đỗ.","ja":"今回こそ必ず試験に合格してみせます。"}'::jsonb, 'topik-4'),
('-았/었어야 했다', '{"en":"\"should have ...\" — regret for past omission or wrong action","es":"\"debería haber + participio\" — arrepentimiento por omisión o error pasado","fr":"«j’aurais dû ...» — regret du passé","pt-BR":"\"deveria ter + particípio\" — arrependimento por ação passada","th":"\"น่าจะ ... ตั้งแต่ตอนนั้น\" — เสียดายเรื่องอดีต","id":"\"seharusnya saya ...\" — penyesalan masa lalu","vi":"\"đáng lẽ phải ...\" — hối tiếc về quá khứ","ja":"「〜すべきだった / 〜するべきだった」— 過去の後悔"}'::jsonb, '더 일찍 출발했어야 했어요.', '{"en":"I should have left earlier.","es":"Debería haber salido antes.","fr":"J’aurais dû partir plus tôt.","pt-BR":"Eu deveria ter saído mais cedo.","th":"น่าจะออกเดินทางก่อนหน้านี้","id":"Seharusnya saya berangkat lebih awal.","vi":"Đáng lẽ tôi phải đi sớm hơn.","ja":"もっと早く出発するべきでした。"}'::jsonb, 'topik-4'),
('-(으)ㄹ 테니까', '{"en":"\"since I’ll ... / it must be that ..., so ...\" — intention or supposition used as a reason","es":"\"como yo voy a / debe ser que ..., así que ...\" — intención o suposición que sirve de razón","fr":"«étant donné que je vais ... / il doit ..., alors ...»","pt-BR":"\"como vou ... / deve ser que ..., então ...\"","th":"\"ฉันจะ ... ฉะนั้น / น่าจะ ... ฉะนั้น ...\"","id":"\"saya akan ... / pasti ..., jadi ...\"","vi":"\"tôi sẽ ... / chắc là ..., nên ...\"","ja":"「〜だろうから / 〜するから(理由)」"}'::jsonb, '제가 음식을 준비할 테니까 너는 음료수를 가져와.', '{"en":"I’ll prepare the food, so you bring the drinks.","es":"Yo voy a preparar la comida, así que tú trae las bebidas.","fr":"Je vais préparer à manger, donc apporte les boissons.","pt-BR":"Eu vou preparar a comida, então traga as bebidas.","th":"ฉันจะเตรียมอาหารเอง เธอเอาเครื่องดื่มมานะ","id":"Saya akan menyiapkan makanan, jadi kamu bawa minuman.","vi":"Tôi sẽ chuẩn bị đồ ăn, nên bạn mang đồ uống đi.","ja":"私が料理を用意しますから、あなたは飲み物を持ってきてください。"}'::jsonb, 'topik-4'),
('-(으)ㄴ 채(로)', '{"en":"\"in the state of ...\" — keeping a previously achieved state during another action","es":"\"con / en el estado de ...\" — manteniendo el estado durante otra acción","fr":"«en gardant ... / avec ... encore ...»","pt-BR":"\"com ... ainda\" — mantendo o estado","th":"\"ทั้ง ... อยู่อย่างนั้น / โดยที่ ...\"","id":"\"dalam keadaan ... / sambil tetap ...\"","vi":"\"trong tình trạng ... / vẫn để nguyên ...\"","ja":"「〜したまま」"}'::jsonb, '신발을 신은 채로 들어왔어요.', '{"en":"They came in with their shoes still on.","es":"Entró con los zapatos puestos.","fr":"Il/elle est entré(e) avec ses chaussures.","pt-BR":"Entrou com os sapatos ainda nos pés.","th":"เดินเข้ามาทั้งที่ยังใส่รองเท้า","id":"Masuk dalam keadaan masih bersepatu.","vi":"Người ấy bước vào mà vẫn mang nguyên giày.","ja":"靴を履いたまま入ってきました。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 김에', '{"en":"\"while you’re at it / taking the opportunity to ...\" — secondary action on the fly","es":"\"ya que estás / aprovechando que ...\" — acción secundaria aprovechando la primera","fr":"«pendant que tu y es / tant qu’à ...»","pt-BR":"\"já que está / aproveitando que ...\"","th":"\"ในเมื่อ ... แล้ว ก็เลย ...\"","id":"\"mumpung sedang ..., sekalian ...\"","vi":"\"nhân tiện đang ..., ... luôn\"","ja":"「〜したついでに」"}'::jsonb, '마트에 간 김에 우유도 사 왔어요.', '{"en":"Since I went to the supermarket, I bought milk too.","es":"Ya que fui al supermercado, también traje leche.","fr":"Tant qu’à aller au supermarché, j’ai aussi pris du lait.","pt-BR":"Já que fui ao supermercado, trouxe leite também.","th":"ในเมื่อไปซูเปอร์แล้ว เลยซื้อนมมาด้วย","id":"Mumpung ke supermarket, sekalian beli susu.","vi":"Nhân tiện đi siêu thị, tôi mua luôn sữa.","ja":"スーパーに行ったついでに牛乳も買ってきました。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 길에', '{"en":"\"on the way (to/from) ...\" — doing something during a journey","es":"\"de camino a / en el camino ...\" — solo con verbos de movimiento","fr":"«en chemin / sur le trajet de ...»","pt-BR":"\"a caminho de / no caminho ...\"","th":"\"ระหว่างทาง / ตอนกำลังเดินทาง ...\"","id":"\"di tengah jalan / sambil pergi ...\"","vi":"\"trên đường (đi / về) ...\"","ja":"「〜する途中で」"}'::jsonb, '집에 오는 길에 빵을 샀어요.', '{"en":"On the way home I bought some bread.","es":"De camino a casa compré pan.","fr":"Sur le chemin du retour, j’ai acheté du pain.","pt-BR":"No caminho para casa comprei pão.","th":"ระหว่างทางกลับบ้านฉันแวะซื้อขนมปัง","id":"Di perjalanan pulang, saya beli roti.","vi":"Trên đường về tôi mua bánh mì.","ja":"家に帰る途中でパンを買いました。"}'::jsonb, 'topik-4'),
('-(으)ㄹ 겸', '{"en":"\"for X and also for Y\" — two purposes combined","es":"\"para X y también para Y\" — doble propósito combinado","fr":"«à la fois pour ... et pour ...»","pt-BR":"\"para X e também para Y\"","th":"\"เพื่อ ... และ ... ในคราวเดียว\"","id":"\"sekalian untuk ... dan ...\"","vi":"\"vừa để ... vừa để ...\"","ja":"「〜も〜も兼ねて」"}'::jsonb, '운동도 할 겸 친구도 만날 겸 공원에 갔어요.', '{"en":"I went to the park to both exercise and meet a friend.","es":"Fui al parque para hacer ejercicio y también ver a un amigo.","fr":"Je suis allé au parc à la fois pour faire du sport et voir un ami.","pt-BR":"Fui ao parque para me exercitar e também encontrar um amigo.","th":"ฉันไปสวนทั้งเพื่อออกกำลังกายและพบเพื่อน","id":"Saya ke taman sekalian olahraga dan bertemu teman.","vi":"Tôi ra công viên vừa tập thể dục vừa gặp bạn.","ja":"運動も兼ねて、友達にも会いに公園に行きました。"}'::jsonb, 'topik-4'),
('-느라(고)', '{"en":"\"because of being busy ...ing ...\" — same-subject simultaneous excuse","es":"\"por estar haciendo ...\" — excusa de acción simultánea, mismo sujeto","fr":"«à cause de / en train de ...»","pt-BR":"\"por estar ...ndo ...\" — desculpa simultânea","th":"\"เพราะมัวแต่ ... อยู่ ...\"","id":"\"karena (sedang) sibuk ...\"","vi":"\"vì mải ... nên ...\"","ja":"「〜していて(言い訳)」— 同主語・同時"}'::jsonb, '공부하느라고 잠을 못 잤어요.', '{"en":"I couldn’t sleep because I was busy studying.","es":"No pude dormir por estar estudiando.","fr":"Je n’ai pas pu dormir parce que j’étudiais.","pt-BR":"Não consegui dormir porque estava estudando.","th":"นอนไม่หลับเพราะมัวแต่อ่านหนังสือ","id":"Tidak bisa tidur karena sibuk belajar.","vi":"Vì mải học, tôi không ngủ được.","ja":"勉強していて寝られませんでした。"}'::jsonb, 'topik-4'),
('-길래', '{"en":"\"since I noticed / heard ... I did ...\" — personal-reaction cause (usually 1st-person 2nd clause)","es":"\"como vi / oí que ..., yo ...\" — causa por reacción personal (2ª cláusula en 1ª persona)","fr":"«comme j’ai vu / entendu que ..., j’ai ...»","pt-BR":"\"como vi / ouvi que ..., eu ...\"","th":"\"พอเห็น / ได้ยินว่า ... ฉันก็เลย ...\"","id":"\"karena saya lihat / dengar ..., saya pun ...\"","vi":"\"thấy / nghe ... nên tôi đã ...\"","ja":"「〜なので（私は）〜した」— 1人称反応"}'::jsonb, '비가 오길래 우산을 가져왔어요.', '{"en":"Since I saw it was raining, I brought an umbrella.","es":"Como vi que llovía, traje paraguas.","fr":"Comme je voyais qu’il pleuvait, j’ai pris un parapluie.","pt-BR":"Como vi que estava chovendo, trouxe guarda-chuva.","th":"พอเห็นว่าฝนตก ฉันเลยเอาร่มมา","id":"Karena lihat hujan, saya bawa payung.","vi":"Thấy trời mưa nên tôi mang ô đi.","ja":"雨が降っていたので傘を持ってきました。"}'::jsonb, 'topik-4'),
('-다가는', '{"en":"\"if you keep doing that ...\" — warning of a bad consequence","es":"\"si sigues haciendo eso ...\" — advertencia de consecuencia negativa","fr":"«si tu continues ainsi ...» — avertissement","pt-BR":"\"se continuar fazendo isso ...\" — aviso de consequência ruim","th":"\"ขืน ... อยู่ จะ ...\" — เตือนถึงผลร้าย","id":"\"kalau terus begitu, nanti ...\" — peringatan","vi":"\"cứ thế thì rồi sẽ ...\" — cảnh báo\",","ja":"「〜していたら(悪いことになる)」"}'::jsonb, '그렇게 늦게 자다가는 몸이 망가져요.', '{"en":"If you keep going to bed that late, your health will break down.","es":"Si sigues acostándote tan tarde, tu salud se va a estropear.","fr":"Si tu continues à te coucher si tard, tu vas te ruiner la santé.","pt-BR":"Se continuar dormindo tão tarde, sua saúde vai piorar.","th":"ขืนนอนดึกแบบนี้ ร่างกายจะพังเอา","id":"Kalau terus tidur larut, badan akan rusak.","vi":"Cứ ngủ muộn thế này, cơ thể sẽ hỏng mất.","ja":"そんなに夜更かししていたら、体を壊しますよ。"}'::jsonb, 'topik-4'),
('-다면서요? / -다며?', '{"en":"\"I heard that ..., right?\" — verify rumour; 다며? is the casual form","es":"\"me dijeron que ..., ¿es así?\" — verifica un rumor; 다며? es la forma informal","fr":"«on m’a dit que ..., non ?» — vérification, 다며? = familier","pt-BR":"\"ouvi dizer que ..., né?\" — verifica boato; 다며? casual","th":"\"ได้ยินว่า ... จริงไหม?\" — 다며? คือรูปกันเอง","id":"\"katanya ..., ya kan?\" — 다며? bentuk santai","vi":"\"nghe nói ... phải không?\" — 다며? thân mật","ja":"「〜だって？(口語) / 〜と聞きましたよ？」"}'::jsonb, '결혼했다며?', '{"en":"I heard you got married — really?","es":"Me dijeron que te casaste, ¿es verdad?","fr":"Il paraît que tu t’es marié(e), c’est vrai ?","pt-BR":"Soube que casou, é verdade?","th":"ได้ยินว่าคุณแต่งงานแล้วเหรอ","id":"Katanya kamu sudah menikah, ya?","vi":"Nghe nói bạn cưới rồi, đúng không?","ja":"結婚したんだって？"}'::jsonb, 'topik-4'),
('-다니(요)?', '{"en":"\"what do you mean ...?! / you must be kidding ...\" — disbelief or shock","es":"\"¿cómo que ...?! / ¡¿que ...?!\" — incredulidad o asombro","fr":"«comment ça ...?! / quoi ?!» — incrédulité","pt-BR":"\"como assim ...?! / o quê?!\" — incredulidade","th":"\"จะบอกว่า ... เหรอ?! ตกใจ\"","id":"\"masa ...?! / mana mungkin ...?!\"","vi":"\"sao lại ...?! / chuyện gì vậy?!\"","ja":"「〜だなんて？！」— 驚き・信じられない"}'::jsonb, '그가 갔다니요?', '{"en":"What do you mean he left?","es":"¡¿Cómo que se fue?!","fr":"Comment ça, il est parti ?!","pt-BR":"Como assim, ele foi embora?","th":"จะบอกว่าเขาไปแล้วเหรอ?!","id":"Masa dia sudah pergi?!","vi":"Sao lại bảo người ấy đi rồi?!","ja":"彼が行ったなんて？！"}'::jsonb, 'topik-4'),
('-다니까(요)', '{"en":"\"I’m telling you ...\" — insistent repetition, mild frustration","es":"\"¡ya te dije que ...! / ¡que sí!\" — repetición insistente con leve frustración","fr":"«je te dis que ...! / mais si !» — répétition insistante","pt-BR":"\"já disse que ...! / que sim!\" — repetição insistente","th":"\"ก็บอกแล้วไงว่า ...!\"","id":"\"sudah kubilang, ...!\"","vi":"\"đã bảo là ... rồi mà!\"","ja":"「〜だってば」— 強い繰り返し"}'::jsonb, '안 된다니까요!', '{"en":"I’m telling you, it’s not allowed!","es":"¡Que no, ya te dije!","fr":"Je te dis que c’est non !","pt-BR":"Já disse que não pode!","th":"ก็บอกแล้วว่าไม่ได้!","id":"Sudah kubilang tidak bisa!","vi":"Đã bảo là không được mà!","ja":"だめだってば！"}'::jsonb, 'topik-4'),
('-다고(요)?', '{"en":"\"you said ...?\" — echo with confirmation request, polite -요","es":"\"¿dijiste que ...?\" — pregunta de eco para confirmar","fr":"«vous avez dit que ... ?» — reprise pour confirmation","pt-BR":"\"você disse que ...?\" — pergunta-eco para confirmar","th":"\"คุณบอกว่า ... ใช่ไหม?\" — ขอยืนยัน","id":"\"katanya ...?\" — meminta konfirmasi","vi":"\"bạn bảo ... à?\" — yêu cầu xác nhận","ja":"「〜と言いましたか？」— 丁寧な聞き返し"}'::jsonb, '다시 한다고요?', '{"en":"You’re going to do it again, you say?","es":"¿Que lo vas a hacer de nuevo?","fr":"Tu dis que tu vas le refaire ?","pt-BR":"Você disse que vai fazer de novo?","th":"คุณว่าจะทำอีกครั้งเหรอ","id":"Katanya mau diulang?","vi":"Bạn bảo sẽ làm lại à?","ja":"もう一回やると言いましたか？"}'::jsonb, 'topik-4'),
('-다는 + N', '{"en":"modifier with embedded quote — \"the N that says ...\" (news, rumor, idea)","es":"modificador con cita incrustada — \"la N de que ...\" (noticia, rumor, idea)","fr":"modificateur avec citation — «la N selon laquelle ...»","pt-BR":"modificador com citação — \"a N de que ...\"","th":"รูปขยายที่ฝังคำพูด — \"N ที่ว่า ...\"","id":"pengubah dengan kutipan — \"N yang menyatakan ...\"","vi":"bổ ngữ chứa lời dẫn — \"N rằng ...\"","ja":"「〜という N」(伝聞・噂・考え)"}'::jsonb, '비가 온다는 소식을 들었어요.', '{"en":"I heard the news that it’s going to rain.","es":"Escuché la noticia de que va a llover.","fr":"J’ai entendu dire qu’il allait pleuvoir.","pt-BR":"Soube da notícia de que vai chover.","th":"ฉันได้ยินข่าวว่าฝนจะตก","id":"Saya dengar kabar bahwa akan hujan.","vi":"Tôi nghe tin nói trời sẽ mưa.","ja":"雨が降るという知らせを聞きました。"}'::jsonb, 'topik-4'),
('-다고 + 생각하다 / 믿다 / 듣다 / 보다 / 알다 / 느끼다 / 여기다', '{"en":"indirect quote + cognition verb — \"think / believe / hear / consider / know / feel / regard that ...\"","es":"cita indirecta + verbo de cognición — \"pensar / creer / escuchar / considerar / saber / sentir / tener por que ...\"","fr":"citation indirecte + verbe cognitif — «penser / croire / entendre / considérer / savoir / sentir / tenir pour que ...»","pt-BR":"citação indireta + verbo de cognição — \"pensar / acreditar / ouvir / considerar / saber / sentir / ter como que ...\"","th":"การพูดอ้อม + กริยาทางความคิด — \"คิดว่า / เชื่อว่า / ได้ยินว่า / มองว่า ...\"","id":"kutipan tak langsung + verba kognitif — \"berpikir / percaya / mendengar / menganggap bahwa ...\"","vi":"lời dẫn gián tiếp + động từ nhận thức — \"nghĩ / tin / nghe / coi / biết / cảm thấy rằng ...\"","ja":"間接話法 + 認識動詞「〜と思う / 信じる / 聞く / 見る / 知る / 感じる」"}'::jsonb, '그 사람이 정직하다고 믿어요.', '{"en":"I believe that person is honest.","es":"Creo que esa persona es honesta.","fr":"Je crois que cette personne est honnête.","pt-BR":"Acredito que essa pessoa é honesta.","th":"ฉันเชื่อว่าคนนั้นซื่อสัตย์","id":"Saya percaya orang itu jujur.","vi":"Tôi tin rằng người ấy thật thà.","ja":"あの人は正直だと信じています。"}'::jsonb, 'topik-4'),
('-나 보다', '{"en":"\"looks like ... / it seems ...\" — conjecture based on evidence (action verbs and 있다/없다)","es":"\"parece que / se ve que ...\" — conjetura basada en señales (verbos de acción y 있다/없다)","fr":"«on dirait que / il semble que ...» — conjecture (verbes d’action)","pt-BR":"\"parece que / dá para ver que ...\" — conjetura (verbos de ação)","th":"\"ดูเหมือนว่า ... (กับกริยาการกระทำ และ 있다/없다)\"","id":"\"sepertinya ... (verba aksi, 있다/없다)\"","vi":"\"có vẻ ... (với động từ hành động và 있다/없다)\"","ja":"「〜らしい / 〜のかな(動作動詞)」"}'::jsonb, '사람이 많이 모인 걸 보니 영화가 재미있나 봐요.', '{"en":"Seeing how crowded it is, the movie must be good.","es":"Por la cantidad de gente, parece que la película es buena.","fr":"À voir la foule, on dirait que le film est bon.","pt-BR":"Pela multidão, parece que o filme é bom.","th":"ดูจากที่คนเยอะแบบนี้ หนังคงจะสนุก","id":"Melihat ramainya, sepertinya filmnya bagus.","vi":"Thấy đông thế này, có lẽ phim hay.","ja":"人が多く集まっているところを見ると、映画が面白いみたいです。"}'::jsonb, 'topik-4'),
('-(으)ㄴ가 보다', '{"en":"\"looks like ...\" for adjectives (present) and verbs (past): -았/었나 보다","es":"versión adjetivo (presente) y verbo (pasado): -았/었나 보다","fr":"version adjectif / passé: -았/었나 보다","pt-BR":"versão adjetivo / pretérito: -았/었나 보다","th":"ใช้กับคำคุณศัพท์ (ปัจจุบัน) และกริยาในอดีต -았/었나 보다","id":"untuk adjektiva (kini) atau verba (lampau): -았/었나 보다","vi":"cho tính từ (hiện tại) hoặc động từ (quá khứ): -았/었나 보다","ja":"「〜ようだ(形容詞・過去)」— -았/었나 보다"}'::jsonb, '길이 막히는 걸 보니 사고가 났나 봐요.', '{"en":"There’s a traffic jam — looks like there was an accident.","es":"Como hay atasco, parece que hubo un accidente.","fr":"Vu l’embouteillage, on dirait qu’il y a eu un accident.","pt-BR":"Pelo trânsito, parece que aconteceu um acidente.","th":"ดูจากรถติด เดาว่าน่าจะเกิดอุบัติเหตุ","id":"Melihat macet begini, sepertinya ada kecelakaan.","vi":"Thấy kẹt xe thế này, có lẽ đã xảy ra tai nạn.","ja":"道が混んでいるので事故が起きたみたいです。"}'::jsonb, 'topik-4'),
('-(으)ㄹ걸(요)', '{"en":"with 요 (rising): \"I think / probably ...\"; without 요 (falling): \"should have ...\"","es":"con 요 (entonación alta): \"creo que / probablemente ...\"; sin 요 (descendente): \"debería haber ...\"","fr":"avec 요 (intonation montante): «probablement»; sans (descendante): «j’aurais dû»","pt-BR":"com 요 (subindo): \"talvez ...\"; sem 요 (descendo): \"deveria ter ...\"","th":"\"คงจะ ...\" (ขึ้นเสียง 요) / \"น่าจะ ... ตอนนั้น\" (ลง, เสียดาย)\"","id":"\"mungkin ...\" (요 naik) / \"seharusnya ...\" (turun, sesal)","vi":"\"chắc là ...\" (요 lên) / \"đáng lẽ phải ...\" (xuống, hối tiếc)","ja":"「〜だろうな / 〜すればよかった」— 推量 or 後悔"}'::jsonb, '그분도 오실걸요.', '{"en":"I think they’ll come too.","es":"Creo que él/ella también vendrá.","fr":"Je crois qu’il/elle viendra aussi.","pt-BR":"Acho que ele/ela também vem.","th":"คิดว่าคุณคนนั้นก็คงจะมาเหมือนกัน","id":"Sepertinya beliau juga akan datang.","vi":"Chắc người đó cũng sẽ đến.","ja":"あの方も来るでしょうね。"}'::jsonb, 'topik-4'),
('-(으)면서도', '{"en":"\"even while ..., still ...\" — same subject doing two contradictory things","es":"\"aunque al mismo tiempo ..., (sin embargo) ...\" — el mismo sujeto hace dos cosas contradictorias","fr":"«tout en ... pourtant ...» — même sujet, deux faits opposés","pt-BR":"\"ainda que ao mesmo tempo ..., ainda assim ...\" — mesmo sujeito","th":"\"ทั้งที่ก็ ... กลับยัง ...\" — ผู้กระทำเดียวกันทำสิ่งขัดแย้ง","id":"\"meskipun (saat) ..., tetap ...\" — subjek sama, bertentangan","vi":"\"vừa ... vừa ... mà vẫn ...\" — mâu thuẫn cùng chủ ngữ","ja":"「〜ながらも」— 同主語の矛盾"}'::jsonb, '알면서도 모르는 척해요.', '{"en":"They know but still pretend not to.","es":"Aunque sabe, finge no saber.","fr":"Tout en sachant, il/elle fait semblant de ne pas savoir.","pt-BR":"Mesmo sabendo, finge que não sabe.","th":"ทั้งที่รู้ ก็ยังแกล้งทำเป็นไม่รู้","id":"Padahal tahu, tetap pura-pura tidak tahu.","vi":"Biết mà vẫn giả vờ không biết.","ja":"知っていながら知らないふりをします。"}'::jsonb, 'topik-4'),
('-아/어다(가)', '{"en":"\"go/come do X and then carry the result to the next action ...\" — transfer of result","es":"\"ir/venir a hacer X y luego ...\" — transferencia del resultado","fr":"«faire X (ailleurs) puis ramener ...»","pt-BR":"\"ir/vir fazer X e depois ...\" — transferência do resultado","th":"\"ไปทำ ... แล้วเอามา ...\"","id":"\"pergi melakukan ... lalu (membawa ke) ...\"","vi":"\"đi làm X rồi đem (về) ...\"","ja":"「〜してきて / 〜してから(場所移動)」"}'::jsonb, '빵을 사다가 친구에게 줬어요.', '{"en":"I bought bread and gave it to my friend.","es":"Compré pan y se lo di a mi amigo.","fr":"J’ai acheté du pain et je l’ai donné à mon ami.","pt-BR":"Comprei pão e dei para meu amigo.","th":"ไปซื้อขนมปังมาให้เพื่อน","id":"Saya beli roti lalu kasih ke teman.","vi":"Tôi đi mua bánh mì rồi đưa cho bạn.","ja":"パンを買ってきて友達にあげました。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 만큼', '{"en":"\"as much as / in proportion to ...\" — equivalence of degree","es":"\"tanto como / en la medida en que ...\" — proporción o equivalencia","fr":"«autant que / proportionnellement à»","pt-BR":"\"tanto quanto / na medida em que ...\"","th":"\"เท่าที่ ... / มากเท่ากับ ...\"","id":"\"sebanding dengan / sebanyak ...\"","vi":"\"tương xứng với / chừng nào ... thì ...\"","ja":"「〜だけ / 〜分」— 程度の対応"}'::jsonb, '노력한 만큼 결과가 나올 거예요.', '{"en":"Results will come in proportion to the effort.","es":"Los resultados saldrán en la medida del esfuerzo.","fr":"Les résultats seront à la hauteur de l’effort fourni.","pt-BR":"Os resultados virão na medida do esforço.","th":"จะได้ผลลัพธ์เท่ากับที่พยายาม","id":"Hasil akan sebanding dengan usaha.","vi":"Cố gắng bao nhiêu thì kết quả bấy nhiêu.","ja":"努力した分だけ結果が出るでしょう。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 척 + V', '{"en":"\"pretending to ..., do ...\" — combine 척 with another action (cf. -(으)ㄴ/는 척하다 in T4)","es":"\"fingiendo ..., hacer ...\" — combinar 척 con otra acción (cf. G094 en T4)","fr":"«faisant semblant de ..., faire ...» — combiner avec une autre action","pt-BR":"\"fingindo ..., fazer ...\" — combinação com outra ação","th":"\"แกล้งทำเป็น ... แล้ว ...\"","id":"\"berpura-pura ..., kemudian ...\"","vi":"\"giả vờ ... rồi ...\"","ja":"「〜ふりをして〜する」(G094 の応用)"}'::jsonb, '못 들은 척 그냥 지나갔어요.', '{"en":"I just walked by, pretending I hadn’t heard.","es":"Pasé de largo fingiendo no haber escuchado.","fr":"Je suis passé sans m’arrêter, en faisant semblant de ne pas avoir entendu.","pt-BR":"Passei direto fingindo não ter ouvido.","th":"แกล้งทำเป็นไม่ได้ยิน แล้วเดินผ่านไปเฉย ๆ","id":"Saya berlalu saja, pura-pura tidak dengar.","vi":"Tôi giả vờ không nghe rồi đi luôn.","ja":"聞こえなかったふりをして通り過ぎました。"}'::jsonb, 'topik-4'),
('-았/었었-', '{"en":"remote / discontinued past — \"had been ..., but no longer ...\"","es":"pasado lejano / discontinuado — \"había ... (pero ya no)\"","fr":"passé éloigné / révolu — «avait été ... (mais plus maintenant)»","pt-BR":"pretérito remoto / descontinuado — \"tinha sido ... (mas já não)\"","th":"\"เคย ... (ตอนนี้ไม่ใช่แล้ว)\"","id":"\"dahulu pernah ... (kini sudah tidak)\"","vi":"\"trước đây từng ... (giờ thì không nữa)\"","ja":"「〜していた(が今は違う)」"}'::jsonb, '어렸을 때 부산에 살았었어요.', '{"en":"I lived in Busan as a child (but no longer).","es":"De niño viví en Busan (pero ya no).","fr":"Enfant, j’habitais à Busan (mais plus maintenant).","pt-BR":"Quando criança, eu morava em Busan (mas não mais).","th":"ตอนเด็กฉันเคยอยู่ที่ปูซาน (ตอนนี้ไม่อยู่แล้ว)","id":"Waktu kecil saya tinggal di Busan (sekarang tidak lagi).","vi":"Hồi nhỏ tôi từng sống ở Busan (giờ thì không nữa).","ja":"子供のころ釜山に住んでいました（今は違います）。"}'::jsonb, 'topik-4'),
('-지 않을 수 없다', '{"en":"\"cannot but / cannot help ...ing\" — unavoidable acknowledgement or action","es":"\"no puedo dejar de / no me queda más remedio que ...\" — inevitable","fr":"«je ne peux que / il faut bien ...» — inévitable","pt-BR":"\"não posso deixar de / não me resta senão ...\"","th":"\"อดไม่ได้ที่จะ ... / จำเป็นต้อง ...\"","id":"\"tidak bisa tidak ... / mau tidak mau ...\"","vi":"\"không thể không ... / đành phải ...\"","ja":"「〜ざるを得ない / 〜ないわけにはいかない」"}'::jsonb, '그 결과에 놀라지 않을 수 없었어요.', '{"en":"I couldn’t help being surprised by that result.","es":"No pude evitar sorprenderme ante ese resultado.","fr":"Je n’ai pu m’empêcher d’être surpris par ce résultat.","pt-BR":"Não pude deixar de me surpreender com aquele resultado.","th":"อดไม่ได้ที่จะประหลาดใจกับผลลัพธ์นั้น","id":"Mau tidak mau saya terkejut dengan hasilnya.","vi":"Tôi không thể không bất ngờ trước kết quả đó.","ja":"その結果に驚かずにはいられませんでした。"}'::jsonb, 'topik-4'),
('-(으)ㄴ/는 데(에)다(가)', '{"en":"\"on top of ... / and besides ...\" — compact additive accumulation","es":"\"además de / encima de eso ...\" — acumulación compacta","fr":"«en plus de ... / qui plus est»","pt-BR":"\"além de ... / por cima ...\" — adição compacta","th":"\"นอกจาก ... แล้ว ยัง ...\"","id":"\"selain ..., juga ...\"","vi":"\"vừa ... lại còn ...\"","ja":"「〜うえに(短縮)」"}'::jsonb, '늦게 일어난 데다가 차도 막혀서 지각했어요.', '{"en":"On top of waking up late, the traffic was bad, so I was late.","es":"Encima de levantarme tarde, había atasco; por eso llegué tarde.","fr":"En plus de me lever tard, il y avait du trafic, donc j’étais en retard.","pt-BR":"Além de acordar tarde, ainda peguei trânsito, então me atrasei.","th":"ตื่นสายแล้วยังเจอรถติดอีก เลยมาสาย","id":"Selain bangun kesiangan, jalan juga macet, jadi terlambat.","vi":"Vừa dậy muộn lại còn kẹt xe, nên tôi đến muộn.","ja":"寝坊したうえに渋滞もあって遅刻しました。"}'::jsonb, 'topik-4'),
('-아/어다(가) 주다', '{"en":"\"go and do X, then give the result to someone\" — fetch-and-give compound","es":"\"ir a hacer X y luego dárselo a alguien\" — compuesto de movimiento + favor","fr":"«aller faire X et le rapporter à qqn»","pt-BR":"\"ir fazer X e dar para alguém\"","th":"\"ไปทำ ... แล้วเอามาให้ ...\"","id":"\"pergi melakukan ... lalu memberikannya untuk ...\"","vi":"\"đi làm X rồi đưa cho ...\"","ja":"「〜してきてあげる」"}'::jsonb, '약을 사다 줄게요.', '{"en":"I’ll go buy the medicine for you.","es":"Voy a comprarte la medicina.","fr":"Je vais t’acheter le médicament.","pt-BR":"Vou comprar o remédio para você.","th":"จะไปซื้อยามาให้","id":"Saya akan belikan obat untuk kamu.","vi":"Tôi sẽ đi mua thuốc cho bạn.","ja":"薬を買ってきてあげますね。"}'::jsonb, 'topik-4'),
('-(으)면 -(으)ㄹ수록', '{"en":"\"the more X, the more Y ...\" — emphatic version of -(으)ㄹ수록 (G083)","es":"\"cuanto más X, más Y ...\" — versión enfática de -(으)ㄹ수록 (G083)","fr":"«plus X, plus Y» — version emphatique de -(으)ㄹ수록","pt-BR":"\"quanto mais X, mais Y\" — versão enfática de -(으)ㄹ수록","th":"\"ยิ่ง ... ก็ยิ่ง ...\" — รูปเน้นของ G083","id":"\"semakin ..., semakin ...\" — versi penegasan G083","vi":"\"càng ... thì càng ...\" — biến thể nhấn mạnh","ja":"「〜ば〜ほど(強調)」— G083 の強形"}'::jsonb, '한국어는 공부하면 공부할수록 재미있어요.', '{"en":"The more I study Korean, the more I enjoy it.","es":"Cuanto más estudio coreano, más me gusta.","fr":"Plus j’étudie le coréen, plus c’est intéressant.","pt-BR":"Quanto mais estudo coreano, mais gosto.","th":"ภาษาเกาหลีเรียนยิ่งมาก ยิ่งสนุก","id":"Bahasa Korea semakin dipelajari, semakin menyenangkan.","vi":"Tiếng Hàn càng học càng thấy thú vị.","ja":"韓国語は勉強すればするほど面白いです。"}'::jsonb, 'topik-4'),
('-았/었어야', '{"en":"\"should have ...\" — short colloquial regret form (cf. G221 -았/었어야 했다)","es":"\"debería haber ...\" — forma corta coloquial (cf. G221)","fr":"«j’aurais dû ...» — forme courte familière","pt-BR":"\"deveria ter ...\" — forma curta coloquial","th":"\"น่าจะ ... ตั้งแต่ตอนนั้น (รูปย่อ)\"","id":"\"seharusnya ... (bentuk pendek)\"","vi":"\"đáng lẽ phải ... (rút gọn)\"","ja":"「〜すればよかった(短縮)」"}'::jsonb, '좀 더 일찍 출발했어야지.', '{"en":"You should have left a bit earlier.","es":"Deberías haber salido un poco antes.","fr":"Tu aurais dû partir un peu plus tôt.","pt-BR":"Você deveria ter saído mais cedo.","th":"น่าจะออกเดินทางให้เร็วกว่านี้","id":"Mestinya kamu berangkat lebih awal.","vi":"Đáng lẽ bạn phải đi sớm hơn.","ja":"もう少し早く出発すればよかったのに。"}'::jsonb, 'topik-4'),
('-더니', '{"en":"\"I observed X, and then Y happened (as expected)\" — evidential past with consequence","es":"\"observé X y resultó Y\" — evidencial pasado con resultado esperado","fr":"«j’avais remarqué X, et puis Y est arrivé»","pt-BR":"\"observei X, e então Y\" — evidencial passado com consequência","th":"\"ก่อนหน้านี้ ... จึง / กลายเป็น ...\" — บอกเล่าจากที่ได้สังเกตเอง","id":"\"tadinya ... lalu jadi ...\" — observasi langsung di masa lalu","vi":"\"trước thì ... rồi sau đó ...\" — chứng kiến rồi có kết quả","ja":"「〜していたが / 〜だったが(観察)」— 直接観察 → 結果"}'::jsonb, '아침에 구름이 많더니 지금 비가 오네요.', '{"en":"It was cloudy this morning, and now sure enough it’s raining.","es":"Esta mañana había muchas nubes; ahora, como cabía esperar, llueve.","fr":"Il y avait beaucoup de nuages ce matin, et voilà qu’il pleut.","pt-BR":"De manhã tinha muitas nuvens; agora, como esperado, está chovendo.","th":"ตอนเช้ามีเมฆเยอะ ตอนนี้ฝนก็ตก","id":"Tadi pagi awannya banyak, sekarang ternyata hujan.","vi":"Sáng nay nhiều mây, giờ thì trời mưa thật.","ja":"朝から雲が多かったと思ったら、今は雨が降っていますね。"}'::jsonb, 'topik-5'),
('-던', '{"en":"modifier — past habit or unfinished action (\"used to / was X-ing\")","es":"modificador — hábito pasado o acción interrumpida (\"solía / estaba ...\")","fr":"modificateur — habitude passée ou action inachevée («qui … autrefois»)","pt-BR":"modificador — hábito passado ou ação inacabada (\"costumava / estava ...\")","th":"รูปขยาย — เคยทำ (ตอนนี้เลิกแล้ว) / ยังทำไม่จบ","id":"pengubah — kebiasaan lampau / aksi tak selesai (\"dulu suka / sedang ...\")","vi":"bổ ngữ — thói quen cũ / hành động dở dang (\"từng / đang ...\")","ja":"連体形「〜していた / よく〜した(今はしない)」"}'::jsonb, '어렸을 때 자주 가던 공원이에요.', '{"en":"It’s the park I used to go to often as a child.","es":"Es el parque al que solía ir a menudo de niño.","fr":"C’est le parc où j’allais souvent enfant.","pt-BR":"É o parque ao qual eu costumava ir quando criança.","th":"นี่คือสวนที่ตอนเด็ก ๆ ฉันมักจะไปบ่อย","id":"Ini taman tempat saya dulu sering main waktu kecil.","vi":"Đây là công viên hồi nhỏ tôi hay đến.","ja":"子供のころよく行っていた公園です。"}'::jsonb, 'topik-5'),
('-더니만', '{"en":"\"sure enough / just as I expected\" — emphatic version of -더니","es":"\"como yo decía / tal como esperaba\" — versión enfática de -더니","fr":"«je le savais bien que ...» — variante emphatique de -더니","pt-BR":"\"como eu dizia / sabia que ...\" — variante enfática de -더니","th":"\"นี่ไง บอกแล้วว่า ...\" — เน้นจาก -더니","id":"\"benar saja ...\" — versi penegasan dari -더니","vi":"\"đúng như tôi đoán ...\" — biến thể nhấn mạnh của -더니","ja":"「やっぱり〜していたっけ」— -더니 の強調"}'::jsonb, '연습을 열심히 하더니만 역시 잘 하네요.', '{"en":"They practiced hard, and sure enough they’re doing great.","es":"Estuvo practicando mucho y, tal como pensaba, lo hace muy bien.","fr":"Il s’était entraîné dur ; sans surprise, il s’en sort très bien.","pt-BR":"Treinou muito e, como eu esperava, está indo muito bem.","th":"ฝึกซ้อมหนัก สุดท้ายก็ทำได้ดีจริง ๆ","id":"Latihan terus, dan benar saja hasilnya bagus.","vi":"Tập luyện chăm chỉ, đúng như tôi đoán, giờ giỏi thật.","ja":"一生懸命練習していたから、やっぱり上手ですね。"}'::jsonb, 'topik-5'),
('-(으)ㄹ지언정', '{"en":"\"even if it means ..., I’d rather than ...\" — firm determination, prefers hardship to giving in","es":"\"aunque tenga que ..., antes que ...\" — determinación firme; prefiere lo difícil","fr":"«même au prix de ..., plutôt que de ...» — résolution ferme","pt-BR":"\"ainda que ..., antes que ...\" — determinação firme","th":"\"ถึงจะ ... ก็ ไม่ ...\" — เด็ดเดี่ยว ยอมลำบาก","id":"\"meskipun harus ..., tetap tidak ...\" — tekad bulat","vi":"\"thà ... còn hơn ...\" — quyết tâm dứt khoát","ja":"「〜することがあっても / 〜してでも(決して〜ない)」"}'::jsonb, '굶을지언정 그 사람한테 도움을 요청하지 않겠어요.', '{"en":"Even if I starve, I won’t ask that person for help.","es":"Aunque pase hambre, no le pediré ayuda a esa persona.","fr":"Quitte à mourir de faim, je ne lui demanderai pas d’aide.","pt-BR":"Mesmo que eu passe fome, não vou pedir ajuda a essa pessoa.","th":"ต่อให้อดข้าวก็ไม่ขอความช่วยเหลือจากคนนั้น","id":"Walau kelaparan, saya tidak akan minta tolong padanya.","vi":"Thà nhịn đói chứ tôi không nhờ vả người ấy.","ja":"飢えてでも、あの人に助けは求めません。"}'::jsonb, 'topik-5'),
('-(으)ㄹ지라도', '{"en":"\"even if / even though ...\" — formal/literary concession","es":"\"aunque / incluso si ...\" — concesión formal o literaria","fr":"«même si / quand même» — registre formel / littéraire","pt-BR":"\"mesmo que / ainda que ...\" — concessão formal/literária","th":"\"แม้ว่าจะ ... ก็ ... (ทางการ)\"","id":"\"meskipun ... (formal / sastra)\"","vi":"\"dù cho ... (trang trọng / văn chương)\"","ja":"「〜であれ / 〜であろうとも(改まり)」"}'::jsonb, '힘들지라도 포기하지 않겠어요.', '{"en":"Even if it’s hard, I won’t give up.","es":"Aunque sea difícil, no me rendiré.","fr":"Même si c’est difficile, je n’abandonnerai pas.","pt-BR":"Mesmo que seja difícil, não vou desistir.","th":"แม้จะลำบาก ฉันจะไม่ยอมแพ้","id":"Meskipun sulit, saya tidak akan menyerah.","vi":"Dù khó khăn tôi cũng không bỏ cuộc.","ja":"たとえつらくても、諦めません。"}'::jsonb, 'topik-5'),
('-고도', '{"en":"\"even after fully ... still ...\" — concession with action already completed","es":"\"aunque habiendo ..., aun así ...\" — concesión con acción ya hecha","fr":"«même après avoir ... encore ...» — concession action accomplie","pt-BR":"\"mesmo tendo ..., ainda ...\" — concessão com ação concluída","th":"\"แม้จะ ... แล้ว ก็ยัง ...\"","id":"\"meskipun sudah ..., masih ...\"","vi":"\"đã ... rồi mà vẫn ...\"","ja":"「〜してもなお / 〜したうえに(なお)」"}'::jsonb, '이렇게 많이 먹고도 배가 고파요?', '{"en":"You’re hungry even after eating this much?","es":"¿Tienes hambre a pesar de haber comido tanto?","fr":"Tu as encore faim après avoir tant mangé ?","pt-BR":"Mesmo tendo comido tanto, ainda está com fome?","th":"กินไปขนาดนี้แล้วยังหิวอีกเหรอ","id":"Sudah makan sebanyak ini masih lapar?","vi":"Ăn nhiều thế rồi vẫn đói à?","ja":"こんなにたくさん食べたのにまだお腹が空いていますか？"}'::jsonb, 'topik-5'),
('-느니 (차라리)', '{"en":"\"rather than ..., I’d prefer ...\" — preference between two undesirable options; often with 차라리","es":"\"antes que ..., prefiero ...\" — preferencia entre dos males; a menudo con 차라리","fr":"«plutôt que de ..., je préfère ...» — souvent avec 차라리","pt-BR":"\"em vez de ..., prefiro ...\" — preferência entre opções ruins; frequentemente com 차라리","th":"\"แทนที่จะ ... สู้ ... ดีกว่า\" — มักมี 차라리","id":"\"daripada ..., lebih baik ...\" — sering pakai 차라리","vi":"\"thà ... còn hơn (làm) ...\" — thường với 차라리","ja":"「〜するくらいなら / むしろ〜したほうがいい」"}'::jsonb, '거짓말을 하느니 차라리 아무 말도 안 하겠어요.', '{"en":"Rather than lie, I’d rather say nothing at all.","es":"Antes que mentir, prefiero no decir nada.","fr":"Plutôt que de mentir, je préfère ne rien dire.","pt-BR":"Em vez de mentir, prefiro não dizer nada.","th":"แทนที่จะโกหก ฉันยอมไม่พูดอะไรเลย","id":"Daripada bohong, lebih baik diam saja.","vi":"Thà không nói gì còn hơn nói dối.","ja":"嘘をつくくらいなら、何も言わない方がいいです。"}'::jsonb, 'topik-5'),
('-(으)면 몰라도', '{"en":"\"unless / except if ...\" — only condition under which the claim wouldn’t hold","es":"\"a no ser que / salvo si ...\" — única condición que cambiaría el caso","fr":"«à moins que / sauf si ...»","pt-BR":"\"a menos que / a não ser que ...\"","th":"\"นอกจาก ... แล้ว / ยกเว้นว่า ...\"","id":"\"kecuali kalau / kalau bukan karena ...\"","vi":"\"trừ phi / nếu không thì ...\"","ja":"「〜なら別だが / 〜でないかぎり」"}'::jsonb, '기적이 일어나면 몰라도 불가능한 일이에요.', '{"en":"Unless a miracle happens, it’s impossible.","es":"A no ser que ocurra un milagro, es imposible.","fr":"À moins qu’un miracle ne se produise, c’est impossible.","pt-BR":"A não ser que aconteça um milagre, é impossível.","th":"นอกจากจะเกิดปาฏิหาริย์ ไม่อย่างนั้นเป็นไปไม่ได้","id":"Kecuali ada keajaiban, mustahil terjadi.","vi":"Trừ phi xảy ra phép màu, chuyện đó không thể.","ja":"奇跡が起きるならともかく、不可能な話です。"}'::jsonb, 'topik-5'),
('-다손 치더라도', '{"en":"\"even granting / supposing that ...\" — argumentative concession; formal","es":"\"aun concediendo que / aun suponiendo que ...\" — concesión argumentativa, formal","fr":"«à supposer même que ...» — concession argumentative formelle","pt-BR":"\"mesmo admitindo que / supondo que ...\" — concessão argumentativa","th":"\"ต่อให้สมมุติว่า ... ก็ ...\" — แบบเชิงโต้แย้ง, ทางการ","id":"\"meskipun seandainya ..., tetap ...\"","vi":"\"cứ cho là ..., (vẫn) ...\"","ja":"「〜だと仮にしても」— 議論的譲歩"}'::jsonb, '그것이 사실이다손 치더라도 용서할 수 없어요.', '{"en":"Even granting that it’s true, I can’t forgive it.","es":"Aun concediendo que sea verdad, no puedo perdonarlo.","fr":"À supposer même que ce soit vrai, je ne peux pas pardonner.","pt-BR":"Mesmo admitindo que seja verdade, não consigo perdoar.","th":"ต่อให้สมมุติว่ามันเป็นเรื่องจริง ก็ยังให้อภัยไม่ได้","id":"Meskipun seandainya itu benar, tetap tidak bisa saya maafkan.","vi":"Cứ cho là chuyện đó đúng đi, tôi cũng không tha thứ.","ja":"それが事実だとしても、許せません。"}'::jsonb, 'topik-5'),
('-(으)ㄴ/는 셈이다', '{"en":"\"amounts to / comes to be ...\" — approximate equivalence","es":"\"viene a ser / equivale a ...\" — equivalencia aproximada","fr":"«cela revient à / autant dire que»","pt-BR":"\"vem a ser / é como se ...\" — equivalência aproximada","th":"\"ก็คือ ... โดยรวม / เท่ากับว่า ...\"","id":"\"berarti / praktisnya ... = ...\"","vi":"\"coi như / xem ra / tính ra là ...\"","ja":"「〜ようなものだ / 〜することになる」"}'::jsonb, '하루에 세 번 먹으니까 규칙적으로 먹는 셈이에요.', '{"en":"Eating three times a day, it amounts to eating regularly.","es":"Como como tres veces al día, viene a ser que como con regularidad.","fr":"Comme je mange trois fois par jour, ça revient à manger régulièrement.","pt-BR":"Como como três vezes ao dia, é como se comesse regularmente.","th":"กินวันละสามมื้อ ก็เท่ากับกินสม่ำเสมอ","id":"Makan tiga kali sehari berarti praktisnya teratur.","vi":"Ăn ba bữa một ngày, coi như là ăn đều đặn.","ja":"一日三回食べているので、規則正しく食べているようなものです。"}'::jsonb, 'topik-5'),
('-(으)ㄹ 따름이다', '{"en":"\"merely / all I (can) do is ...\" — humble or resigned limitation","es":"\"simplemente / lo único que (puedo) ...\" — limitación humilde o resignada","fr":"«je ne fais que / il n’y a plus qu’à ...» — humilité ou résignation","pt-BR":"\"apenas / só me resta ...\" — humildade ou resignação","th":"\"เพียงแต่ ... เท่านั้น\" — ทำได้แค่นี้ (ถ่อมตน)","id":"\"hanya bisa ... / yang dapat saya lakukan hanyalah ...\"","vi":"\"chỉ có thể ... mà thôi\" — khiêm tốn / cam chịu","ja":"「〜するばかりだ / 〜するほかない(改まり)」"}'::jsonb, '그저 감사할 따름이에요.', '{"en":"I can only feel grateful.","es":"Solo puedo estar agradecido.","fr":"Je ne peux qu’être reconnaissant.","pt-BR":"Só me resta agradecer.","th":"ทำได้แค่ขอบคุณเท่านั้น","id":"Saya hanya bisa berterima kasih.","vi":"Tôi chỉ biết cảm ơn mà thôi.","ja":"ただただ感謝するばかりです。"}'::jsonb, 'topik-5'),
('-(으)ㄹ 뿐이다', '{"en":"\"merely / just ...\" — restrictive limitation; nothing beyond","es":"\"no es más que / simplemente ...\" — limitación restrictiva","fr":"«rien d’autre que / juste ...»","pt-BR":"\"apenas / nada além de ...\" — limitação restritiva","th":"\"แค่ ... เท่านั้น / ไม่ใช่อะไรมากกว่านั้น\"","id":"\"sekadar / hanya ...\"","vi":"\"chỉ ... mà thôi\"","ja":"「〜だけだ / 〜にすぎない」"}'::jsonb, '저는 제 의견을 말했을 뿐이에요.', '{"en":"I merely expressed my opinion.","es":"Simplemente expresé mi opinión, nada más.","fr":"Je n’ai fait que donner mon avis.","pt-BR":"Eu apenas dei a minha opinião.","th":"ฉันแค่บอกความคิดเห็นของตัวเองเท่านั้น","id":"Saya hanya menyampaikan pendapat saya.","vi":"Tôi chỉ nói ra ý kiến của mình thôi.","ja":"私は自分の意見を言ったにすぎません。"}'::jsonb, 'topik-5'),
('에 불과하다', '{"en":"\"is no more than / just ...\" — minimization with N","es":"\"no es más que / apenas ...\" — minimización con sustantivo","fr":"«ne représente que / n’est qu’un(e) simple ...»","pt-BR":"\"não passa de / é apenas um(a) ...\" — minimização com substantivo","th":"\"เป็นเพียง ... เท่านั้น\"","id":"\"tidak lebih dari (sekadar) ...\"","vi":"\"chẳng qua chỉ là / không hơn ...\"","ja":"「〜にすぎない」(名詞)"}'::jsonb, '이것은 시작에 불과해요.', '{"en":"This is no more than the beginning.","es":"Esto no es más que el comienzo.","fr":"Ce n’est qu’un début.","pt-BR":"Isso não passa do começo.","th":"นี่เป็นเพียงจุดเริ่มต้นเท่านั้น","id":"Ini tidak lebih dari sebuah permulaan.","vi":"Đây chẳng qua chỉ là khởi đầu.","ja":"これは始まりにすぎません。"}'::jsonb, 'topik-5'),
('-기 나름이다', '{"en":"\"depends on how you do it\" — outcome hinges on the approach","es":"\"depende de cómo se haga / es cuestión de ...\" — el resultado depende del enfoque","fr":"«tout dépend de la façon dont ...»","pt-BR":"\"depende de como se faz ...\" — resultado depende da abordagem","th":"\"ขึ้นอยู่กับวิธีทำ ...\"","id":"\"tergantung bagaimana ...\"","vi":"\"tùy cách mình làm ...\"","ja":"「〜次第だ」— 取り組み方による"}'::jsonb, '어떤 일이든 하기 나름이에요.', '{"en":"Any task is what you make of it.","es":"Cualquier trabajo depende de cómo lo enfoques.","fr":"Tout travail dépend de la façon dont on l’aborde.","pt-BR":"Qualquer trabalho depende de como você o encara.","th":"งานใด ๆ ก็ขึ้นอยู่กับวิธีทำของเรา","id":"Pekerjaan apa pun tergantung cara mengerjakannya.","vi":"Việc nào cũng tùy cách mình làm.","ja":"どんな仕事もやり方次第です。"}'::jsonb, 'topik-5'),
('-(으)ㄹ 나위가 없다', '{"en":"\"needless to say / there’s no room for doubt ...\" — obviousness","es":"\"huelga decir que / está de más decir que ...\" — obviedad","fr":"«inutile de dire que / cela va sans dire»","pt-BR":"\"escusado é dizer que / nem é preciso dizer ...\"","th":"\"ไม่จำเป็นต้องพูดว่า ...\"","id":"\"tidak perlu dikatakan lagi ...\"","vi":"\"khỏi cần nói / hiển nhiên là ...\"","ja":"「〜までもない / 言うまでもない」"}'::jsonb, '건강이 중요하다는 것은 더 말할 나위도 없죠.', '{"en":"It goes without saying that health is important.","es":"Que la salud es importante está de más decirlo.","fr":"Inutile de dire que la santé est importante.","pt-BR":"Nem precisa dizer que saúde é importante.","th":"ไม่ต้องพูดเลยว่าสุขภาพสำคัญแค่ไหน","id":"Tidak perlu dikatakan lagi bahwa kesehatan itu penting.","vi":"Khỏi cần nói thì sức khỏe vẫn quan trọng.","ja":"健康が大事なのは言うまでもありません。"}'::jsonb, 'topik-5'),
('-(으)ㄹ 것 없이', '{"en":"\"no need to ..., just ...\" — dispenses with the unnecessary","es":"\"sin necesidad de ..., simplemente ...\" — descarta lo innecesario","fr":"«sans avoir besoin de ..., il suffit de ...»","pt-BR":"\"sem necessidade de ..., simplesmente ...\"","th":"\"ไม่ต้อง ... แค่ ...\"","id":"\"tidak perlu ..., cukup ...\"","vi":"\"không cần ..., cứ ... đi\"","ja":"「〜することなく / 〜するまでもなく」"}'::jsonb, '걱정할 것 없이 그냥 해보세요.', '{"en":"No need to worry — just give it a try.","es":"Sin preocuparte, simplemente inténtalo.","fr":"Sans t’inquiéter, essaie tout simplement.","pt-BR":"Sem se preocupar, é só tentar.","th":"ไม่ต้องกังวล ลองทำดูก่อน","id":"Tidak perlu khawatir, coba saja.","vi":"Khỏi lo, cứ thử đi.","ja":"心配せずに、とにかくやってみてください。"}'::jsonb, 'topik-5'),
('-(으)면 그만이다', '{"en":"\"just X is enough / X and that’s that ...\" — minimal sufficiency, sometimes dismissive","es":"\"con X basta / con eso es suficiente ...\" — suficiencia mínima, a veces desdeñoso","fr":"«il suffit de ... / une fois ... fait, c’est terminé»","pt-BR":"\"basta ... / só precisa ... e pronto\"","th":"\"แค่ ... ก็พอ / ทำเท่านี้ก็จบ\"","id":"\"cukup ... saja sudah selesai\"","vi":"\"chỉ cần ... là xong\"","ja":"「〜ばそれでいい / 〜ばすむ」"}'::jsonb, '그냥 솔직하게 말하면 그만이에요.', '{"en":"Just be honest and that’s enough.","es":"Con ser honesto basta.","fr":"Il suffit d’être honnête, c’est tout.","pt-BR":"Basta ser honesto e pronto.","th":"แค่พูดตรง ๆ ก็พอแล้ว","id":"Cukup bicara jujur saja.","vi":"Chỉ cần thành thật là đủ.","ja":"正直に言えばそれですみます。"}'::jsonb, 'topik-5'),
('-기에', '{"en":"\"because / since ...\" — formal, often based on observation; reasoned consequence","es":"\"porque / dado que ...\" — formal, basado en observación; consecuencia razonada","fr":"«parce que / du moment que ...» — formel, raisonné","pt-BR":"\"porque / dado que ...\" — formal, baseado em observação","th":"\"เพราะว่า ... (ทางการ, อิงสิ่งที่เห็น)\"","id":"\"karena / lantaran ... (formal)\"","vi":"\"vì / do ... (trang trọng, dựa trên quan sát)\"","ja":"「〜ので / 〜だから(改まり、観察に基づく)」"}'::jsonb, '가격이 저렴하기에 많이 샀어요.', '{"en":"Since the price was cheap, I bought a lot.","es":"Como el precio era barato, compré bastante.","fr":"Le prix étant bas, j’en ai acheté beaucoup.","pt-BR":"Como o preço estava barato, comprei bastante.","th":"เพราะราคาถูก ฉันเลยซื้อเยอะ","id":"Karena harganya murah, saya beli banyak.","vi":"Vì giá rẻ nên tôi mua nhiều.","ja":"価格が安かったので、たくさん買いました。"}'::jsonb, 'topik-5'),
('-(으)ㄴ/는 탓에', '{"en":"\"because of (negatively) / it’s the fault of ...\" — always with bad outcome","es":"\"por culpa de / a causa de ...\" — siempre con resultado negativo","fr":"«à cause de / par la faute de ...» — résultat négatif","pt-BR":"\"por culpa de / por causa de ...\" — sempre com resultado negativo","th":"\"เพราะ ... (สิ่งไม่ดี) / โทษ ...\"","id":"\"gara-gara ... / akibat ...\" — selalu hasil buruk","vi":"\"do tại ... / vì ... (kết quả xấu)\"","ja":"「〜せいで」— 悪い結果"}'::jsonb, '늦게 자는 탓에 항상 피곤해요.', '{"en":"I’m always tired because I go to bed late.","es":"Por culpa de acostarme tarde, siempre estoy cansado.","fr":"À cause de mes nuits tardives, je suis toujours fatigué.","pt-BR":"Por causa de dormir tarde, sempre estou cansado.","th":"เพราะนอนดึก เลยเหนื่อยตลอด","id":"Gara-gara tidur larut, saya selalu lelah.","vi":"Vì hay ngủ muộn nên tôi luôn mệt.","ja":"夜更かしのせいでいつも疲れています。"}'::jsonb, 'topik-5'),
('-(으)로 인해(서)', '{"en":"\"due to / as a result of ...\" — formal/written cause; news and academic style","es":"\"debido a / como consecuencia de ...\" — causa formal/escrita","fr":"«à cause de / en raison de ...» — registre formel / écrit","pt-BR":"\"devido a / em razão de ...\" — causa formal, escrita","th":"\"เนื่องด้วย / อันเป็นผลจาก ... (ทางการ)\"","id":"\"akibat / disebabkan oleh ... (formal)\"","vi":"\"do / vì lý do ... (trang trọng)\"","ja":"「〜により / 〜によって」— 改まり・新聞語調"}'::jsonb, '폭우로 인해 도로가 통제됐어요.', '{"en":"Due to heavy rain, the road was closed.","es":"Debido a las lluvias torrenciales, la carretera fue bloqueada.","fr":"En raison de fortes pluies, la route a été fermée.","pt-BR":"Devido às chuvas fortes, a estrada foi interditada.","th":"อันเนื่องมาจากฝนตกหนัก ถนนถูกปิด","id":"Akibat hujan deras, jalan ditutup.","vi":"Do mưa lớn, đường đã bị phong tỏa.","ja":"豪雨により道路が通行止めになりました。"}'::jsonb, 'topik-5'),
('-고자', '{"en":"\"with the purpose of / intending to ...\" — formal/literary intention","es":"\"con el propósito de / con la intención de ...\" — formal/literario","fr":"«dans le but de / en vue de» — registre formel","pt-BR":"\"com o propósito de / a fim de ...\" — formal/literário","th":"\"เพื่อ / ด้วยจุดประสงค์ที่จะ ... (ทางการ)\"","id":"\"dengan maksud / demi ... (formal)\"","vi":"\"nhằm / với mục đích ... (trang trọng)\"","ja":"「〜しようと / 〜すべく(改まり)」"}'::jsonb, '더 나은 세상을 만들고자 노력하고 있습니다.', '{"en":"We are striving to build a better world.","es":"Nos esforzamos con el propósito de crear un mundo mejor.","fr":"Nous nous efforçons de bâtir un monde meilleur.","pt-BR":"Estamos nos esforçando a fim de criar um mundo melhor.","th":"พวกเรากำลังพยายามเพื่อสร้างโลกที่ดีกว่า","id":"Kami berupaya demi membangun dunia yang lebih baik.","vi":"Chúng tôi đang nỗ lực nhằm tạo ra một thế giới tốt đẹp hơn.","ja":"より良い世界を作るべく努力しています。"}'::jsonb, 'topik-5'),
('-(으)ㄴ/는 나머지', '{"en":"\"as a result of (extreme) ...\" — overflow leading to unexpected outcome","es":"\"tanto que / de tanto ...\" — exceso que provoca un resultado","fr":"«à force de ... / au point que»","pt-BR":"\"de tanto ... / a ponto de ...\" — excesso com resultado","th":"\"จนถึงขั้น ... / มากเกินไปจน ...\"","id":"\"saking ... / akibat terlalu ...\"","vi":"\"vì ... quá đến nỗi ...\"","ja":"「〜あまり」— 程度の超過 → 結果"}'::jsonb, '너무 웃은 나머지 배가 아팠어요.', '{"en":"I laughed so much that my stomach hurt.","es":"Me reí tanto que me dolió el estómago.","fr":"À force de rire, j’en ai eu mal au ventre.","pt-BR":"De tanto rir, minha barriga doeu.","th":"หัวเราะจนปวดท้อง","id":"Saking banyak tertawa, perut saya sakit.","vi":"Tôi cười nhiều đến nỗi đau bụng.","ja":"笑いすぎてお腹が痛くなりました。"}'::jsonb, 'topik-5'),
('-(으)ㄹ 지경이다', '{"en":"\"on the verge of / to the point of ...\" — extreme situation, usually negative","es":"\"al borde de / hasta el punto de ...\" — situación extrema, suele ser negativa","fr":"«au point de / sur le point de ...» — situation extrême","pt-BR":"\"a ponto de / no limite de ...\" — situação extrema","th":"\"แทบจะ ... / ถึงขั้น ...\"","id":"\"hampir ... / sampai-sampai ...\"","vi":"\"đến mức suýt ... / sắp sửa ...\"","ja":"「〜しそうなほどだ / 〜する寸前だ」"}'::jsonb, '너무 바빠서 쓰러질 지경이에요.', '{"en":"I’m so busy I’m about to collapse.","es":"Estoy tan ocupado que estoy al borde del colapso.","fr":"Je suis tellement occupé que je suis au bord de l’effondrement.","pt-BR":"Estou tão ocupado que estou a ponto de desmaiar.","th":"ยุ่งจนแทบจะหมดแรงล้มไปแล้ว","id":"Saking sibuk, saya hampir tumbang.","vi":"Tôi bận đến mức sắp ngã quỵ.","ja":"忙しすぎて倒れそうな状態です。"}'::jsonb, 'topik-5'),
('-는 커녕', '{"en":"\"far from ... ; let alone ...\" — strong contrast with negative result","es":"\"lejos de ... / ni siquiera ...\" — contraste fuerte con resultado negativo","fr":"«loin de ... / encore moins ...»","pt-BR":"\"longe de ... / quanto mais ...\"","th":"\"ไม่ใช่แค่ไม่ ... แต่กลับ ...\"","id":"\"jangankan ..., malah ...\"","vi":"\"chứ đừng nói ... / nói gì đến ...\"","ja":"「〜どころか」— 強い反転"}'::jsonb, '감사하기는 커녕 화를 냈어요.', '{"en":"Far from being grateful, they got angry.","es":"Lejos de agradecer, se enojó.","fr":"Loin de remercier, il/elle s’est mis(e) en colère.","pt-BR":"Longe de agradecer, ficou bravo(a).","th":"จะขอบคุณก็ไม่ขอบคุณ กลับโกรธอีก","id":"Jangankan terima kasih, malah marah.","vi":"Đừng nói cảm ơn, người ấy còn nổi giận.","ja":"感謝するどころか怒り出しました。"}'::jsonb, 'topik-5'),
('-든지', '{"en":"\"whether ... or / no matter ...\" — indifference to alternatives","es":"\"ya sea ... o / sin importar ...\" — indiferencia entre opciones","fr":"«que ... ou ... / quel que soit»","pt-BR":"\"seja ... ou ... / não importa ...\"","th":"\"ไม่ว่าจะ ... หรือ ...\"","id":"\"baik ... maupun ... / apa pun ...\"","vi":"\"dù ... hay ...\"","ja":"「〜であろうと / 〜にせよ」— 無関心の選択"}'::jsonb, '어디에 가든지 연락해 주세요.', '{"en":"No matter where you go, please contact me.","es":"Vayas a donde vayas, avísame.","fr":"Où que tu ailles, contacte-moi.","pt-BR":"Aonde quer que vá, me avise.","th":"ไม่ว่าจะไปไหน บอกฉันด้วยนะ","id":"Ke mana pun kamu pergi, kabari saya.","vi":"Dù bạn đi đâu, hãy báo cho tôi.","ja":"どこへ行こうと連絡してください。"}'::jsonb, 'topik-5'),
('-(으)ㄴ 끝에', '{"en":"\"after much / at the end of ...\" — result after prolonged effort or process","es":"\"después de mucho / al final de ...\" — resultado tras un proceso largo","fr":"«au bout de / après bien des ...»","pt-BR":"\"depois de muito / ao cabo de ...\"","th":"\"หลังจาก ... อันยาวนาน\"","id":"\"setelah lama / akhirnya setelah ...\"","vi":"\"sau bao nhiêu ... cuối cùng ...\"","ja":"「〜の末に」"}'::jsonb, '오랜 고민 끝에 결정했어요.', '{"en":"After much deliberation, I decided.","es":"Después de mucha reflexión, decidí.","fr":"Au bout d’une longue réflexion, j’ai décidé.","pt-BR":"Após muita reflexão, decidi.","th":"หลังจากคิดอยู่นาน ฉันก็ตัดสินใจ","id":"Setelah lama berpikir, akhirnya saya memutuskan.","vi":"Sau bao đắn đo, tôi đã quyết định.","ja":"長い悩みの末に決めました。"}'::jsonb, 'topik-5'),
('-자', '{"en":"\"as soon as ... (literary)\" — narrative variant of -자마자","es":"\"en cuanto (literario)\" — variante narrativa de -자마자","fr":"«à peine ... que / dès que (littéraire)»","pt-BR":"\"assim que (literário)\" — variante narrativa de -자마자","th":"\"พอ ... ก็ (วรรณกรรม)\" — ใช้ในเรื่องเล่า","id":"\"begitu ... (sastrawi)\"","vi":"\"vừa ... thì (văn chương)\"","ja":"「〜するや / 〜したとたん(文語)」"}'::jsonb, '그가 들어오자 모두가 일어났어요.', '{"en":"As soon as he came in, everyone stood up.","es":"En cuanto él entró, todos se levantaron.","fr":"Dès qu’il est entré, tout le monde s’est levé.","pt-BR":"Assim que ele entrou, todos se levantaram.","th":"พอเขาเข้ามาทุกคนก็ลุกขึ้น","id":"Begitu dia masuk, semua orang berdiri.","vi":"Vừa anh ấy bước vào, mọi người đều đứng lên.","ja":"彼が入ってくるや、皆が立ち上がりました。"}'::jsonb, 'topik-5'),
('-고서', '{"en":"\"after (emphatic) ...\" — stronger sequence than -고; near-synonym of -고 나서","es":"\"después de (con énfasis) ...\" — secuencia más fuerte que -고","fr":"«après avoir ... (emphatique)»","pt-BR":"\"depois de (com ênfase) ...\" — sequência mais forte que -고","th":"\"หลังจาก ... (เน้น)\" — เน้นมากกว่า -고","id":"\"setelah ... (penekanan)\" — lebih kuat dari -고","vi":"\"sau khi ... (nhấn mạnh)\" — mạnh hơn -고","ja":"「〜してから(強調)」"}'::jsonb, '그 말을 듣고서 화가 났어요.', '{"en":"After hearing that, I got angry.","es":"Tras escuchar eso, me enojé.","fr":"En entendant cela, je me suis fâché.","pt-BR":"Depois de ouvir isso, fiquei com raiva.","th":"พอได้ยินคำนั้นก็โกรธขึ้นมา","id":"Setelah mendengar itu, saya marah.","vi":"Sau khi nghe câu đó tôi đã nổi giận.","ja":"その言葉を聞いて腹が立ちました。"}'::jsonb, 'topik-5'),
('-다 못해', '{"en":"\"to the point that one can no longer ...\" — surpasses a limit","es":"\"hasta el punto de no poder más / tanto que ya ...\" — supera el límite","fr":"«à ne plus pouvoir / au point que ...»","pt-BR":"\"a ponto de não poder mais / tanto que já ...\" — passa do limite","th":"\"... จนทนไม่ไหว / ... จนสุด ...\"","id":"\"sampai tidak tahan / sampai-sampai ...\"","vi":"\"đến mức không còn ... nữa / ... cùng cực ...\"","ja":"「〜きれず / 〜の極み」"}'::jsonb, '기다리다 못해 그냥 갔어요.', '{"en":"I couldn’t wait any longer, so I just left.","es":"De tanto esperar, terminé yéndome.","fr":"À force d’attendre, je suis simplement parti.","pt-BR":"De tanto esperar, acabei indo embora.","th":"รอจนทนไม่ไหว เลยไปก่อน","id":"Sampai tidak tahan menunggu, akhirnya saya pergi saja.","vi":"Đợi không nổi nữa, tôi đành bỏ đi.","ja":"待ちきれず、もう帰りました。"}'::jsonb, 'topik-5'),
('-다고 해서', '{"en":"\"because (they) say ...\" — action based on second-hand information","es":"\"porque (dicen) que ...\" — actuar basado en información de terceros","fr":"«parce qu’on dit que / comme on a dit que ...»","pt-BR":"\"porque dizem que ...\" — agir baseado em informação alheia","th":"\"เพราะได้ยินว่า ...\"","id":"\"karena katanya ...\"","vi":"\"vì nghe nói rằng ...\"","ja":"「〜だと言うので / 〜らしいので」"}'::jsonb, '그 식당이 맛있다고 해서 가 봤어요.', '{"en":"Since they said the restaurant was good, I went to try it.","es":"Como dicen que ese restaurante está rico, fui a probarlo.","fr":"Comme on disait que ce restaurant était bon, j’y suis allé.","pt-BR":"Como diziam que o restaurante era bom, fui experimentar.","th":"เพราะได้ยินว่าร้านอร่อย เลยไปลอง","id":"Karena katanya restorannya enak, saya coba ke sana.","vi":"Vì nghe nói nhà hàng đó ngon, tôi đã đến thử.","ja":"あの店が美味しいと言うので、行ってみました。"}'::jsonb, 'topik-5'),
('-다고 해도', '{"en":"\"even if (they) say ...\" — concession over reported information","es":"\"aunque digan que ...\" — concesión sobre información reportada","fr":"«même si on dit que ...»","pt-BR":"\"mesmo que digam que ...\" — concessão sobre informação alheia","th":"\"แม้จะบอกว่า ... ก็ ...\"","id":"\"meskipun (orang) bilang ..., tetap ...\"","vi":"\"dù có nói rằng ... thì cũng ...\"","ja":"「〜だと言われても」"}'::jsonb, '비싸다고 해도 사야 해요.', '{"en":"Even if they say it’s expensive, I have to buy it.","es":"Aunque digan que es caro, tengo que comprarlo.","fr":"Même si on dit que c’est cher, je dois l’acheter.","pt-BR":"Mesmo que digam que é caro, preciso comprar.","th":"แม้จะบอกว่าแพงก็ต้องซื้อ","id":"Meskipun katanya mahal, tetap harus dibeli.","vi":"Dù có nói là đắt thì tôi cũng phải mua.","ja":"高いと言われても買わなければなりません。"}'::jsonb, 'topik-5'),
('-다는 게', '{"en":"\"the (very) fact of being said to ...\" — nominalized indirect quote","es":"\"lo de que / el hecho de que ...\" — cita indirecta nominalizada","fr":"«le fait de dire que / le fait que ...»","pt-BR":"\"o fato de (dizerem) que ...\" — citação nominalizada","th":"\"การที่บอกว่า ... / เรื่องที่ว่า ...\"","id":"\"hal bahwa / kenyataan bahwa ...\"","vi":"\"việc bảo rằng ... / chuyện rằng ...\"","ja":"「〜ということ(が)」— 引用名詞化"}'::jsonb, '결혼한다는 것은 큰 결정이에요.', '{"en":"Getting married is a big decision.","es":"Lo de casarse es una gran decisión.","fr":"Se marier, c’est une grande décision.","pt-BR":"Casar-se é uma grande decisão.","th":"การแต่งงานเป็นการตัดสินใจครั้งใหญ่","id":"Keputusan menikah itu besar.","vi":"Việc kết hôn là một quyết định lớn.","ja":"結婚するというのは大きな決断です。"}'::jsonb, 'topik-5'),
('-다는데 / -다더라 / -다더니', '{"en":"\"they say ..., but / I heard that ... / it was said that ... and indeed ...\" — combos of indirect + context","es":"\"dicen que ..., pero / oí que ... / decían que ... y resultó que ...\" — combinaciones del indirecto","fr":"«on dit que ... mais / on m’a dit que ... / on disait que ..., et effectivement ...»","pt-BR":"\"dizem que ..., mas / ouvi que ... / diziam que ... e de fato ...\"","th":"\"ได้ยินว่า ... แต่ / เขาเล่าว่า ... / เคยว่ากันว่า ... ก็เป็นจริง ...\"","id":"\"katanya ... tetapi / saya dengar ... / sempat dibilang ..., dan memang ...\"","vi":"\"nghe nói ... mà / nghe đồn ... / trước nói ... và quả nhiên ...\"","ja":"間接話法の拡張「〜だそうだけど / 〜だってさ / 〜と言っていたが」"}'::jsonb, '친구가 아프다는데 병문안 갈까요?', '{"en":"I heard my friend is sick — shall we visit?","es":"Mi amigo dice que está enfermo, ¿vamos a visitarlo?","fr":"On m’a dit que mon ami est malade, on va le voir ?","pt-BR":"Disseram que meu amigo está doente, vamos visitá-lo?","th":"ได้ยินว่าเพื่อนป่วย ไปเยี่ยมกันไหม","id":"Katanya teman saya sakit, mau jenguk?","vi":"Nghe nói bạn tôi ốm, mình đi thăm nhé?","ja":"友達が病気だそうだけど、お見舞いに行きますか？"}'::jsonb, 'topik-5'),
('-다고 할까 봐 / -다고 할 줄 알았다', '{"en":"\"in case they’d say ... / I thought they’d say ...\" — anticipation of reported speech","es":"\"por miedo a que digan ... / pensé que dirían que ...\" — anticipo del discurso ajeno","fr":"«de peur qu’on dise / je pensais qu’on dirait que ...»","pt-BR":"\"com medo de que digam ... / achei que diriam que ...\"","th":"\"กลัวว่าจะบอกว่า ... / คิดว่าเขาจะบอกว่า ...\"","id":"\"khawatir akan dikatakan ... / saya pikir dia akan bilang ...\"","vi":"\"sợ rằng người ấy sẽ nói ... / tôi tưởng họ sẽ nói ...\"","ja":"「〜と言うかと思って / 〜と言うだろうと思った」"}'::jsonb, '모른다고 할까 봐 대답을 준비했어요.', '{"en":"I prepared an answer in case they’d say I didn’t know.","es":"Preparé una respuesta por miedo a que dijera que no sabía.","fr":"J’ai préparé une réponse de peur qu’on dise que je ne savais pas.","pt-BR":"Preparei uma resposta com medo de que dissessem que eu não sabia.","th":"เตรียมคำตอบไว้ กลัวว่าจะบอกว่าฉันไม่รู้","id":"Saya siapkan jawaban, khawatir bilang saya tidak tahu.","vi":"Tôi chuẩn bị câu trả lời, sợ rằng sẽ bảo tôi không biết.","ja":"知らないと言われると思って答えを用意しました。"}'::jsonb, 'topik-5'),
('-(으)ㄹ까 싶다', '{"en":"\"I wonder if / I’m thinking of ...\" — inner doubt or vacillating plan","es":"\"me pregunto si / estoy pensando en ...\" — duda interior o plan vacilante","fr":"«je me demande si / je pense à ...»","pt-BR":"\"fico pensando se / estou pensando em ...\" — dúvida interior","th":"\"สงสัยว่า ... / กำลังคิดว่าจะ ...\"","id":"\"berpikir-pikir mungkin / ragu-ragu apakah ...\"","vi":"\"tự hỏi liệu / đang nghĩ rằng ...\"","ja":"「〜かと思う / 〜ようかと迷う」"}'::jsonb, '한국에 갈까 싶어요.', '{"en":"I’m thinking of going to Korea.","es":"Estoy pensando en ir a Corea.","fr":"Je me dis que j’irais bien en Corée.","pt-BR":"Estou pensando em ir para a Coreia.","th":"กำลังคิดว่าจะไปเกาหลี","id":"Saya sedang pikir-pikir mau ke Korea.","vi":"Tôi đang nghĩ chắc sẽ đi Hàn Quốc.","ja":"韓国に行こうかと思います。"}'::jsonb, 'topik-5'),
('-지 싶다', '{"en":"\"I suppose / I’d say ...\" — moderate, reflective supposition","es":"\"creo / me parece que ...\" — suposición moderada y reflexiva","fr":"«je suppose que / je dirais que ...»","pt-BR":"\"acho / me parece que ...\" — suposição moderada","th":"\"คิดว่า ... (เบา ๆ ครุ่นคิด)\"","id":"\"saya rasa / kiranya ...\"","vi":"\"tôi nghĩ rằng / có lẽ ...\"","ja":"「〜だろうと思う / 〜だと思う」— 控えめな推測"}'::jsonb, '비가 오겠지 싶어요.', '{"en":"I think it will probably rain.","es":"Creo que va a llover.","fr":"Je suppose qu’il va pleuvoir.","pt-BR":"Acho que vai chover.","th":"คิดว่าฝนน่าจะตก","id":"Saya rasa nanti hujan.","vi":"Tôi nghĩ là trời sẽ mưa.","ja":"雨が降るだろうと思います。"}'::jsonb, 'topik-5'),
('-(으)ㄴ/는 듯하다 / 듯싶다', '{"en":"\"it seems / it appears ...\" — written/literary form of -것 같다","es":"\"parece (formal/escrito) ...\" — forma escrita/literaria de -것 같다","fr":"«il semble que / il paraît que (écrit)»","pt-BR":"\"parece (formal/literário) ...\"","th":"\"ดูเหมือนว่า ... (ทางการ/วรรณกรรม)\"","id":"\"tampaknya / kelihatannya ... (formal/sastrawi)\"","vi":"\"có vẻ / xem chừng ... (văn viết)\"","ja":"「〜ようだ / 〜らしい(文語)」"}'::jsonb, '그분은 이미 알고 있는 듯해요.', '{"en":"It appears that they already know.","es":"Esa persona parece ya saberlo.","fr":"Il semble qu’il/elle le sache déjà.","pt-BR":"Parece que ele/ela já sabe.","th":"ดูเหมือนว่าท่านนั้นจะรู้อยู่แล้ว","id":"Tampaknya beliau sudah tahu.","vi":"Xem chừng người ấy đã biết rồi.","ja":"あの方はすでに知っているようです。"}'::jsonb, 'topik-5'),
('-(으)ㄴ가 싶다', '{"en":"\"I wonder whether ...\" — inner question, reflective","es":"\"me pregunto si será que ...\" — pregunta interior reflexiva","fr":"«je me demande si ce ne serait pas ...»","pt-BR":"\"será que ...\" — pergunta interior reflexiva","th":"\"สงสัยว่า ... จริงหรือเปล่า\"","id":"\"jangan-jangan ... / mungkinkah ...\"","vi":"\"không biết có phải ... không\"","ja":"「〜のだろうか / 〜のかなと思う」"}'::jsonb, '너무 늦은 건가 싶어요.', '{"en":"I wonder if it’s already too late.","es":"Me pregunto si no será demasiado tarde.","fr":"Je me demande s’il n’est pas trop tard.","pt-BR":"Será que já é tarde demais?","th":"สงสัยว่ามันสายเกินไปหรือเปล่า","id":"Jangan-jangan sudah terlalu terlambat.","vi":"Không biết có phải đã quá muộn không.","ja":"もう遅すぎるのではないかと思います。"}'::jsonb, 'topik-5'),
('-(으)ㅁ', '{"en":"formal nominalization — produces an abstract noun; common in titles, notes, academic writing","es":"nominalización formal — sustantivo abstracto; común en títulos, notas y escritura académica","fr":"nominalisation formelle — nom abstrait; titres, notes, écrits académiques","pt-BR":"nominalização formal — substantivo abstrato; títulos, notas, acadêmico","th":"การทำให้เป็นนามแบบทางการ — ใช้ในหัวข้อ บันทึก งานวิชาการ","id":"nominalisasi formal — kata benda abstrak; judul / catatan / akademik","vi":"danh hóa trang trọng — danh từ trừu tượng; tiêu đề, ghi chú, học thuật","ja":"「〜こと → 〜（さ・み）」名詞化(改まり)"}'::jsonb, '행복함을 느껴요.', '{"en":"I feel happiness.","es":"Siento felicidad.","fr":"Je ressens du bonheur.","pt-BR":"Sinto felicidade.","th":"รู้สึกถึงความสุข","id":"Saya merasakan kebahagiaan.","vi":"Tôi cảm thấy hạnh phúc.","ja":"幸せを感じます。"}'::jsonb, 'topik-5'),
('명사화 비교 (-기 / -(으)ㅁ / -는 것)', '{"en":"compares the 3 nominalizers — colloquial -는 것, active -기, formal -(으)ㅁ","es":"compara las 3 nominalizaciones — cotidiana -는 것, activa -기, formal -(으)ㅁ","fr":"compare les 3 nominaliseurs — oral -는 것, actif -기, formel -(으)ㅁ","pt-BR":"compara as 3 nominalizações — cotidiana -는 것, ativa -기, formal -(으)ㅁ","th":"เปรียบเทียบรูปนามทั้ง 3 — พูดทั่วไป -는 것, กริยา -기, ทางการ -(으)ㅁ","id":"membandingkan 3 nominalisasi — lisan -는 것, aktif -기, formal -(으)ㅁ","vi":"so sánh 3 cách danh hóa — nói -는 것, hành động -기, trang trọng -(으)ㅁ","ja":"名詞化3形式の比較: -는 것(口語) / -기(動作) / -(으)ㅁ(改まり)"}'::jsonb, '한국어 공부하는 것이 재미있어요. (cotidiano) / 한국어 공부하기가 어려워요. (énfasis acción)', '{"en":"Studying Korean is fun. (casual) / Studying Korean is hard. (action focus)","es":"Estudiar coreano es divertido. (cotidiano) / Estudiar coreano es difícil. (foco en acción)","fr":"Étudier le coréen est amusant. (oral) / Étudier le coréen est difficile. (action)","pt-BR":"Estudar coreano é divertido. (cotidiano) / Estudar coreano é difícil. (foco na ação)","th":"การเรียนภาษาเกาหลีสนุก (พูดทั่วไป) / การเรียนภาษาเกาหลียาก (เน้นการกระทำ)","id":"Belajar bahasa Korea menyenangkan. (lisan) / Belajar bahasa Korea sulit. (fokus aksi)","vi":"Học tiếng Hàn rất vui. (đời thường) / Học tiếng Hàn rất khó. (nhấn vào hành động)","ja":"韓国語を勉強することが楽しい(口語) / 韓国語の勉強が難しい(動作焦点)。"}'::jsonb, 'topik-5'),
('-(으)ㄴ/는 데에', '{"en":"\"for / when it comes to ...ing ...\" — frequently with 도움이 되다, 필요하다, 걸리다","es":"\"para / en cuanto a hacer ...\" — frecuente con 도움이 되다, 필요하다, 걸리다","fr":"«pour / quand il s’agit de ...» — souvent avec 도움이 되다, 필요하다, 걸리다","pt-BR":"\"para / quando se trata de fazer ...\" — comum com 도움이 되다, 필요하다, 걸리다","th":"\"ในการ ... / สำหรับการ ...\" — มักใช้กับ 도움이 되다, 필요하다, 걸리다","id":"\"untuk / dalam hal ...-ing\" — sering dengan 도움이 되다 dll.","vi":"\"trong việc / để ...-ing\" — thường với 도움이 되다 v.v.","ja":"「〜するのに(役立つ / 必要だ / かかる)」"}'::jsonb, '이 책이 공부하는 데에 도움이 돼요.', '{"en":"This book is helpful for studying.","es":"Este libro es útil para estudiar.","fr":"Ce livre est utile pour étudier.","pt-BR":"Este livro ajuda nos estudos.","th":"หนังสือเล่มนี้มีประโยชน์ในการเรียน","id":"Buku ini bermanfaat untuk belajar.","vi":"Cuốn sách này hữu ích cho việc học.","ja":"この本は勉強するのに役立ちます。"}'::jsonb, 'topik-5'),
('-(이)나마 / -(으)나마', '{"en":"\"even if just / however small ...\" — humble, polite concession","es":"\"aunque solo sea / por modesto que sea ...\" — concesión humilde","fr":"«même modeste / si humble que ce soit»","pt-BR":"\"mesmo que pequeno / por modesto que seja ...\"","th":"\"แม้จะ ... เล็กน้อย ก็ ... (สุภาพ ถ่อมตน)\"","id":"\"meskipun sedikit ... (santun, rendah hati)\"","vi":"\"dẫu chỉ ... (khiêm tốn)\"","ja":"「〜なりとも / 〜とはいえ(控えめ)」"}'::jsonb, '작은 도움이나마 되었으면 합니다.', '{"en":"I hope I’ve been at least a small help.","es":"Espero que haya sido de ayuda, aunque sea pequeña.","fr":"J’espère avoir été d’une aide, si modeste soit-elle.","pt-BR":"Espero que tenha sido de ajuda, ainda que pequena.","th":"หวังว่าจะเป็นความช่วยเหลือ แม้เพียงเล็กน้อย","id":"Semoga bisa membantu, walau sedikit.","vi":"Mong rằng dù chỉ giúp được chút ít cũng có ích.","ja":"小さな助けなりとも、お役に立てればと思います。"}'::jsonb, 'topik-5'),
('-느니만 못하다', '{"en":"\"is worse than (doing) ...\" — comparative inferiority","es":"\"es peor que / ni siquiera vale como ...\" — inferioridad comparativa","fr":"«vaut moins que / pire que»","pt-BR":"\"é pior do que / nem chega a ...\"","th":"\"แย่กว่า ... / ไม่ดีเท่า ...\"","id":"\"lebih buruk daripada / tidak setara dengan ...\"","vi":"\"còn tệ hơn ... / không bằng ...\"","ja":"「〜するよりむしろ悪い」"}'::jsonb, '그렇게 할 거면 안 하느니만 못해요.', '{"en":"If you’re going to do it like that, it’s worse than not doing it.","es":"Si lo vas a hacer así, es peor que no hacerlo.","fr":"Si tu le fais comme ça, mieux vaudrait ne pas le faire.","pt-BR":"Se vai fazer assim, é pior do que não fazer.","th":"ถ้าจะทำแบบนั้น สู้ไม่ทำเสียดีกว่า","id":"Kalau begitu caranya, lebih baik tidak usah.","vi":"Nếu làm kiểu đó thì thà không làm còn hơn.","ja":"そんな風にするくらいなら、しない方がましです。"}'::jsonb, 'topik-5'),
('-았/었던들', '{"en":"\"if (only) one had ...\" — literary counterfactual past (cf. G181 -았/었더라면)","es":"\"si (solo) hubiera ...\" — contrafactual pasado literario (cf. G181)","fr":"«si seulement on avait ...» — irréel littéraire (cf. G181)","pt-BR":"\"se ao menos tivesse ...\" — contrafactual literário (cf. G181)","th":"\"ถ้าตอนนั้น ... (วรรณกรรม)\" — เทียบ G181","id":"\"andai dulu pernah ... (sastrawi)\"","vi":"\"giá mà đã ... (văn chương)\"","ja":"「〜ていたなら(文語)」— G181 の文語形"}'::jsonb, '그때 더 노력했던들 후회가 없었을 텐데요.', '{"en":"If I had only tried harder back then, I wouldn’t have regrets.","es":"Si me hubiera esforzado más en ese momento, no tendría arrepentimientos.","fr":"Si seulement j’avais fait plus d’efforts à l’époque, je n’aurais pas de regrets.","pt-BR":"Se eu tivesse me esforçado mais, não teria arrependimentos.","th":"หากตอนนั้นพยายามมากกว่านี้ คงไม่ต้องเสียใจ","id":"Andai dulu lebih berusaha, pasti tidak ada penyesalan.","vi":"Giá hồi ấy nỗ lực hơn thì giờ đã không hối tiếc.","ja":"あのときもっと努力していたなら、後悔はなかったでしょうに。"}'::jsonb, 'topik-5'),
('-(으)ㄹ 새(도) 없이', '{"en":"\"without a moment to (even) ...\" — extreme lack of time","es":"\"sin tiempo ni para ...\" — falta extrema de tiempo","fr":"«sans avoir le temps de ...»","pt-BR":"\"sem tempo nem para ...\"","th":"\"ไม่มีเวลาแม้แต่จะ ...\"","id":"\"tanpa sempat sekalipun untuk ...\"","vi":"\"không có cả lúc nào để ...\"","ja":"「〜する暇もなく」"}'::jsonb, '숨 쉴 새도 없이 바빠요.', '{"en":"I’m so busy I don’t even have a moment to breathe.","es":"Estoy tan ocupado que no tengo ni tiempo para respirar.","fr":"Je suis tellement occupé que je n’ai pas même le temps de respirer.","pt-BR":"Estou tão ocupado que não tenho tempo nem para respirar.","th":"ยุ่งจนหายใจไม่ทัน","id":"Sibuk sampai tidak sempat menarik napas.","vi":"Bận đến mức không có cả thời gian để thở.","ja":"息をつく暇もなく忙しいです。"}'::jsonb, 'topik-5'),
('즉시 표현 비교 (-자마자 / -는 대로 / -자 / -는 즉시)', '{"en":"compares 4 \"as soon as\" expressions by register and nuance","es":"compara 4 expresiones de \"en cuanto\" por registro y matiz","fr":"compare 4 expressions de «dès que» selon le registre","pt-BR":"compara 4 expressões de \"assim que\" por registro e nuance","th":"เปรียบเทียบ 4 สำนวน \"ทันทีที่\" ตามระดับและความหมาย","id":"membandingkan 4 ungkapan \"begitu / segera\" menurut register","vi":"so sánh 4 cách diễn đạt \"ngay khi\" theo phong cách","ja":"即時表現4種の比較: -자마자(中立) / -는 대로(可能になり次第) / -자(文語) / -는 즉시(改まり)"}'::jsonb, '도착하자마자 전화하세요. (cotidiano) / 도착하는 즉시 출발하세요. (formal)', '{"en":"Call as soon as you arrive. (casual) / Depart immediately upon arrival. (formal)","es":"Llame en cuanto llegue. (cotidiano) / Parta inmediatamente al llegar. (formal)","fr":"Appelle dès ton arrivée. (oral) / Partez dès votre arrivée. (formel)","pt-BR":"Ligue assim que chegar. (cotidiano) / Saia imediatamente ao chegar. (formal)","th":"พอถึงให้โทรเลย (พูดทั่วไป) / เมื่อถึงให้ออกเดินทางทันที (ทางการ)","id":"Telepon begitu sampai. (sehari-hari) / Berangkat segera setelah tiba. (formal)","vi":"Đến nơi là gọi ngay nhé. (đời thường) / Xin khởi hành ngay khi đến. (trang trọng)","ja":"着いたらすぐ電話してください。(口語) / 到着次第出発してください。(改まり)"}'::jsonb, 'topik-5'),
('-(으)ㄴ/는 한이 있어도', '{"en":"\"even if it means ...\" — extreme determination at any cost","es":"\"aunque tenga que / aun a costa de ...\" — determinación extrema","fr":"«quitte à ... / au prix de ...»","pt-BR":"\"mesmo que tenha de / ainda que ao custo de ...\"","th":"\"ต่อให้ต้อง ... ก็ ...\" — เด็ดเดี่ยวสุดขั้ว","id":"\"meskipun harus ..., tetap ...\"","vi":"\"dù có phải ... cũng ...\"","ja":"「〜することがあっても」— 強い覚悟"}'::jsonb, '굶는 한이 있어도 그 돈은 안 받아요.', '{"en":"Even if I starve, I won’t take that money.","es":"Aunque tenga que pasar hambre, no aceptaré ese dinero.","fr":"Quitte à mourir de faim, je ne prendrai pas cet argent.","pt-BR":"Mesmo que eu passe fome, não aceito esse dinheiro.","th":"ต่อให้ต้องอดอยาก ก็ไม่รับเงินนั้น","id":"Walau harus kelaparan, saya tidak akan menerima uang itu.","vi":"Dù có phải nhịn đói, tôi cũng không nhận số tiền đó.","ja":"飢えることがあっても、あのお金は受け取りません。"}'::jsonb, 'topik-5'),
('-답시고', '{"en":"\"supposedly / under the pretext of ...\" — ironic, critical","es":"\"bajo el pretexto de / supuestamente porque ...\" — irónico, crítico","fr":"«sous prétexte que / soi-disant ...»","pt-BR":"\"sob o pretexto de / supostamente porque ...\" — irônico","th":"\"อ้างว่า ... / แสร้งทำว่า ... (ประชด)\"","id":"\"katanya / dengan dalih ... (sindiran)\"","vi":"\"viện cớ ... / lấy lý do ... (mỉa mai)\"","ja":"「〜のつもりで(揶揄)」"}'::jsonb, '도와준답시고 더 일을 만들었어요.', '{"en":"Supposedly helping, they only created more work.","es":"Bajo el pretexto de ayudar, creó más trabajo.","fr":"Sous prétexte d’aider, il/elle a créé plus de travail.","pt-BR":"Sob o pretexto de ajudar, criou mais trabalho.","th":"อ้างว่าจะช่วย กลับทำให้งานเพิ่ม","id":"Dengan dalih membantu, malah menambah pekerjaan.","vi":"Viện cớ giúp, nhưng làm việc thêm phần rối.","ja":"手伝うつもりで、かえって仕事を増やしました。"}'::jsonb, 'topik-5'),
('-(으)ㄴ/는다거나', '{"en":"\"either say ... or say ...\" — alternative quoted opinions or actions","es":"\"ya sea que diga ... o ...\" — citas alternativas","fr":"«qu’on dise ... ou ...»","pt-BR":"\"seja dizendo ... ou ...\" — alternativas citadas","th":"\"ทั้งบอกว่า ... และบอกว่า ...\"","id":"\"ada yang bilang ... ada yang ...\"","vi":"\"hoặc nói ... hoặc nói ...\"","ja":"間接 + 「〜たり〜たり」— 引用の選択"}'::jsonb, '좋다고 한다거나 싫다고 한다거나 의견이 분분해요.', '{"en":"Some say they like it, others say they don’t — opinions are split.","es":"Hay opiniones divididas, unos dicen que les gusta, otros que no.","fr":"Les avis sont partagés : certains disent qu’ils aiment, d’autres pas.","pt-BR":"As opiniões estão divididas: uns dizem que gostam, outros que não.","th":"ความเห็นแตกต่าง บ้างก็ว่าชอบ บ้างก็ว่าไม่ชอบ","id":"Pendapatnya beragam, ada yang suka ada yang tidak.","vi":"Có người bảo thích, có người bảo không, ý kiến chia rẽ.","ja":"良いと言ったり嫌だと言ったり、意見が分かれています。"}'::jsonb, 'topik-5'),
('-(으)며', '{"en":"\"and / while ... (formal / written)\" — listing or simultaneity in formal writing","es":"\"y / mientras ... (formal/escrito)\" — enumeración o simultaneidad formal","fr":"«et / tout en ... (formel / écrit)»","pt-BR":"\"e / enquanto ... (formal / escrito)\"","th":"\"และ / ในขณะที่ ... (ทางการ/เขียน)\"","id":"\"dan / sembari ... (formal / tulis)\"","vi":"\"và / đồng thời ... (trang trọng / viết)\"","ja":"「〜し / 〜ながら(改まり / 文章語)」"}'::jsonb, '이 제품은 가격이 저렴하며 품질도 좋습니다.', '{"en":"This product is affordable and also of good quality.","es":"Este producto es económico y además tiene buena calidad.","fr":"Ce produit est à la fois abordable et de bonne qualité.","pt-BR":"Este produto é barato e também tem boa qualidade.","th":"สินค้าตัวนี้ราคาประหยัด และคุณภาพยังดีอีกด้วย","id":"Produk ini harganya murah, kualitasnya pun bagus.","vi":"Sản phẩm này giá rẻ, đồng thời chất lượng tốt.","ja":"この製品は価格が安く、品質も良いです。"}'::jsonb, 'topik-5'),
('-(으)며 -(으)며', '{"en":"\"now ... now ... / alternating between two actions\" — listing alternations","es":"\"unas veces ... otras veces ...\" — enumeración alternativa","fr":"«tantôt ... tantôt ...»","pt-BR":"\"ora ... ora ...\" — enumeração alternada","th":"\"ทั้ง ... ทั้ง ... สลับกัน\"","id":"\"sambil ... sambil ... bergantian\"","vi":"\"vừa ... vừa ... xen kẽ\"","ja":"「〜ながら〜ながら / 〜たり〜たり」"}'::jsonb, '웃으며 울며 이야기했어요.', '{"en":"They told the story between laughs and tears.","es":"Hablaron entre risas y llantos.","fr":"Ils ont raconté entre rires et larmes.","pt-BR":"Contaram entre risos e lágrimas.","th":"พวกเขาเล่าเรื่องไปร้องไห้ไปยิ้มไป","id":"Mereka bercerita sambil tertawa dan menangis.","vi":"Họ vừa cười vừa khóc kể chuyện.","ja":"笑ったり泣いたりしながら話しました。"}'::jsonb, 'topik-5'),
('-(으)나', '{"en":"\"but / although ...\" — literary/formal version of -지만","es":"\"pero / aunque (literario/formal)\" — versión literaria de -지만","fr":"«mais / quoique (littéraire/formel)»","pt-BR":"\"mas / embora (literário/formal)\"","th":"\"แต่ / แม้ว่า (ทางการ/วรรณกรรม)\"","id":"\"tetapi / meskipun (formal/sastrawi)\"","vi":"\"nhưng / dù (trang trọng / văn chương)\"","ja":"「〜が / 〜けれども(文語)」"}'::jsonb, '노력은 했으나 결과가 좋지 않았다.', '{"en":"I made the effort, but the result was not good.","es":"Hice el esfuerzo, pero los resultados no fueron buenos.","fr":"J’ai fait des efforts, mais le résultat n’était pas bon.","pt-BR":"Fiz o esforço, mas o resultado não foi bom.","th":"พยายามแล้ว แต่ผลลัพธ์ไม่ดี","id":"Sudah berusaha, tetapi hasilnya tidak baik.","vi":"Tôi đã cố gắng nhưng kết quả không tốt.","ja":"努力はしたが、結果が良くなかった。"}'::jsonb, 'topik-5'),
('-(으)려고 들다', '{"en":"\"insist on / be set on ...ing ...\" — usually with critical / annoyed tone","es":"\"empeñarse en / insistir en ...\" — con tono crítico o de fastidio","fr":"«s’entêter à / s’acharner à ...»","pt-BR":"\"insistir em / fazer questão de ...\" — com tom crítico","th":"\"จะ ... ให้ได้ / ดันทุรัง ...\" — เชิงตำหนิ","id":"\"ngotot mau ... / memaksakan diri ...\"","vi":"\"khăng khăng ... / cố gắng ép ...\"","ja":"「〜しようとする / 〜したがる(批判)」"}'::jsonb, '자꾸 싸우려고 들어요.', '{"en":"They keep insisting on picking a fight.","es":"No para de buscar pelea.","fr":"Il/elle ne cesse de chercher la dispute.","pt-BR":"Vive querendo arrumar briga.","th":"เอาแต่จะหาเรื่องทะเลาะ","id":"Maunya bertengkar terus.","vi":"Cứ khăng khăng đòi gây gổ.","ja":"何かにつけて喧嘩しようとします。"}'::jsonb, 'topik-5'),
('-기 십상이다', '{"en":"\"is likely to (negatively) end up ...\" — high probability, usually bad","es":"\"es muy fácil que termine en / es propenso a ...\" — probabilidad alta, usualmente mala","fr":"«risque fort de / a vite fait de» — issue souvent négative","pt-BR":"\"facilmente termina em ...\" — geralmente negativo","th":"\"มีโอกาสสูงที่จะ ... (ทางลบ)\"","id":"\"mudah berakhir dengan ... (biasanya buruk)\"","vi":"\"dễ kết cục là ... (thường tiêu cực)\"","ja":"「〜しがちだ / 〜するのがおち」"}'::jsonb, '그렇게 운전하면 사고 나기 십상이에요.', '{"en":"Driving like that, you’re bound to have an accident.","es":"Conduciendo así es fácil que tengas un accidente.","fr":"À conduire comme ça, on a vite fait d’avoir un accident.","pt-BR":"Dirigindo assim, é fácil acabar em acidente.","th":"ขับแบบนั้นมีโอกาสเกิดอุบัติเหตุสูง","id":"Kalau menyetir begitu, mudah saja kecelakaan.","vi":"Lái xe kiểu đó dễ gặp tai nạn lắm.","ja":"そんな運転をしていると、事故を起こしがちです。"}'::jsonb, 'topik-5'),
('-(으)ㄴ/는 셈 치다', '{"en":"\"treat as if it were ... / let’s say ...\" — accept a fiction for the sake of moving on","es":"\"considerar como si fuera ...\" — aceptar una ficción para seguir adelante","fr":"«considérer comme si ...»","pt-BR":"\"considerar como se fosse ...\" — aceitar uma ficção","th":"\"ถือว่า ... / นับว่าเป็น ...\"","id":"\"anggap saja ... / dianggap seolah ...\"","vi":"\"coi như là ... / xem như ...\"","ja":"「〜したことにする / 〜つもりで」"}'::jsonb, '잃어버린 셈 치고 그냥 잊어버려요.', '{"en":"Treat it as if you’d lost it and just forget about it.","es":"Considéralo como si lo hubieras perdido y olvídate.","fr":"Considère-le comme perdu et oublie-le.","pt-BR":"Considere como se tivesse perdido e esqueça.","th":"ถือว่าหายไป แล้วลืม ๆ มันไปซะ","id":"Anggap saja sudah hilang dan lupakan.","vi":"Coi như đã mất rồi quên đi.","ja":"なくしたつもりで、もう忘れましょう。"}'::jsonb, 'topik-5'),
('-(으)ㄹ락 말락 하다', '{"en":"\"on the verge of but not quite ...\" — wavering, almost happening","es":"\"estar a punto de pero sin llegar ...\" — vacilante","fr":"«être sur le point de ... sans tout à fait ...»","pt-BR":"\"prestes a / quase ..., mas não chegar ...\"","th":"\"จะ ... ก็ไม่ค่อย ... / เกือบ ... แต่ไม่\"","id":"\"hampir ... tetapi tidak ...\"","vi":"\"chực ... mà không hẳn ...\"","ja":"「〜しそうで〜しない / 〜たり〜なかったり」"}'::jsonb, '잠이 들락 말락 했어요.', '{"en":"I was drifting between sleep and waking.","es":"Estaba entre dormido y despierto.","fr":"J’étais entre veille et sommeil.","pt-BR":"Estava entre dormindo e acordado.","th":"อยู่ระหว่างหลับกับตื่น","id":"Saya berada antara tidur dan terjaga.","vi":"Tôi ở giữa cơn mơ và tỉnh.","ja":"寝るか寝ないかという状態でした。"}'::jsonb, 'topik-5'),
('-는 둥 마는 둥', '{"en":"\"doing X half-heartedly / barely doing X ...\" — superficial, without commitment","es":"\"haciéndolo a medias / sin ganas ...\" — superficial, sin compromiso","fr":"«à moitié / sans conviction»","pt-BR":"\"fazendo pela metade / sem vontade ...\"","th":"\"ทำแบบขอไปที / ทำไม่ใส่ใจ\"","id":"\"setengah hati / sambil lalu\"","vi":"\"qua loa / cho có lệ\"","ja":"「〜たり〜なかったり / うわのそらで」"}'::jsonb, '아침을 먹는 둥 마는 둥 했어요.', '{"en":"I barely ate any breakfast.","es":"Desayuné a medias, casi sin desayunar.","fr":"J’ai mangé mon petit-déjeuner du bout des lèvres.","pt-BR":"Mal toquei no café da manhã.","th":"กินอาหารเช้าไม่กี่คำก็เลิก","id":"Sarapan setengah hati saja.","vi":"Tôi ăn sáng qua loa cho có.","ja":"朝食を食べたり食べなかったりするような感じでした。"}'::jsonb, 'topik-5'),
('-느냐에 따라(서)', '{"en":"\"depending on whether / how ...\" — outcome hinges on a question","es":"\"dependiendo de si / cómo ...\" — el resultado depende de la respuesta","fr":"«selon que ... / selon le fait de ...»","pt-BR":"\"dependendo de se / de como ...\"","th":"\"ขึ้นอยู่กับว่า ...\"","id":"\"tergantung apakah / bagaimana ...\"","vi":"\"tùy theo việc ... có / không / như thế nào ...\"","ja":"「〜かどうかによって / 〜次第で」"}'::jsonb, '어떻게 준비하느냐에 따라 결과가 달라져요.', '{"en":"The result varies depending on how you prepare.","es":"Los resultados varían según cómo se prepare uno.","fr":"Le résultat varie selon la façon dont on se prépare.","pt-BR":"Os resultados mudam dependendo de como você se prepara.","th":"ผลลัพธ์เปลี่ยนไปตามวิธีการเตรียมตัว","id":"Hasilnya berbeda tergantung cara persiapan.","vi":"Kết quả thay đổi tùy theo cách chuẩn bị.","ja":"どう準備するかによって結果が変わります。"}'::jsonb, 'topik-5'),
('-(으)ㄴ/는 가운데', '{"en":"\"in the midst of / amid ...\" — formal contextual envelope","es":"\"en medio de / mientras ...\" — contexto envolvente formal","fr":"«au milieu de / dans le contexte de ...»","pt-BR":"\"em meio a / no meio de ...\" — contexto formal","th":"\"ท่ามกลาง ... / ภายใต้ ...\"","id":"\"di tengah ... / di tengah-tengah ...\"","vi":"\"giữa ... / trong bối cảnh ...\"","ja":"「〜中で / 〜中(なか)を」(改まり)"}'::jsonb, '많은 사람들이 지켜보는 가운데 행사가 진행됐어요.', '{"en":"The event proceeded amid many onlookers.","es":"El evento se realizó en medio de la mirada de mucha gente.","fr":"L’événement s’est déroulé sous le regard de nombreux spectateurs.","pt-BR":"O evento ocorreu em meio à atenção de muita gente.","th":"งานจัดขึ้นท่ามกลางสายตาของผู้คนมากมาย","id":"Acara berlangsung di tengah pandangan banyak orang.","vi":"Buổi lễ diễn ra giữa sự dõi theo của nhiều người.","ja":"多くの人が見守る中、イベントが行われました。"}'::jsonb, 'topik-5'),
('-아/어 뵙다 / 봬요', '{"en":"humble/honorific of -아/어 보다 — for showing humility before superiors","es":"humilde/honorífico de -아/어 보다 — para mostrar humildad ante superiores","fr":"humble/honorifique de -아/어 보다","pt-BR":"humilde/honorífico de -아/어 보다","th":"รูปยกย่อง/ถ่อมตัวของ -아/어 보다","id":"bentuk hormat/santun dari -아/어 보다","vi":"thể khiêm nhường/kính ngữ của -아/어 보다","ja":"-아/어 보다 の謙譲・尊敬形「お〜してみる / お目にかかる」"}'::jsonb, '다음에 또 뵙겠습니다.', '{"en":"I look forward to seeing you next time.","es":"Le veré la próxima vez.","fr":"Au plaisir de vous revoir.","pt-BR":"Vejo o senhor / a senhora na próxima.","th":"แล้วจะพบกันใหม่ครับ","id":"Sampai bertemu lagi, Pak/Bu.","vi":"Hẹn gặp lại lần sau ạ.","ja":"次回またお目にかかります。"}'::jsonb, 'topik-5'),
('-(으)랴 -(으)랴', '{"en":"\"what with this and that ...\" — overwhelmed by multiple tasks","es":"\"qué con esto, qué con aquello ...\" — agobio por múltiples tareas","fr":"«entre ceci et cela / tant à faire»","pt-BR":"\"entre uma coisa e outra ...\" — sobrecarga","th":"\"ทั้ง ... ทั้ง ... ยุ่งจนตัวเป็นเกลียว\"","id":"\"sambil ..., sambil ... — sibuk tak karuan\"","vi":"\"vừa ... vừa ... — bận tối mặt\"","ja":"「〜やら〜やら(忙殺)」"}'::jsonb, '공부하랴 일하랴 너무 바빠요.', '{"en":"Between studying and working, I’m swamped.","es":"Entre estudiar y trabajar, estoy ocupadísimo.","fr":"Entre les études et le travail, je suis débordé.","pt-BR":"Entre estudar e trabalhar, estou atolado.","th":"ทั้งเรียนทั้งทำงาน ยุ่งจนหัวหมุน","id":"Antara belajar dan kerja, saya sibuk sekali.","vi":"Vừa học vừa làm, tôi bận tối tăm mặt mũi.","ja":"勉強やら仕事やらでとても忙しいです。"}'::jsonb, 'topik-5'),
('-(으)ㄴ다는 게', '{"en":"\"meant to ... but ended up ... (colloquial)\" — variant of G184","es":"\"lo que quería era ... pero al final ... (coloquial)\" — variante de G184","fr":"«je voulais ... mais en fin de compte ... (oral)»","pt-BR":"\"queria ... mas acabei ... (coloquial)\" — variante de G184","th":"\"กะว่าจะ ... แต่ก็ ... (พูด)\" — แบบ G184","id":"\"niatnya ... malah ... (lisan)\" — varian G184","vi":"\"định ... mà rốt cuộc ... (nói)\" — biến thể G184","ja":"「〜するつもりが(口語)」— G184 の口語形"}'::jsonb, '인사한다는 게 그만 큰 소리로 외쳐버렸어요.', '{"en":"I meant to greet but ended up shouting.","es":"Quería saludar pero acabé gritando.","fr":"Je voulais saluer, mais j’ai fini par crier.","pt-BR":"Eu queria cumprimentar, mas acabei gritando.","th":"กะจะทักทาย กลับเผลอตะโกนเสียงดัง","id":"Niatnya menyapa, malah berteriak.","vi":"Định chào, lại lỡ la to.","ja":"挨拶しようとしたのに、つい大声を出してしまいました。"}'::jsonb, 'topik-5'),
('-(으)ㄹ 따름입니다', '{"en":"\"merely / simply ...\" in 합쇼체 — humble/formal version of G104","es":"\"simplemente / lo único que ...\" en 합쇼체 — versión humilde de G104","fr":"«je ne fais que / il n’y a qu’à ...» (forme formelle de G104)","pt-BR":"\"apenas / só faço ...\" (forma formal de G104)","th":"\"เพียงแค่ ... (รูปทางการของ G104)\"","id":"\"hanya bisa ... (bentuk formal G104)\"","vi":"\"chỉ biết ... (kính ngữ của G104)\"","ja":"「〜するばかりです(改まり)」— G104 の합쇼체形"}'::jsonb, '그저 감사할 따름입니다.', '{"en":"I can only feel grateful.","es":"Solo puedo estar agradecido.","fr":"Je ne peux qu’être reconnaissant.","pt-BR":"Só me resta agradecer.","th":"ทำได้แค่ขอบคุณเท่านั้น","id":"Saya hanya bisa berterima kasih.","vi":"Tôi chỉ biết cảm ơn mà thôi.","ja":"ただただ感謝するばかりです。"}'::jsonb, 'topik-5'),
('-(으)며 살다 / 지내다', '{"en":"\"live (one’s life) doing ...\" — describes a way of life","es":"\"vivir + gerundio\" — describe un modo de vida","fr":"«vivre en ...ant»","pt-BR":"\"viver + gerúndio\" — descreve um modo de vida","th":"\"ใช้ชีวิตด้วยการ ... / อยู่ไปด้วย ...\"","id":"\"hidup sambil ... / menjalani hidup dengan ...\"","vi":"\"sống mà vẫn ... / sống bằng cách ...\"","ja":"「〜しながら暮らす / 過ごす」"}'::jsonb, '한국에서 한국어를 배우며 살아요.', '{"en":"I live in Korea while learning Korean.","es":"Vivo en Corea estudiando coreano.","fr":"Je vis en Corée tout en apprenant le coréen.","pt-BR":"Vivo na Coreia estudando coreano.","th":"ฉันใช้ชีวิตในเกาหลีพร้อมเรียนภาษาเกาหลี","id":"Saya tinggal di Korea sambil belajar bahasa Korea.","vi":"Tôi sống ở Hàn vừa học tiếng Hàn.","ja":"韓国で韓国語を学びながら暮らしています。"}'::jsonb, 'topik-5'),
('-ㄴ들', '{"en":"\"even if ..., what good ...?\" — rhetorical concession (literary)","es":"\"aunque ..., ¿de qué sirve?\" — concesión retórica (literaria)","fr":"«même si ..., à quoi bon ?» — concession rhétorique (littéraire)","pt-BR":"\"mesmo que ..., de que adianta?\" — concessão retórica (literária)","th":"\"แม้จะ ... ก็ไร้ประโยชน์\" — สำนวนวรรณกรรม","id":"\"meskipun ..., apa gunanya?\" — retoris (sastrawi)","vi":"\"dù ... thì cũng (ích gì)?\" — văn chương","ja":"「〜したところで(何の意味があるか)」— 文語・反語"}'::jsonb, '지금 후회한들 무슨 소용이 있어요?', '{"en":"Even if you regret it now, what good will it do?","es":"¿De qué sirve arrepentirse ahora?","fr":"Même si tu le regrettes maintenant, à quoi bon ?","pt-BR":"De que adianta se arrepender agora?","th":"แม้ตอนนี้จะเสียใจก็ไม่มีประโยชน์อะไร","id":"Meskipun menyesal sekarang, apa gunanya?","vi":"Dù bây giờ có hối hận thì ích gì?","ja":"今さら後悔したところで何になるでしょう。"}'::jsonb, 'topik-6'),
('-(으)ㄹ망정', '{"en":"\"even if it means ...\" — firm moral resolve; more literary than -(으)ㄹ지언정","es":"\"aunque sea ...\" — firmeza moral; más literario que -(으)ㄹ지언정","fr":"«quitte à ... / dussé-je ...» — résolution morale (littéraire)","pt-BR":"\"ainda que / mesmo que ...\" — firmeza moral (literária)","th":"\"ถึงจะ ... ก็ ... (เน้นหลักการ, วรรณกรรม)\"","id":"\"meskipun harus ..., tetap ... (tegas, sastrawi)\"","vi":"\"thà ... cũng (giữ nguyên tắc) ...\" — văn chương","ja":"「〜たとえ〜であろうとも / 〜してでも」— 文語・道徳的決意"}'::jsonb, '가난해질망정 정직하게 살겠어요.', '{"en":"Even if I become poor, I’ll live honestly.","es":"Aunque me vuelva pobre, viviré honestamente.","fr":"Quitte à devenir pauvre, je vivrai honnêtement.","pt-BR":"Mesmo que eu fique pobre, viverei com honestidade.","th":"ต่อให้กลายเป็นคนจน ก็จะใช้ชีวิตอย่างซื่อสัตย์","id":"Meskipun harus jatuh miskin, saya akan hidup jujur.","vi":"Thà nghèo đi tôi cũng sống ngay thẳng.","ja":"たとえ貧しくなろうとも、正直に生きます。"}'::jsonb, 'topik-6'),
('-기로서니', '{"en":"\"just because ... doesn’t mean ...\" — minimizes the cited reason; reproachful","es":"\"solo porque ... no significa que ...\" — minimiza la razón; con reproche","fr":"«ce n’est pas parce que ... que / sous prétexte que»","pt-BR":"\"só porque ... não significa que ...\" — com tom de reprovação","th":"\"แค่ ... ก็ไม่ใช่เหตุผลที่จะ ...\"","id":"\"hanya karena ... bukan berarti ...\"","vi":"\"chỉ vì ... không có nghĩa là ...\"","ja":"「〜だからといって / いくら〜であっても」— 咎める"}'::jsonb, '바쁘기로서니 연락도 못 해요?', '{"en":"Just because you’re busy, you can’t even send a message?","es":"Solo porque estás ocupado, ¿no puedes ni dar señales de vida?","fr":"Ce n’est pas parce que tu es occupé que tu ne peux pas donner de nouvelles.","pt-BR":"Só porque está ocupado, não dá nem para mandar um recado?","th":"แค่ยุ่งจะติดต่อสักหน่อยไม่ได้เลยเหรอ","id":"Hanya karena sibuk, kabar pun tidak bisa?","vi":"Chỉ vì bận thôi mà không thể nhắn tin được sao?","ja":"いくら忙しいからって、連絡もできないんですか？"}'::jsonb, 'topik-6'),
('-(으)로 말미암아', '{"en":"\"owing to / by virtue of ...\" — high-register literary cause","es":"\"a raíz de / por obra de ...\" — causa de registro muy alto (literario)","fr":"«par la faute de / grâce à / du fait de» — registre littéraire","pt-BR":"\"em razão de / em virtude de ...\" — causa em registro literário","th":"\"อันสืบเนื่องมาจาก / ด้วย ... (วรรณกรรม)\"","id":"\"akibat dari / berkat ... (sastrawi)\"","vi":"\"do / nhờ ... (văn chương)\"","ja":"「〜により / 〜ゆえに(文語)」"}'::jsonb, '그의 희생으로 말미암아 많은 사람들이 살 수 있었어요.', '{"en":"Owing to his sacrifice, many people were able to live.","es":"A raíz de su sacrificio, muchas personas pudieron vivir.","fr":"Grâce à son sacrifice, beaucoup ont pu vivre.","pt-BR":"Em virtude de seu sacrifício, muitas pessoas puderam viver.","th":"ด้วยการเสียสละของเขา ทำให้คนจำนวนมากรอดชีวิต","id":"Berkat pengorbanannya, banyak orang bisa hidup.","vi":"Nhờ sự hy sinh của ông, nhiều người đã được sống.","ja":"彼の犠牲によって、多くの人が生きることができました。"}'::jsonb, 'topik-6'),
('-(으)ㄴ/는 즉', '{"en":"\"namely / in other words / that is to say ...\" — formal restatement","es":"\"es decir / o sea / lo que significa ...\" — reformulación formal","fr":"«c’est-à-dire / autrement dit / soit ...»","pt-BR":"\"isto é / ou seja / o que significa ...\"","th":"\"กล่าวคือ / ก็คือ ... (ทางการ)\"","id":"\"yakni / dengan kata lain / artinya ...\"","vi":"\"tức là / nói cách khác ...\"","ja":"「すなわち / つまり(改まり)」"}'::jsonb, '그는 이미 결정을 내렸다. 즉 더 이상 논의는 필요 없다는 뜻이다.', '{"en":"He has already made his decision. That is, no more discussion is needed.","es":"Ya tomó la decisión. Es decir, no hace falta más discusión.","fr":"Il a déjà pris sa décision. Autrement dit, il n’y a plus à discuter.","pt-BR":"Ele já tomou a decisão. Ou seja, não é preciso mais discussão.","th":"เขาตัดสินใจแล้ว กล่าวคือ ไม่จำเป็นต้องถกเถียงอีก","id":"Dia sudah memutuskan. Artinya, tidak perlu lagi diskusi.","vi":"Anh ấy đã quyết định. Tức là không cần bàn thêm.","ja":"彼はすでに決断を下した。すなわち、これ以上の議論は不要だ。"}'::jsonb, 'topik-6'),
('-거니와', '{"en":"\"not only ... but also ...\" — literary version of -(으)ㄹ 뿐만 아니라","es":"\"no solo ... sino también ... (literario)\" — versión literaria","fr":"«non seulement ... mais aussi ...» — registre soutenu / littéraire","pt-BR":"\"não só ... como também ... (literário)\"","th":"\"นอกจาก ... ยัง ... อีกด้วย (วรรณกรรม)\"","id":"\"tidak hanya ... bahkan ... (sastrawi)\"","vi":"\"không những ... mà còn ... (văn chương)\"","ja":"「〜のみならず(文語)」"}'::jsonb, '그분은 능력이 뛰어나거니와 인격도 훌륭해요.', '{"en":"They are not only extremely capable but also of excellent character.","es":"Esa persona no solo es muy capaz, sino que además tiene un carácter excelente.","fr":"Cette personne est non seulement très compétente, mais aussi d’un caractère exemplaire.","pt-BR":"Essa pessoa não só é capaz, como também tem caráter excelente.","th":"ท่านผู้นั้นไม่เพียงเก่ง ยังมีบุคลิกดีเยี่ยมอีกด้วย","id":"Beliau tidak hanya cakap, tetapi juga berkarakter luar biasa.","vi":"Người ấy không chỉ tài năng mà nhân cách còn xuất chúng.","ja":"あの方は能力が優れているのみならず、人格も立派です。"}'::jsonb, 'topik-6'),
('-는 마당에', '{"en":"\"given that ... (now) / at this point ...\" — irreversible/critical context","es":"\"llegados a este punto / dado que ya ...\" — situación irreversible o crítica","fr":"«à présent que / vu où nous en sommes»","pt-BR":"\"a esta altura / dado que já ...\" — situação irreversível","th":"\"ในเมื่อ ... แล้ว / ถึงจุดนี้แล้ว ...\"","id":"\"setelah keadaan sampai ... / sudah ...; \"","vi":"\"đến mức ... rồi thì ...\"","ja":"「〜という段になって / 今さら〜の状況で」"}'::jsonb, '이미 시작한 마당에 포기할 수는 없어요.', '{"en":"Given that we’ve already started, we can’t give up.","es":"Llegados a este punto, ya que empezamos, no podemos rendirnos.","fr":"Maintenant qu’on a commencé, on ne peut pas abandonner.","pt-BR":"Já que começamos, não dá para desistir.","th":"ในเมื่อเริ่มไปแล้ว จะถอนตัวก็ไม่ได้","id":"Sudah dimulai begini, tidak bisa mundur.","vi":"Đã bắt đầu rồi thì không thể bỏ cuộc.","ja":"すでに始めた以上、やめるわけにはいきません。"}'::jsonb, 'topik-6'),
('-는 즉시', '{"en":"\"immediately upon / as soon as ...\" — formal version of -자마자","es":"\"en cuanto / inmediatamente al ... (formal)\" — versión formal de -자마자","fr":"«dès que / aussitôt que» — registre formel","pt-BR":"\"imediatamente após / assim que (formal)\"","th":"\"ทันทีที่ ... (ทางการ)\"","id":"\"segera setelah / begitu ... (formal)\"","vi":"\"ngay khi ... (trang trọng)\"","ja":"「〜次第 / 〜と同時に(改まり)」"}'::jsonb, '연락을 받는 즉시 출발하세요.', '{"en":"Depart immediately upon receiving the contact.","es":"Parta en cuanto reciba el aviso.","fr":"Partez dès que vous recevez l’avis.","pt-BR":"Saia imediatamente assim que receber o aviso.","th":"พอได้รับการติดต่อ ให้ออกเดินทางทันที","id":"Begitu menerima kabar, segera berangkat.","vi":"Ngay khi nhận được liên lạc, hãy khởi hành.","ja":"連絡を受け次第、出発してください。"}'::jsonb, 'topik-6'),
('-(이)야말로', '{"en":"\"precisely / exactly ... is\" — strongest emphatic identification","es":"\"precisamente / justamente / por excelencia ...\" — énfasis máximo","fr":"«c’est précisément / par excellence ...»","pt-BR":"\"justamente / é exatamente ...\" — ênfase máxima","th":"\"... นี่แหละ / ... โดยแท้\"","id":"\"justru ... / ... lah yang\"","vi":"\"chính ... mới là ...\"","ja":"「〜こそ」— 最強の強調"}'::jsonb, '노력이야말로 성공의 열쇠예요.', '{"en":"Effort is precisely the key to success.","es":"El esfuerzo es justamente la clave del éxito.","fr":"C’est précisément le travail qui est la clé du succès.","pt-BR":"O esforço é justamente a chave do sucesso.","th":"ความพยายามนี่แหละคือกุญแจสู่ความสำเร็จ","id":"Justru kerja keras itulah kunci sukses.","vi":"Chính nỗ lực mới là chìa khóa của thành công.","ja":"努力こそが成功の鍵です。"}'::jsonb, 'topik-6'),
('-건대 / 생각건대 / 바라건대', '{"en":"\"in my opinion / I venture to ...\" — formal personal assertion (생각건대, 바라건대, 보건대)","es":"\"a mi juicio / me atrevo a afirmar / espero que ...\" — aserción personal formal","fr":"«à mon avis / je me permets de ...» — assertion personnelle formelle","pt-BR":"\"a meu ver / atrevo-me a dizer ...\" — afirmação pessoal formal","th":"\"ในความเห็นของฉัน / ขอกล่าวว่า ... (ทางการ)\"","id":"\"menurut hemat saya / dengan rendah hati ... (formal)\"","vi":"\"theo tôi / xin mạnh dạn cho rằng ... (trang trọng)\"","ja":"「〜するに / 思うに / 願わくは(改まり)」"}'::jsonb, '생각건대, 이 문제의 근본 원인은 소통 부재예요.', '{"en":"In my view, the root cause of this issue is the lack of communication.","es":"A mi juicio, la causa raíz de este problema es la falta de comunicación.","fr":"À mon avis, la cause profonde de ce problème est l’absence de communication.","pt-BR":"A meu ver, a causa raiz deste problema é a falta de comunicação.","th":"ในความเห็นของผม รากเหง้าของปัญหานี้คือการขาดการสื่อสาร","id":"Menurut hemat saya, akar masalah ini adalah kurangnya komunikasi.","vi":"Theo tôi, nguyên nhân gốc rễ của vấn đề là thiếu giao tiếp.","ja":"思うに、この問題の根本原因は意思疎通の欠如です。"}'::jsonb, 'topik-6'),
('에 있어서', '{"en":"\"in the area of / when it comes to ...\" — formal scope marker","es":"\"en cuanto a / en el ámbito de ...\" — marcador de ámbito formal","fr":"«en ce qui concerne / dans le domaine de ...»","pt-BR":"\"no que diz respeito a / no âmbito de ...\"","th":"\"ในด้าน / ในเรื่อง ... (ทางการ)\"","id":"\"dalam hal / mengenai ... (formal)\"","vi":"\"trong lĩnh vực / về mặt ... (trang trọng)\"","ja":"「〜において / 〜にあたって(改まり)」"}'::jsonb, '교육에 있어서 환경이 매우 중요해요.', '{"en":"When it comes to education, the environment matters a great deal.","es":"En lo que respecta a la educación, el entorno es muy importante.","fr":"En matière d’éducation, l’environnement est très important.","pt-BR":"No que diz respeito à educação, o ambiente é muito importante.","th":"ในด้านการศึกษา สภาพแวดล้อมมีความสำคัญมาก","id":"Dalam hal pendidikan, lingkungan sangatlah penting.","vi":"Trong lĩnh vực giáo dục, môi trường rất quan trọng.","ja":"教育において環境は非常に重要です。"}'::jsonb, 'topik-6'),
('-는 법이다', '{"en":"\"such is the way of things / it’s natural that ...\" — universal truth or norm","es":"\"así son las cosas / es natural que ...\" — verdad universal o norma","fr":"«c’est ainsi que / il est naturel que ...» — vérité générale","pt-BR":"\"é assim que / é natural que ...\" — verdade universal","th":"\"เป็นธรรมดาที่ ... / ก็เป็นเช่นนั้น\"","id":"\"begitulah seharusnya / sudah kodratnya ...\"","vi":"\"vốn dĩ ... / chuyện đời là vậy\"","ja":"「〜ものだ」— 普遍の道理"}'::jsonb, '노력하면 결과가 따르는 법이에요.', '{"en":"It’s natural that effort brings results.","es":"Es natural que el esfuerzo traiga resultados.","fr":"Il est naturel que les efforts portent leurs fruits.","pt-BR":"É natural que o esforço traga resultados.","th":"ถ้าพยายาม ผลลัพธ์ก็ย่อมตามมา","id":"Sudah kodratnya: ada usaha pasti ada hasil.","vi":"Hễ nỗ lực thì ắt có kết quả, đời vốn dĩ vậy.","ja":"努力すれば結果がついてくるものです。"}'::jsonb, 'topik-6'),
('-(으)ㄴ/는 이상', '{"en":"\"given that / as long as it is the case that ...\" — established condition leading to obligation","es":"\"ya que / dado que ... (es así)\" — condición establecida que implica obligación","fr":"«dès lors que / du moment que ...»","pt-BR":"\"já que / desde que ...\" — condição estabelecida","th":"\"ในเมื่อ ... แล้ว ก็ต้อง ...\"","id":"\"karena sudah ..., maka harus ...\"","vi":"\"đã ... thì phải ...\"","ja":"「〜以上 / 〜からには」"}'::jsonb, '약속을 한 이상 반드시 지켜야 해요.', '{"en":"Given that you made a promise, you must keep it.","es":"Ya que hiciste la promesa, tienes que cumplirla.","fr":"Dès lors que tu as fait une promesse, tu dois la tenir.","pt-BR":"Já que fez a promessa, tem que cumprir.","th":"ในเมื่อให้สัญญาแล้ว ก็ต้องรักษา","id":"Karena sudah berjanji, harus ditepati.","vi":"Đã hứa rồi thì phải giữ lời.","ja":"約束をした以上、必ず守らなければなりません。"}'::jsonb, 'topik-6'),
('-다시피', '{"en":"\"as (you) know / as you can see / practically ...\" — shared info or virtual equivalence","es":"\"como (bien) sabes / como puedes ver / prácticamente ...\" — info compartida o casi-equivalencia","fr":"«comme tu le sais / pour ainsi dire»","pt-BR":"\"como você sabe / como dá para ver / praticamente ...\"","th":"\"อย่างที่ทราบ / อย่างที่เห็น / แทบจะ ...\"","id":"\"sebagaimana yang kamu tahu / nyaris ...\"","vi":"\"như bạn đã biết / như có thể thấy / gần như ...\"","ja":"「ご存じのとおり / ご覧のとおり / 〜さながら」"}'::jsonb, '아시다시피 이 문제는 오래전부터 있었어요.', '{"en":"As you know, this problem has existed for a long time.","es":"Como bien saben, este problema existe desde hace mucho tiempo.","fr":"Comme vous le savez, ce problème existe depuis longtemps.","pt-BR":"Como vocês sabem, esse problema existe há muito tempo.","th":"อย่างที่ทราบ ปัญหานี้มีมานานแล้ว","id":"Sebagaimana Anda ketahui, masalah ini sudah lama ada.","vi":"Như quý vị đã biết, vấn đề này có từ lâu rồi.","ja":"ご存じのとおり、この問題は以前からありました。"}'::jsonb, 'topik-6'),
('-ㄴ/는다', '{"en":"narrative declarative (해라체) — written form for novels, articles, diaries","es":"declarativa narrativa (해라체) — forma escrita para narrativa, prensa, diarios","fr":"déclaratif narratif (해라체) — forme écrite (romans, articles, journaux intimes)","pt-BR":"declarativa narrativa (해라체) — forma escrita para narrativa e jornalismo","th":"รูปบอกเล่าในการเล่าเรื่อง (해라체) — สำหรับนวนิยาย / บทความ / ไดอารี","id":"pernyataan naratif (해라체) — bentuk tulis untuk novel, artikel, diari","vi":"lối kể chuyện trần thuật (해라체) — văn viết: tiểu thuyết, báo, nhật ký","ja":"常体・文語の終止形(해라체) — 小説・新聞・日記など"}'::jsonb, '봄이 오면 꽃이 핀다.', '{"en":"When spring comes, flowers bloom.","es":"Cuando llega la primavera, florecen las flores.","fr":"Quand le printemps arrive, les fleurs s’épanouissent.","pt-BR":"Quando a primavera chega, as flores desabrocham.","th":"เมื่อฤดูใบไม้ผลิมาถึง ดอกไม้ก็บาน","id":"Ketika musim semi tiba, bunga bermekaran.","vi":"Khi xuân về, hoa nở rộ.","ja":"春が来れば花が咲く。"}'::jsonb, 'topik-6'),
('-노라', '{"en":"archaic poetic declarative — solemn assertion in poems, hymns, proclamations","es":"declarativa poética arcaica — aserción solemne en poesía, himnos, proclamas","fr":"déclaratif poétique archaïque — assertion solennelle, poésie / hymnes","pt-BR":"declarativa poética arcaica — afirmação solene em poesia / hinos","th":"รูปประกาศแบบโบราณ/บทกวี — สุนทรพจน์ บทเพลง","id":"pernyataan puitis kuno — proklamasi, syair, himne","vi":"lối tuyên xưng cổ thi — trang trọng, dùng trong thơ / khẩu hiệu","ja":"古語・詩語の宣明形「〜なり / 〜であるぞ」"}'::jsonb, '나는 이 땅을 사랑하노라.', '{"en":"I love this land.","es":"Yo amo esta tierra.","fr":"J’aime cette terre.","pt-BR":"Amo esta terra.","th":"ข้าขอประกาศว่ารักแผ่นดินผืนนี้","id":"Saya cinta tanah ini.","vi":"Ta yêu mảnh đất này.","ja":"我はこの地を愛するなり。"}'::jsonb, 'topik-6'),
('-로다 / -(이)로다', '{"en":"archaic solemn declarative — emphatic exclamation in classical poetry and proverbs","es":"declarativa solemne arcaica — exclamación enfática en poesía clásica y refranes","fr":"déclaratif solennel archaïque — exclamation emphatique (poésie classique)","pt-BR":"declarativa solene arcaica — exclamação enfática (poesia clássica)","th":"รูปประกาศแบบสง่างามโบราณ — บทกวีคลาสสิก / สุภาษิต","id":"pernyataan agung kuno — puisi klasik / pepatah","vi":"lối tuyên xưng cổ trang — thơ cổ / tục ngữ","ja":"古語の感嘆・断定「〜なりけり / 〜であるぞ」"}'::jsonb, '이것이 진정한 사랑이로다.', '{"en":"This, indeed, is true love.","es":"Esto es el verdadero amor.","fr":"Voilà l’amour véritable.","pt-BR":"Eis o verdadeiro amor.","th":"นี่แหละคือรักแท้","id":"Inilah cinta sejati.","vi":"Đây mới thật là tình yêu chân chính.","ja":"これぞ真の愛なり。"}'::jsonb, 'topik-6'),
('-(으)ㄹ진대', '{"en":"\"if indeed it is the case that ...\" — formal hypothetical conditional","es":"\"si en verdad / de ser así que ...\" — condicional formal hipotético","fr":"«s’il est vrai que / pour autant que ...» — conditionnel formel","pt-BR":"\"se de fato / sendo o caso que ...\" — condicional formal","th":"\"หากแม้นว่า ... (ทางการ)\"","id":"\"jika sungguh ... (formal)\"","vi":"\"nếu quả thật ... (trang trọng)\"","ja":"「〜であろうから / 〜であるからには(改まり)」"}'::jsonb, '사람이라면 양심이 있을진대 어떻게 그럴 수 있어요?', '{"en":"If indeed one is a person and has a conscience, how could one act like that?","es":"Si uno es persona y tiene conciencia, ¿cómo puede actuar así?","fr":"S’il est vrai que l’on a une conscience, comment peut-on agir ainsi ?","pt-BR":"Se de fato somos pessoas e temos consciência, como agir assim?","th":"หากเป็นมนุษย์ที่มีจิตสำนึก จะกระทำเช่นนั้นได้อย่างไร","id":"Jika benar sebagai manusia memiliki nurani, bagaimana bisa berbuat begitu?","vi":"Nếu quả là người và có lương tâm, sao có thể hành xử như vậy?","ja":"人として良心があるのなら、どうしてそんなことができましょう。"}'::jsonb, 'topik-6'),
('-(으)련마는 / -(으)련만', '{"en":"\"I would ... but ...\" — frustrated or impossible wish (literary, melancholic)","es":"\"quisiera ... pero ...\" — deseo frustrado o imposible (literario, melancólico)","fr":"«je voudrais bien ... mais ...» — souhait frustré (littéraire)","pt-BR":"\"queria ... mas ...\" — desejo frustrado (literário)","th":"\"อยากจะ ... แต่ ... (วรรณกรรม โศกเศร้า)\"","id":"\"ingin sekali ..., tetapi ... (sastrawi, melankoli)\"","vi":"\"muốn ... nhưng ... (văn chương, da diết)\"","ja":"「〜したいけれど / 〜したかろうに(文語)」"}'::jsonb, '당신과 함께 있으련마는 사정이 허락하지 않네요.', '{"en":"I’d gladly be with you, but circumstances don’t allow it.","es":"Quisiera estar contigo, pero las circunstancias no lo permiten.","fr":"Je voudrais bien être avec toi, mais les circonstances ne le permettent pas.","pt-BR":"Eu ficaria com você, mas as circunstâncias não permitem.","th":"อยากอยู่กับคุณ แต่สถานการณ์ไม่อำนวย","id":"Ingin bersamamu, tetapi keadaan tidak mengizinkan.","vi":"Tôi muốn ở bên em nhưng hoàn cảnh không cho phép.","ja":"あなたと共にいたいのですが、事情が許しません。"}'::jsonb, 'topik-6'),
('-(으)ㄹ쏘냐', '{"en":"\"how could one ever ...?\" — archaic rhetorical question (denies emphatically)","es":"\"¿cómo podría jamás ...?\" — pregunta retórica arcaica (negación enfática)","fr":"«comment pourrais-je / pourrait-il ...?» — interrogation rhétorique archaïque","pt-BR":"\"como poderia / acaso ...?\" — pergunta retórica arcaica","th":"\"จะ ... ได้อย่างไรเล่า (โบราณ, สำนวนวรรณกรรม)\"","id":"\"mana mungkin / bagaimana bisa ...? (kuno, sastrawi)\"","vi":"\"sao có thể ... được? (cổ, văn chương)\"","ja":"「〜であろうか / どうして〜できようか(古語)」"}'::jsonb, '이 아름다운 땅을 어찌 잊으리쏘냐.', '{"en":"How could I ever forget this beautiful land?","es":"¿Cómo podría olvidar esta tierra tan hermosa?","fr":"Comment pourrais-je oublier cette belle terre ?","pt-BR":"Como poderia eu esquecer esta terra tão bela?","th":"แผ่นดินอันงดงามนี้จะลืมเลือนได้อย่างไรเล่า","id":"Mana mungkin saya melupakan tanah indah ini.","vi":"Sao có thể quên được mảnh đất tươi đẹp này.","ja":"この美しい大地をどうして忘れられようか。"}'::jsonb, 'topik-6'),
('원인 표현 비교', '{"en":"compares 8 causal expressions by register and nuance: -아/어서, -(으)니까, -기 때문에, -는 바람에, -(으)ㄴ/는 탓에, -기에, -(으)로 인해, -(으)로 말미암아","es":"compara 8 expresiones causales por registro y matiz: -아/어서, -(으)니까, -기 때문에, -는 바람에, -(으)ㄴ/는 탓에, -기에, -(으)로 인해, -(으)로 말미암아","fr":"compare 8 expressions de cause par registre et nuance : -아/어서, -(으)니까, -기 때문에, -는 바람에, -(으)ㄴ/는 탓에, -기에, -(으)로 인해, -(으)로 말미암아","pt-BR":"compara 8 expressões de causa por registro e nuance: -아/어서, -(으)니까, -기 때문에, -는 바람에, -(으)ㄴ/는 탓에, -기에, -(으)로 인해, -(으)로 말미암아","th":"เปรียบเทียบ 8 สำนวนเหตุผลตามระดับและความหมาย: -아/어서, -(으)니까, -기 때문에, -는 바람에, -(으)ㄴ/는 탓에, -기에, -(으)로 인해, -(으)로 말미암아","id":"membandingkan 8 ungkapan sebab menurut register dan nuansa: -아/어서, -(으)니까, -기 때문에, -는 바람에, -(으)ㄴ/는 탓에, -기에, -(으)로 인해, -(으)로 말미암아","vi":"so sánh 8 cách diễn đạt nguyên nhân theo phong cách và sắc thái: -아/어서, -(으)니까, -기 때문에, -는 바람에, -(으)ㄴ/는 탓에, -기에, -(으)로 인해, -(으)로 말미암아","ja":"原因表現8種の比較 — -아/어서・-(으)니까・-기 때문에・-는 바람에・-(으)ㄴ/는 탓에・-기에・-(으)로 인해・-(으)로 말미암아"}'::jsonb, '비 때문에 못 갔어요. (cotidiano) / 폭우로 인해 도로가 통제됐어요. (formal/escrito)', '{"en":"I couldn’t go because of the rain. (casual) / Due to heavy rain, the road was closed. (formal/written)","es":"No pude ir a causa de la lluvia. (cotidiano) / Debido a las lluvias torrenciales, la carretera fue bloqueada. (formal)","fr":"Je n’ai pas pu y aller à cause de la pluie. (oral) / En raison de fortes pluies, la route a été fermée. (formel)","pt-BR":"Não pude ir por causa da chuva. (cotidiano) / Devido às chuvas fortes, a estrada foi interditada. (formal)","th":"ไปไม่ได้เพราะฝนตก (พูดทั่วไป) / อันเนื่องมาจากฝนตกหนัก ถนนถูกปิด (ทางการ)","id":"Tidak bisa pergi karena hujan. (sehari-hari) / Akibat hujan deras, jalan ditutup. (formal)","vi":"Không đi được vì trời mưa. (đời thường) / Do mưa lớn, đường bị phong tỏa. (trang trọng)","ja":"雨のせいで行けませんでした。(口語) / 豪雨により道路が通行止めになりました。(改まり)"}'::jsonb, 'topik-6'),
('양보 표현 비교', '{"en":"compares 10 concessive expressions by level and register: -아/어도, -(으)ㄴ/는데도, -더라도, -지라도, -(으)ㄹ지언정, -(으)ㄹ망정, -고도, -다손 치더라도, -ㄴ들, -(으)련마는","es":"compara 10 expresiones concesivas por nivel y registro: -아/어도, -(으)ㄴ/는데도, -더라도, -지라도, -(으)ㄹ지언정, -(으)ㄹ망정, -고도, -다손 치더라도, -ㄴ들, -(으)련마는","fr":"compare 10 expressions de concession par niveau et registre: -아/어도, -(으)ㄴ/는데도, -더라도, -지라도, -(으)ㄹ지언정, -(으)ㄹ망정, -고도, -다손 치더라도, -ㄴ들, -(으)련마는","pt-BR":"compara 10 expressões concessivas por nível e registro: -아/어도, -(으)ㄴ/는데도, -더라도, -지라도, -(으)ㄹ지언정, -(으)ㄹ망정, -고도, -다손 치더라도, -ㄴ들, -(으)련마는","th":"เปรียบเทียบ 10 สำนวนยอม-อ้างเหตุตามระดับและการใช้: -아/어도, -(으)ㄴ/는데도, -더라도, -지라도, -(으)ㄹ지언정, -(으)ㄹ망정, -고도, -다손 치더라도, -ㄴ들, -(으)련마는","id":"membandingkan 10 ungkapan konsesif menurut level dan register: -아/어도, -(으)ㄴ/는데도, -더라도, -지라도, -(으)ㄹ지언정, -(으)ㄹ망정, -고도, -다손 치더라도, -ㄴ들, -(으)련마는","vi":"so sánh 10 cách diễn đạt nhượng bộ theo cấp độ và phong cách: -아/어도, -(으)ㄴ/는데도, -더라도, -지라도, -(으)ㄹ지언정, -(으)ㄹ망정, -고도, -다손 치더라도, -ㄴ들, -(으)련마는","ja":"譲歩表現10種の比較 — -아/어도・-(으)ㄴ/는데도・-더라도・-지라도・-(으)ㄹ지언정・-(으)ㄹ망정・-고도・-다손 치더라도・-ㄴ들・-(으)련마는"}'::jsonb, '비가 와도 갈 거예요. (단순) / 가난해질망정 정직하게 살겠어요. (도덕적 결의)', '{"en":"Even if it rains, I’ll go. (simple) / Even if I become poor, I’ll live honestly. (moral resolve)","es":"Aunque llueva, iré. (simple) / Aunque me vuelva pobre, viviré con honestidad. (resolución moral)","fr":"Même s’il pleut, j’irai. (simple) / Quitte à devenir pauvre, je vivrai honnêtement. (résolution morale)","pt-BR":"Mesmo que chova, irei. (simples) / Mesmo que eu fique pobre, viverei com honestidade. (resolução moral)","th":"แม้ฝนตกก็จะไป (ปกติ) / ต่อให้จนก็จะใช้ชีวิตอย่างซื่อสัตย์ (มุ่งมั่นทางคุณธรรม)","id":"Meski hujan, saya tetap pergi. (sederhana) / Walau jatuh miskin, akan hidup jujur. (tekad moral)","vi":"Dù trời mưa tôi vẫn đi. (đơn giản) / Thà nghèo cũng sống ngay thẳng. (quyết tâm đạo đức)","ja":"雨が降っても行きます。(基本) / 貧しくなろうとも正直に生きます。(道徳的決意)"}'::jsonb, 'topik-6'),
('-아/어 마지않다', '{"en":"\"I cannot but ...\" — formal/literary emphatic expression","es":"\"no puedo más que ...\" — expresión formal/literaria enfática","fr":"«je ne puis que / je ne saurais ne pas ...»","pt-BR":"\"não posso senão ...\" — expressão formal/literária","th":"\"ไม่อาจไม่ ... ได้ / ขอ ... ยิ่ง\"","id":"\"tidak bisa tidak ... / dengan sungguh ...\"","vi":"\"không thể không ... / xin (kính) ...\"","ja":"「〜してやまない(改まり)」"}'::jsonb, '감사해 마지않습니다.', '{"en":"I cannot but be deeply grateful.","es":"No puedo más que estar profundamente agradecido.","fr":"Je ne saurais trop vous remercier.","pt-BR":"Não posso senão agradecer profundamente.","th":"ขอขอบพระคุณอย่างยิ่ง","id":"Saya tidak bisa tidak berterima kasih sedalam-dalamnya.","vi":"Tôi không thể không bày tỏ lòng biết ơn sâu sắc.","ja":"感謝してやみません。"}'::jsonb, 'topik-6'),
('-아/어 마땅하다', '{"en":"\"is fitting / deserves to ...\" — moral or normative judgment","es":"\"es justo / merecido ...\" — juicio moral o normativo","fr":"«mérite / il est juste de ...»","pt-BR":"\"é justo / merece ...\"","th":"\"สมควรที่จะ ... / สมแล้ว\"","id":"\"layak / pantas untuk ...\"","vi":"\"đáng phải ... / xứng đáng ...\"","ja":"「〜するに値する / 当然だ」"}'::jsonb, '칭찬받아 마땅한 행동이에요.', '{"en":"It’s behavior that deserves praise.","es":"Es una acción que merece elogios.","fr":"C’est un comportement qui mérite des éloges.","pt-BR":"É um comportamento que merece elogio.","th":"เป็นพฤติกรรมที่สมควรได้รับคำชม","id":"Itu perilaku yang patut dipuji.","vi":"Đó là hành động đáng được khen ngợi.","ja":"称賛されるに値する行いです。"}'::jsonb, 'topik-6'),
('-(으)리라(고)', '{"en":"\"I firmly believe / surely ...\" — literary firm conjecture, used with 생각하다/믿다/보다","es":"\"creo firmemente / sin duda ...\" — conjetura literaria firme, con 생각하다/믿다/보다","fr":"«je crois fermement que / sans aucun doute»","pt-BR":"\"acredito firmemente que / com certeza ...\"","th":"\"เชื่อมั่นว่า ... / แน่นอนว่า ... (วรรณกรรม)\"","id":"\"yakin / pasti ... (sastrawi)\"","vi":"\"chắc chắn rằng / tin rằng ... (văn chương)\"","ja":"「〜であろうと(信じる / 思う)」(文語)"}'::jsonb, '이번에는 성공하리라고 믿어요.', '{"en":"I firmly believe this time will succeed.","es":"Creo firmemente que esta vez tendrá éxito.","fr":"Je crois fermement que cette fois sera la bonne.","pt-BR":"Acredito firmemente que desta vez vai dar certo.","th":"ฉันเชื่อมั่นว่าครั้งนี้จะสำเร็จ","id":"Saya yakin kali ini akan berhasil.","vi":"Tôi tin chắc lần này sẽ thành công.","ja":"今回はきっと成功するだろうと信じています。"}'::jsonb, 'topik-6'),
('-(으)ㄹ세라', '{"en":"\"for fear that ...\" — literary version of -(으)ㄹ까 봐","es":"\"por miedo a que ... (literario)\" — versión literaria de -(으)ㄹ까 봐","fr":"«de peur que ... (littéraire)»","pt-BR":"\"com medo de que ... (literário)\"","th":"\"กลัวว่าจะ ... (วรรณกรรม)\" — เทียบ G144","id":"\"khawatir kalau-kalau ... (sastrawi)\"","vi":"\"sợ rằng ... (văn chương)\"","ja":"「〜しようかと(文語)」— G144 の文語形"}'::jsonb, '아기가 깰세라 조용히 걸었어요.', '{"en":"I walked quietly for fear of waking the baby.","es":"Caminé en silencio por miedo a despertar al bebé.","fr":"J’ai marché en silence de peur de réveiller le bébé.","pt-BR":"Andei em silêncio com medo de acordar o bebê.","th":"เดินเงียบ ๆ กลัวว่าจะปลุกเด็ก","id":"Saya berjalan pelan, khawatir bayi terbangun.","vi":"Tôi đi rón rén vì sợ làm em bé thức giấc.","ja":"赤ちゃんが起きるかと、静かに歩きました。"}'::jsonb, 'topik-6'),
('질문 종결 비교', '{"en":"compares question endings across registers — 드십니까 / 드세요 / 먹어요 / 먹니 / 먹어 / 먹나(요) / 먹는가 / 먹느냐","es":"compara terminaciones interrogativas por registro — 드십니까 / 드세요 / 먹어요 / 먹니 / 먹어 / 먹나(요) / 먹는가 / 먹느냐","fr":"compare les terminaisons interrogatives selon le registre","pt-BR":"compara terminações interrogativas por registro","th":"เปรียบเทียบรูปคำถามตามระดับ — 드십니까 / 드세요 / 먹어요 / 먹니 / 먹어 / 먹나(요) / 먹는가 / 먹느냐","id":"membandingkan akhiran pertanyaan menurut register","vi":"so sánh đuôi câu hỏi theo phong cách","ja":"疑問終結の比較: 합쇼체・해요체・반말・해라체・文語"}'::jsonb, '드십니까? (muy formal) / 드세요? (educado) / 먹어요? (cotidiano) / 먹어? (informal)', '{"en":"Are you eating? (very formal / polite / casual / informal)","es":"¿Está comiendo? (muy formal / educado / cotidiano / informal)","fr":"Mangez-vous ? (très formel / poli / courant / familier)","pt-BR":"Você está comendo? (muito formal / educado / cotidiano / informal)","th":"รับประทานอยู่ไหมครับ/ดื่มอะไรอยู่คะ (ทางการมาก / สุภาพ / ทั่วไป / กันเอง)","id":"Apakah Anda makan? (sangat formal / sopan / sehari-hari / santai)","vi":"Anh/chị đang ăn ạ? (rất trang trọng / lịch sự / đời thường / thân mật)","ja":"召し上がりますか？ / お食べになりますか？ / 食べますか？ / 食べる？ — 文体比較"}'::jsonb, 'topik-6'),
('-건만', '{"en":"\"but / and yet ...\" — literary adversative with lament or frustration","es":"\"pero / y sin embargo ... (literario)\" — con tono de lamento","fr":"«mais / et pourtant ... (littéraire, regret)»","pt-BR":"\"mas / contudo ... (literário com lamento)\"","th":"\"แต่ ... (วรรณกรรม, สื่ออารมณ์โศก)\"","id":"\"namun / tetapi ... (sastrawi, getir)\"","vi":"\"thế mà / nhưng ... (văn chương, da diết)\"","ja":"「〜けれど(文語・嘆き)」"}'::jsonb, '봄이 왔건만 마음은 여전히 춥다.', '{"en":"Spring has come, but the heart is still cold.","es":"Llegó la primavera, pero el corazón sigue frío.","fr":"Le printemps est venu, et pourtant le cœur reste froid.","pt-BR":"A primavera chegou, mas o coração continua frio.","th":"ฤดูใบไม้ผลิมาแล้ว แต่ใจยังคงหนาว","id":"Musim semi telah tiba, namun hati tetap dingin.","vi":"Xuân về rồi mà lòng vẫn lạnh.","ja":"春が来たけれど、心はまだ寒い。"}'::jsonb, 'topik-6'),
('-아/어 주십사 (하고)', '{"en":"\"I humbly beg you to ...\" — extremely formal request, often in letters / speeches","es":"\"le ruego encarecidamente que ...\" — petición muy formal","fr":"«je vous prie d’avoir la bonté de ...» — formel extrême","pt-BR":"\"peço encarecidamente que ...\" — pedido muito formal","th":"\"ขอความกรุณา ... (ทางการขั้นสูง)\"","id":"\"dengan hormat saya memohon ... (sangat formal)\"","vi":"\"kính mong ngài / quý vị ... (rất trang trọng)\"","ja":"「お〜くださいますよう(極めて改まり)」"}'::jsonb, '도와 주십사 하고 부탁드립니다.', '{"en":"I humbly request your help.","es":"Le ruego encarecidamente que me ayude.","fr":"Je vous prie d’avoir la bonté de m’aider.","pt-BR":"Peço encarecidamente sua ajuda.","th":"ขอความกรุณาท่านโปรดช่วยเหลือด้วยครับ","id":"Dengan hormat saya memohon bantuan Anda.","vi":"Kính mong ngài giúp đỡ ạ.","ja":"お助けくださいますようお願い申し上げます。"}'::jsonb, 'topik-6'),
('-아/어 마다하지 않다', '{"en":"\"would not refuse / is willing to do even ...\" — total willingness","es":"\"no rehúsa ni / está dispuesto a hacer incluso ...\" — disposición total","fr":"«ne refuser même pas / accepter de faire jusqu’à ...»","pt-BR":"\"não recusa nem / está disposto a fazer até ...\"","th":"\"ไม่ปฏิเสธแม้แต่จะ ... / เต็มใจทำทุกอย่าง\"","id":"\"tidak menolak meskipun harus ... / rela melakukan apapun\"","vi":"\"không từ chối cả ... / sẵn sàng ...\"","ja":"「〜することを厭わない / 嫌がらない」"}'::jsonb, '가족을 위해 희생을 마다하지 않으셨어요.', '{"en":"They didn’t refuse any sacrifice for their family.","es":"No rehusó ningún sacrificio por su familia.","fr":"Il/elle n’a refusé aucun sacrifice pour sa famille.","pt-BR":"Ele/ela não recusou nenhum sacrifício pela família.","th":"ท่านไม่ปฏิเสธความเสียสละใด ๆ เพื่อครอบครัว","id":"Beliau tidak menolak pengorbanan apa pun demi keluarga.","vi":"Người ấy không từ chối hy sinh nào vì gia đình.","ja":"家族のために犠牲を厭わずに尽くしました。"}'::jsonb, 'topik-6'),
('-노라면', '{"en":"\"if one keeps doing / as one lives ...\" — literary version of -다 보면","es":"\"si uno sigue haciendo / al vivir ... (literario)\" — versión literaria de -다 보면","fr":"«à force de ... / en vivant ainsi ... (littéraire)»","pt-BR":"\"se uno continua / vivendo assim ... (literário)\"","th":"\"หากใช้ชีวิต / ทำต่อไปเรื่อย ๆ ... (วรรณกรรม)\"","id":"\"jika terus / seraya menjalani ... (sastrawi)\"","vi":"\"nếu cứ ... mãi (văn chương)\"","ja":"「〜していけば / 生きていれば(文語)」"}'::jsonb, '살노라면 좋은 날도 오겠지요.', '{"en":"If one keeps on living, good days will surely come.","es":"Si uno vive, llegarán días buenos.","fr":"En vivant, de meilleurs jours viendront sans doute.","pt-BR":"Continuando a viver, dias melhores hão de vir.","th":"หากใช้ชีวิตต่อไป วันที่ดีก็คงมาถึง","id":"Jika kita terus hidup, hari baik pasti akan datang.","vi":"Cứ sống tiếp thì ngày tốt đẹp ắt sẽ đến.","ja":"生きていれば、良い日も来るでしょう。"}'::jsonb, 'topik-6'),
('-아/어 죽을 지경이다', '{"en":"\"on the verge of dying from ...\" — combination of G210 and G188; extreme intensity","es":"\"al borde de morir de ...\" — combinación de G210 y G188","fr":"«être au point de mourir de ...» — combinaison de G210 et G188","pt-BR":"\"a ponto de morrer de ...\" — combinação de G210 e G188","th":"\"แทบจะตายเพราะ ...\" — รวม G210 + G188","id":"\"hampir mati karena ...\" — gabungan G210 + G188","vi":"\"sắp chết vì ...\" — kết hợp G210 + G188","ja":"「〜て死にそうな状態だ」(G210 + G188 の合成)"}'::jsonb, '더워 죽을 지경이에요.', '{"en":"I’m about to die from this heat.","es":"No aguanto más del calor que hace.","fr":"Je suis à deux doigts de mourir de chaleur.","pt-BR":"Estou a ponto de morrer com este calor.","th":"แทบจะตายเพราะร้อนแล้ว","id":"Hampir mati saya saking panasnya.","vi":"Tôi sắp chết vì nóng mất.","ja":"暑くて死にそうな状態です。"}'::jsonb, 'topik-6')
