-- 20260608000001_resync_catalog_topik.sql
-- Re-sync the catalog (`public.grammars`) with the new client seed.
--
-- Replaces the 14 legacy 'general'-deck entries with the full 300-entry
-- TOPIK 1–6 catalog (matching `app/seed/grammars-n{1..6}.ts`).
--
-- Schema defaults also move:
--   grammars.deck_id              'general' → 'topik-1'
--   user_custom_grammars.deck_id  'general' → 'topik-1'
--   user_decks.color_id           'indigo'  → 'sky'
--
-- Idempotent via UPSERT (`ON CONFLICT (ko) DO UPDATE`) so re-running the
-- migration aligns rows with the latest seed without inflating row counts.

BEGIN;

-- ─── Schema defaults ─────────────────────────────────────────────
ALTER TABLE public.grammars              ALTER COLUMN deck_id  SET DEFAULT 'topik-1';
ALTER TABLE public.user_custom_grammars  ALTER COLUMN deck_id  SET DEFAULT 'topik-1';
ALTER TABLE public.user_decks            ALTER COLUMN color_id SET DEFAULT 'sky';

-- ─── Re-map any legacy 'general' rows on user-owned tables to 'topik-1'
-- (safe fallback — users keep their custom grammars under the entry deck).
UPDATE public.user_custom_grammars SET deck_id = 'topik-1' WHERE deck_id = 'general';

-- ─── Catalog: remove pre-topik legacy entries that no longer exist in seed
-- (their 'ko' notation has changed in the new client seed).
DELETE FROM public.grammars WHERE ko IN (
  '에서/부터~까지',
  '한테/한테서',
  '-(으)러',
  '못',
  '-지 않다',
  '-아/어야 되다',
  '는/은'
);

-- ─── Catalog: 300 grammars across topik-1 … topik-6
ON CONFLICT (ko) DO UPDATE SET
  meaning = EXCLUDED.meaning,
  example = EXCLUDED.example,
  trans   = EXCLUDED.trans,
  deck_id = EXCLUDED.deck_id;

COMMIT;
